#include <iostream>
using namespace std;

constexpr int factorial(int n) {
 return (n <= 1) ? 1 : n * factorial(n - 1);
}

int main() {
 constexpr int fact5 = factorial(5);
 int n = 5;
 int runtime_fact5 = factorial(n);

 cout << \Факториал 5 (compile-time): " << fact5 << endl;
 cout << "Факториал 5 (runtime): " << runtime_fact5 << endl;
 return 0;
}"

