#include <iostream>
#include <typeinfo>
using namespace std;

int main() {
 int i = 10;
 double d = 3.14;
 char c = 'A';

 cout << \Тип i: " << typeid(i).name() << endl;
 cout << "Тип d: " << typeid(d).name() << endl;
 cout << "Тип c: " << typeid(c).name() << endl;

 if (typeid(i) == typeid(int)) {
 cout << "i действительно имеет тип int" << endl;
 }

 if (typeid(d) != typeid(int)) {
 cout << "d не имеет тип int" << endl;
 }

 return 0;
}"

