#include <iostream>
using namespace std;

class Cache {
private:
 mutable int access_count;
 int data;
public:
 Cache(int d) : data(d), access_count(0) {}

 int getData() const {
 access_count++;
 return data;
 }

 int getAccessCount() const { return access_count; }
};

int main() {
 const Cache cache(42);

 cout << \Данные: " << cache.getData() << endl;
 cout << "Данные: " << cache.getData() << endl;
 cout << "Число обращений: " << cache.getAccessCount() << endl;

 return 0;
}"

