#include <iostream>
#include <vector>
using namespace std;

int main() {
 vector<int> numbers = {1, 2, 3, 4, 5};

 auto it = numbers.begin();
 decltype(numbers.begin()) it2 = numbers.begin();

 int x = 10;
 double y = 3.14;
 decltype(x * y + 5.0) result;
 result = x * y + 5.0;

 cout << \Тип it: " << typeid(it).name() << endl;
 cout << "Тип it2: " << typeid(it2).name() << endl;
 cout << "Тип result: " << typeid(result).name() << endl;
 cout << "Значение result: " << result << endl;

 int a = 100;
 decltype((a)) ref = a;
 ref = 200;
 cout << "a после изменения через decltype((a)): " << a << endl;

 return 0;
}"

