#include <iostream>
using namespace std;

int main() {
 double pi = 3.14159;

 int int_pi = (int)pi;
 cout << \C-style cast double->int: " << int_pi << " (потеря дробной части)" << endl;

 const int original = 100;
 int* dangerous_ptr = (int*)&original; *dangerous_ptr = 200;

 cout << "Оригинальная константа: " << original << endl;
 cout << "Измененное значение через указатель: " << *dangerous_ptr << endl;
 cout << "ВНИМАНИЕ: Неопределенное поведение!" << endl;

 float float_pi = static_cast<float>(pi);
 cout << "\nБезопасный static_cast double->float: " << float_pi << endl;

 const int value = 300;
 int& mutable_ref = const_cast<int&>(value);

 return 0;
}"

