 cout << "is_integral<float>: " << is_integral<float>::value << endl;
 cout << "is_integral<bool>: " << is_integral<bool>::value << endl;
 cout << "is_integral<char>: " << is_integral<char>::value << endl;

 cout << "\nis_floating_point<float>: " << is_floating_point<float>::value << endl;
 cout << "is_floating_point<double>: " << is_floating_point<double>::value << endl;
 cout << "is_floating_point<int>: " << is_floating_point<int>::value << endl;

 cout << "\nis_arithmetic<int>: " << is_arithmetic<int>::value << endl;
 cout << "is_arithmetic<float>: " << is_arithmetic<float>::value << endl;
 cout << "is_arithmetic<void*>: " << is_arithmetic<void*>::value << endl;

 if constexpr (is_integral<int>::value) {
 cout << "\nТип int является целочисленным (проверено в compile-time)" << endl;
 }

 return 0;
}"

