#include <iostream>
#include <type_traits>
using namespace std;

struct Trivial {
 int x;
 double y;
};

struct NonTrivial {
 NonTrivial() {}
 int x;
};

struct StandardLayout {
 int x;
private:
 int y;
};

struct NonStandardLayout {
 int x;
private:
 int y;
public:
 int z;
};

int main() {
 cout << boolalpha;

 cout << \is_trivial<Trivial>: " << is_trivial<Trivial>::value << endl;
 cout << "is_trivial<NonTrivial>: " << is_trivial<NonTrivial>::value << endl;
 cout << "is_trivial<int>: " << is_trivial<int>::value << endl;

 cout << "\nis_standard_layout<StandardLayout>: " << is_standard_layout<StandardLayout>::value << endl;
 cout << "is_standard_layout<NonStandardLayout>: " << is_standard_layout<NonStandardLayout>::value << endl;
 cout << "is_standard_layout<int[]>: " << is_standard_layout<int[]>::value << endl;

 cout << "\nis_pod<Trivial>: " << is_pod<Trivial>::value << endl;
 cout << "is_pod<NonTrivial>: " << is_pod<NonTrivial>::value << endl;

 if constexpr (is_trivial_v<Trivial>) {
 cout << "\nTrivial можно безопасно копировать memcpy" << endl;
 }

 return 0;
}"

