 std::cin >> old_value >> new_value;

 if (old_value == 0) {
 std::cout << "Ошибка: старое значение не может быть нулевым!" << std::endl;
 return 1;
 }

 double change_percent = ((new_value - old_value) / old_value) * 100.0;
 std::cout << "Изменение: " << change_percent << "%" << std::endl;
 return 0;
}"

