#include <iostream>
#include <cmath>
using namespace std;

int main() {
 double x;
 cout << Введите угол в радианах: ";
 cin >> x;

 double sin_val = sin(x);
 double cos_val = cos(x);

 if (sin_val == cos_val) {
 cout << "Ошибка: деление на ноль (sin(x) - cos(x) = 0)!" << endl;
 return 1;
 }

 double result = (sin_val + cos_val) / (sin_val - cos_val);
 cout << "Результат (sin(x)+cos(x))/(sin(x)-cos(x)): " << result << endl;
 return 0;
}"

