#include <iostream>
#include <cmath>
using namespace std;

int main() {
 double side, height;
 cout << Введите длину стороны основания и высоту призмы: ";
 cin >> side >> height;

 if (side <= 0 || height <= 0) {
 cout << "Ошибка: значения должны быть положительными!" << endl;
 return 1;
 }

 double base_area = (3.0 * sqrt(3.0) * side * side) / 2.0;
 double volume = base_area * height;
 cout << "Объем правильной шестиугольной призмы: " << volume << endl;
 return 0;
}"

