#include <iostream>
#include <cmath>
using namespace std;

int main() {
 double a, b, c;
 cout << Введите три положительных числа: ";
 cin >> a >> b >> c;

 if (a <= 0 || b <= 0 || c <= 0) {
 cout << "Ошибка: числа должны быть положительными!" << endl;
 return 1;
 }

 double mean = (a + b + c) / 3.0;
 double variance = (aa + bb + c*c)/3.0 - mean*mean;
 double std_dev = sqrt(variance);
 double cv = (std_dev / mean) * 100.0;

 cout << "Коэффициент вариации: " << cv << "%" << endl;
 return 0;
}"

