}"

#include <iostream>
using namespace std;

int main() {
 int n, first_term, difference;
 cout << Введите количество членов (N): ";
 cin >> n;
 cout << "Введите первый член прогрессии: ";
 cin >> first_term;
 cout << "Введите разность прогрессии: ";
 cin >> difference;

 cout << "Первые " << n << " членов арифметической прогрессии:" << endl;
 for (int i = 0; i < n; i++) {
 int term = first_term + i * difference;
 cout << term << " ";
 }
 cout << endl;
 return 0;
}"

