#include <iostream>
using namespace std;

int main() {
 long long number, reversed = 0;
 cout << \Введите целое число: ";
 cin >> number;

 long long original = number;
 if (number < 0) number = -number;

 while (number > 0) {
 int digit = number % 10;
 reversed = reversed * 10 + digit;
 number /= 10;
 }

 bool is_palindrome = (reversed == original || reversed == -original);

 if (is_palindrome) {
 cout << original << " является палиндромом" << endl;
 } else {
 cout << original << " не является палиндромом" << endl;
 }
 return 0;
}"

