#include <iostream>
using namespace std;

int main() {
 int number;
 cout << \Введите целое положительное число: ";
 cin >> number;

 if (number <= 0) {
 cout << "Ошибка: число должно быть положительным" << endl;
 return 1;
 }

 int sum = 0;
 for (int i = 1; i <= number / 2; i++) {
 if (number % i == 0) {
 sum += i;
 }
 }

 bool is_perfect = (sum == number);

 if (is_perfect) {
 cout << number << " является совершенным числом" << endl;
 } else {
 cout << number << " не является совершенным числом" << endl;
 }
 return 0;
}"

