#include <iostream>
using namespace std;

int main() {
 int n, first_term, difference;
 cout << \Введите количество членов (N): ";
 cin >> n;
 cout << "Введите первый член прогрессии: ";
 cin >> first_term;
 cout << "Введите разность прогрессии: ";
 cin >> difference;

 if (n <= 0) {
 cout << "Ошибка: N должно быть положительным" << endl;
 return 1;
 }

 int last_term = first_term + (n - 1) * difference;
 long long sum = (long long)n * (first_term + last_term) / 2;

 cout << "Сумма первых " << n << " членов арифметической прогрессии: " << sum << endl;
 return 0;
}"

