#include <iostream>
using namespace std;

int main() {
 double real1, imag1, real2, imag2;
 cout << Введите действительную и мнимую часть первого числа: ";
 cin >> real1 >> imag1;
 cout << "Введите действительную и мнимую часть второго числа: ";
 cin >> real2 >> imag2;

 double denominator = real2*real2 + imag2*imag2;
 if (denominator == 0) {
 cout << "Ошибка: деление на ноль!" << endl;
 return 1;
 }

 double real = (real1*real2 + imag1*imag2) / denominator;
 double imag = (imag1*real2 - real1*imag2) / denominator;

 cout << "Результат деления: " << real << " + " << imag << "i" << endl;
 return 0;
}"

