 cin >> distance1 >> speed1;
 cout << "Введите расстояние и скорость на втором участке: ";
 cin >> distance2 >> speed2;

 if (speed1 <= 0 || speed2 <= 0) {
 cout << "Ошибка: скорости должны быть положительными!" << endl;
 return 1;
 }

 double total_distance = distance1 + distance2;
 double total_time = distance1/speed1 + distance2/speed2;
 double average_speed = total_distance / total_time;

 cout << "Средняя скорость: " << average_speed << endl;
 return 0;
}"

