#include <iostream>
#include <cmath>
using namespace std;

int main() {
 double number;
 const double epsilon = 1e-10;
 const int max_iterations = 1000;

 cout << Введите положительное число: ";
 cin >> number;

 if (number < 0) {
 cout << "Ошибка: невозможно вычислить квадратный корень из отрицательного числа" << endl;
 return 1;
 }

 if (number == 0) {
 cout << "Квадратный корень из 0 равен 0" << endl;
 return 0;
 }

 double guess = number / 2.0;
 int iterations = 0;

 while (fabs(guess * guess - number) > epsilon && iterations < max_iterations) {
 guess = (guess + number / guess) / 2.0;
 iterations++;
 }

 cout << "Приближённое значение квадратного корня из " << number << " = " << guess << endl;
 cout << "Количество итераций: " << iterations << endl;

 return 0;
}"

#include <iostream>
#include <cmath>

int main() {
 double number;
 const double epsilon = 1e-10;
 const int max_iterations = 1000;

 std::cout << Введите положительное число: ";
 std::cin >> number;

 if (number < 0) {
 std::cout << "Ошибка: невозможно вычислить квадратный корень из отрицательного числа" << std::endl;
 return 1;
 }

 if (number == 0) {
 std::cout << "Квадратный корень из 0 равен 0" << std::endl;
 return 0;
 }

 double guess = number / 2.0;
 int iterations = 0;

 while (std::fabs(guess * guess - number) > epsilon && iterations < max_iterations) {
 guess = (guess + number / guess) / 2.0;
 iterations++;
 }

 std::cout << "Приближённое значение квадратного корня из " << number << " = " << guess << std::endl;
 std::cout << "Количество итераций: " << iterations << std::endl;

 return 0;
}"

