#include <iostream>
using namespace std;

int main() {
 double a, b;
 char op;

 cout << Введите выражение (например 2 + 3): ";
 cin >> a >> op >> b;

 switch (op) {
 case '+':
 cout << "Результат: " << a + b << endl;
 break;
 case '-':
 cout << "Результат: " << a - b << endl;
 break;
 case '*':
 cout << "Результат: " << a * b << endl;
 break;
 case '/':
 if (b != 0) {
 cout << "Результат: " << a / b << endl;
 } else {
 cout << "Ошибка: деление на ноль!" << endl;
 }
 break;
 default:
 cout << "Неизвестная операция!" << endl;
 }
 return 0;
}"

