#include <iostream>
#include <vector>
using namespace std;

void insertionSort(vector<int>& arr) {
    int n = arr.size();
    for (int i = 1; i < n; i++) {
        int key = arr[i];
        int j = i - 1;

        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
}

int main() {
    vector<int> numbers = {5, 2, 8, 1, 9, 3};

    cout << \До сортировки: ";
    for (int num : numbers) cout << num << " ";
    cout << endl;

    insertionSort(numbers);

    cout << "После сортировки: ";
    for (int num : numbers) cout << num << " ";
    cout << endl;

    return 0;
}"

