#include <iostream>
#include <vector>
#include <climits>
using namespace std;

int kadane(const vector<int>& arr) {
    int maxSoFar = INT_MIN;
    int maxEndingHere = 0;

    for (int num : arr) {
        maxEndingHere = max(num, maxEndingHere + num);
        maxSoFar = max(maxSoFar, maxEndingHere);
    }

    return maxSoFar;
}

pair<int, pair<int, int>> kadaneWithIndices(const vector<int>& arr) {
    int maxSoFar = INT_MIN;
    int maxEndingHere = 0;
    int start = 0, end = 0, tempStart = 0;

    for (int i = 0; i < arr.size(); i++) {
        if (maxEndingHere < 0) {
            maxEndingHere = arr[i];
            tempStart = i;
        } else {
            maxEndingHere += arr[i];
        }

        if (maxEndingHere > maxSoFar) {
            maxSoFar = maxEndingHere;
            start = tempStart;
            end = i;
        }
    }

    return {maxSoFar, {start, end}};
}

int main() {
    vector<int> arr = {-2, 1, -3, 4, -1, 2, 1, -5, 4};

    int maxSum = kadane(arr);
    cout << \Максимальная сумма подмассива: " << maxSum << endl;

    auto result = kadaneWithIndices(arr);
    cout << "Максимальная сумма: " << result.first << endl;
    cout << "Подмассив: с индекса " << result.second.first 
         << " по индекс " << result.second.second << endl;

    cout << "Элементы подмассива: ";
    for (int i = result.second.first; i <= result.second.second; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    return 0;
}"

#include <iostream>
#include <vector>
#include <climits>

int kadane(const std::vector<int>& arr) {
    int maxSoFar = INT_MIN;
    int maxEndingHere = 0;

    for (int num : arr) {
        maxEndingHere = std::max(num, maxEndingHere + num);
        maxSoFar = std::max(maxSoFar, maxEndingHere);
    }

    return maxSoFar;
}

std::pair<int, std::pair<int, int>> kadaneWithIndices(const std::vector<int>& arr) {
    int maxSoFar = INT_MIN;
    int maxEndingHere = 0;
    int start = 0, end = 0, tempStart = 0;

    for (int i = 0; i < arr.size(); i++) {
        if (maxEndingHere < 0) {
            maxEndingHere = arr[i];
            tempStart = i;
        } else {
            maxEndingHere += arr[i];
        }

        if (maxEndingHere > maxSoFar) {
            maxSoFar = maxEndingHere;
            start = tempStart;
            end = i;
        }
    }

    return {maxSoFar, {start, end}};
}

int main() {
    std::vector<int> arr = {-2, 1, -3, 4, -1, 2, 1, -5, 4};

    int maxSum = kadane(arr);
    std::cout << \Максимальная сумма подмассива: " << maxSum << std::endl;

    auto result = kadaneWithIndices(arr);
    std::cout << "Максимальная сумма: " << result.first << std::endl;
