bool isPrime(int n) {
    if (n <= 1) return false;
    for (int i = 2; i <= sqrt(n); i++) {
        if (n % i == 0) return false;
    }
    return true;
}

int main() {
    int num;
    cout << \Введите число: ";
    cin >> num;
    cout << num << (isPrime(num) ? " - простое" : " - не простое") << endl;
    return 0;
}"

#include <iostream>
