#include <iostream>
using namespace std;

int main() {
    double arr[] = {1.0, 2.0, 4.0};
    int size = sizeof(arr) / sizeof(arr[0]);
    double sumReciprocals = 0.0;

    for (int i = 0; i < size; i++) {
        if (arr[i] != 0) {
            sumReciprocals += 1.0 / arr[i];
        }
    }

    double harmonicMean = size / sumReciprocals;
    cout << \Среднее гармоническое: " << harmonicMean << endl;

    return 0;
}"

