#include <iostream>
using namespace std;

int main() {
    const int n = 5;
    int factorials[n];
    int fact = 1;

    for (int i = 0; i < n; i++) {
        factorials[i] = fact;
        fact *= (i + 2); // i+2 потому что факториал (i+1)! = (i+1) * i!
    }

    cout << \Факториалы первых " << n << " чисел: ";
    for (int i = 0; i < n; i++) {
        cout << factorials[i] << " ";
    }
    cout << endl;

    return 0;
}"

