#include <iostream>
#include <cmath>
using namespace std;

int main() {
    double arr[] = {1.0, 4.0, 9.0, 16.0};
    int size = sizeof(arr) / sizeof(arr[0]);
    double product = 1.0;
    int count = 0;

    for (int i = 0; i < size; i++) {
        if (arr[i] > 0) {
            product *= arr[i];
            count++;
        }
    }

    double geometricMean = pow(product, 1.0 / count);
    cout << \Среднее геометрическое: " << geometricMean << endl;

    return 0;
}"

