#include <iostream>
#include <algorithm>
using namespace std;

int main() {
    int arr1[] = {1, 3, 8};
    int arr2[] = {7, 9, 10, 11};
    int n1 = sizeof(arr1) / sizeof(arr1[0]);
    int n2 = sizeof(arr2) / sizeof(arr2[0]);

    int merged[n1 + n2];
    merge(arr1, arr1 + n1, arr2, arr2 + n2, merged);

    int total = n1 + n2;
    double median;

    if (total % 2 == 0) {
        median = (merged[total/2 - 1] + merged[total/2]) / 2.0;
    } else {
        median = merged[total/2];
    }

    cout << \Медиана двух массивов: " << median << endl;

    return 0;
}"

