#include <iostream>
using namespace std;

int main() {
    int arr[] = {3, 7, 2, 5, 3};
    int size = sizeof(arr) / sizeof(arr[0]);
    bool allUnique = true;

    for (int i = 0; i < size; i++) {
        for (int j = i + 1; j < size; j++) {
            if (arr[i] == arr[j]) {
                allUnique = false;
                break;
            }
        }
        if (!allUnique) break;
    }

    if (allUnique) {
        cout << \Все элементы уникальны" << endl;
    } else {
        cout << "Есть повторяющиеся элементы" << endl;
    }

    return 0;
}"

