#include <iostream>
#include <climits>
using namespace std;

int main() {
    int arr[] = {7, 10, 4, 3, 20, 15};
    int n = sizeof(arr) / sizeof(arr[0]);
    int k = 3;

    for (int i = 0; i < k; i++) {
        int minVal = INT_MAX;
        int minIdx = -1;

        for (int j = 0; j < n; j++) {
            if (arr[j] < minVal) {
                minVal = arr[j];
                minIdx = j;
            }
        }

        if (i == k - 1) {
            cout << k << \-й наименьший элемент: " << minVal << endl;
        }
        arr[minIdx] = INT_MAX;
    }

    return 0;
}"

