#include <iostream>
using namespace std;

int main() {
    int arr[] = {1, 0, 2, 0, 3, 0, 4};
    int size = sizeof(arr) / sizeof(arr[0]);
    int nonZeroIndex = 0;

    for (int i = 0; i < size; i++) {
        if (arr[i] != 0) {
            arr[nonZeroIndex] = arr[i];
            nonZeroIndex++;
        }
    }

    while (nonZeroIndex < size) {
        arr[nonZeroIndex] = 0;
        nonZeroIndex++;
    }

    cout << \Массив после перемещения нулей: ";
    for (int i = 0; i < size; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
    return 0;
}"

