#include <iostream>
using namespace std;

int main() {
    int matrix[3][3];

    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            if (i == j) {
                matrix[i][j] = i + 1; // диагональ
            } else if (i < j) {
                matrix[i][j] = (i + 1) * 10 + (j + 1); // верхний треугольник
                matrix[j][i] = matrix[i][j]; // нижний треугольник
            }
        }
    }

    cout << \Симметричная матрица:" << endl;
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            cout << matrix[i][j] << " ";
        }
        cout << endl;
    }

    return 0;
}"

