#include <iostream>
using namespace std;

int main() {
    int arr[] = {2, 3, 2, 4, 3, 2, 5};
    int size = sizeof(arr) / sizeof(arr[0]);
    int maxCount = 0, mostFrequent = arr[0];

    for (int i = 0; i < size; i++) {
        int count = 0;
        for (int j = 0; j < size; j++) {
            if (arr[j] == arr[i]) {
                count++;
            }
        }
        if (count > maxCount) {
            maxCount = count;
            mostFrequent = arr[i];
        }
    }

    cout << \Наиболее частый элемент: " << mostFrequent 
         << " (встречается " << maxCount << " раз)" << endl;

    return 0;
}"

