#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    const int N = 4;
    int mat[N][N] = {0};
    int value = 1;
    int top = 0, bottom = N-1, left = 0, right = N-1;

    while (value <= N*N) {
        for (int i = left; i <= right; i++) mat[top][i] = value++;
        top++;
        for (int i = top; i <= bottom; i++) mat[i][right] = value++;
        right--;
        for (int i = right; i >= left; i--) mat[bottom][i] = value++;
        bottom--;
        for (int i = bottom; i >= top; i--) mat[i][left] = value++;
        left++;
    }

    cout << \Матрица

style:
 заполненная по спирали:" << endl;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            cout << setw(3) << mat[i][j];
        }
        cout << endl;
    }
    return 0;
}"

