using namespace std;

int main() {
    int arr[] = {-2, 1, -3, 4, -1, 2, 1, -5, 4};
    int n = sizeof(arr) / sizeof(arr[0]);

    int maxSoFar = INT_MIN, maxEndingHere = 0;
    int start = 0, end = 0, tempStart = 0;

    for (int i = 0; i < n; i++) {
        maxEndingHere += arr[i];

        if (maxSoFar < maxEndingHere) {
            maxSoFar = maxEndingHere;
            start = tempStart;
            end = i;
        }

        if (maxEndingHere < 0) {
            maxEndingHere = 0;
            tempStart = i + 1;
        }
    }

    cout << \Максимальная сумма подмассива: " << maxSoFar << endl;
    cout << "Подмассив: ";
    for (int i = start; i <= end; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    return 0;
}"

