#include <iostream>
using namespace std;

int main() {
    int mat[3][3] = {{1,2,3}, {4,5,6}, {7,8,9}};
    bool found = false;

    for (int i = 0; i < 3; i++) {
        int minRow = mat[i][0];
        int colIndex = 0;
        for (int j = 1; j < 3; j++) {
            if (mat[i][j] < minRow) {
                minRow = mat[i][j];
                colIndex = j;
            }
        }
        bool isSaddle = true;
        for (int k = 0; k < 3; k++) {
            if (mat[k][colIndex] > minRow) {
                isSaddle = false;
                break;
            }
        }
        if (isSaddle) {
            cout << \Седловая точка: " << minRow << " в позиции (" << i << "

style:
" << colIndex << ")" << endl;
            found = true;
        }
    }

    if (!found) {
        cout << "Седловая точка не найдена" << endl;
    }
    return 0;
}"

