#include <iostream>
#include <climits>
using namespace std;

int main() {
    const int V = 4;
    int graph[V][V] = {{0, 4, 0, 0},
                       {4, 0, 8, 0},
                       {0, 8, 0, 7},
                       {0, 0, 7, 0}};

    int dist[V];
    bool visited[V];

    for (int i = 0; i < V; i++) {
        dist[i] = INT_MAX;
        visited[i] = false;
    }
    dist[0] = 0;

    for (int count = 0; count < V - 1; count++) {
        int min = INT_MAX, u;

        for (int v = 0; v < V; v++) {
            if (!visited[v] && dist[v] <= min) {
                min = dist[v];
                u = v;
            }
        }

        visited[u] = true;

        for (int v = 0; v < V; v++) {
            if (!visited[v] && graph[u][v] && dist[u] != INT_MAX &&
                dist[u] + graph[u][v] < dist[v]) {
                dist[v] = dist[u] + graph[u][v];
            }
        }
    }

    cout << \Кратчайшие расстояния от вершины 0:" << endl;
    for (int i = 0; i < V; i++) {
        cout << "До вершины " << i << ": " << dist[i] << endl;
    }

    return 0;
}"

