#include <iostream>
#include <string>
using namespace std;

const int d = 256; // размер алфавита
const int q = 101; // простое число

int main() {
    string text = \GEEKS FOR GEEKS";
    string pattern = "GEEK";

    int n = text.length();
    int m = pattern.length();

    int h = 1;
    for (int i = 0; i < m - 1; i++) {
        h = (h * d) % q;
    }

    int p = 0; // хэш для pattern
    int t = 0; // хэш для text

    for (int i = 0; i < m; i++) {
        p = (d * p + pattern[i]) % q;
        t = (d * t + text[i]) % q;
    }

    bool found = false;
    for (int i = 0; i <= n - m; i++) {
        if (p == t) {
            bool match = true;
            for (int j = 0; j < m; j++) {
                if (text[i + j] != pattern[j]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                cout << "Образец найден на позиции " << i << endl;
                found = true;
            }
        }

        if (i < n - m) {
            t = (d * (t - text[i] * h) + text[i + m]) % q;
            if (t < 0) {
                t += q;
            }
        }
    }

    if (!found) {
        cout << "Образец не найден" << endl;
    }

    return 0;
}"

#include <iostream>
#include <string>

const int d = 256; // размер алфавита
const int q = 101; // простое число

int main() {
    std::string text = \GEEKS FOR GEEKS";
    std::string pattern = "GEEK";

    int n = text.length();
    int m = pattern.length();

    int h = 1;
    for (int i = 0; i < m - 1; i++) {
        h = (h * d) % q;
    }

    int p = 0; // хэш для pattern
    int t = 0; // хэш для text

    for (int i = 0; i < m; i++) {
        p = (d * p + pattern[i]) % q;
        t = (d * t + text[i]) % q;
    }

    bool found = false;
    for (int i = 0; i <= n - m; i++) {
        if (p == t) {
            bool match = true;
            for (int j = 0; j < m; j++) {
                if (text[i + j] != pattern[j]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                std::cout << "Образец найден на позиции " << i << std::endl;
                found = true;
            }
        }

        if (i < n - m) {
            t = (d * (t - text[i] * h) + text[i + m]) % q;
            if (t < 0) {
                t += q;
            }
        }
    }

    if (!found) {
        std::cout << "Образец не найден" << std::endl;
    }

    return 0;
}"

#include <iostream>
#include <climits>
using namespace std;

int main() {
    const int V = 5;
    int graph[V][V] = {{0, 2, 0, 6, 0},
                       {2, 0, 3, 8, 5},
                       {0, 3, 0, 0, 7},
                       {6, 8, 0, 0, 9},
                       {0, 5, 7, 9, 0}};

    bool inMST[V] = {false};
    int key[V];
    int parent[V];

    for (int i = 0; i < V; i++) {
        key[i] = INT_MAX;
    }

    key[0] = 0;
    parent[0] = -1;

    for (int count = 0; count < V - 1; count++) {
        int minKey = INT_MAX, u;

        for (int v = 0; v < V; v++) {
            if (!inMST[v] && key[v] < minKey) {
                minKey = key[v];
                u = v;
            }
        }

        inMST[u] = true;

        for (int v = 0; v < V; v++) {
            if (graph[u][v] && !inMST[v] && graph[u][v] < key[v]) {
                parent[v] = u;
                key[v] = graph[u][v];
            }
        }
    }

    cout << \Ребра минимального остовного дерева:" << endl;
    cout << "Ребро \tВес" << endl;
    int totalWeight = 0;
    for (int i = 1; i < V; i++) {
        cout << parent[i] << " - " << i << " \t" << graph[i][parent[i]] << endl;
        totalWeight += graph[i][parent[i]];
    }
    cout << "Общий вес: " << totalWeight << endl;

    return 0;
}"

#include <iostream>
#include <climits>

int main() {
    const int V = 5;
    int graph[V][V] = {{0, 2, 0, 6, 0},
                       {2, 0, 3, 8, 5},
                       {0, 3, 0, 0, 7},
                       {6, 8, 0, 0, 9},
                       {0, 5, 7, 9, 0}};

    bool inMST[V] = {false};
    int key[V];
    int parent[V];

    for (int i = 0; i < V; i++) {
        key[i] = INT_MAX;
    }

    key[0] = 0;
    parent[0] = -1;

    for (int count = 0; count < V - 1; count++) {
        int minKey = INT_MAX, u;

        for (int v = 0; v < V; v++) {
            if (!inMST[v] && key[v] < minKey) {
                minKey = key[v];
                u = v;
            }
        }

        inMST[u] = true;

        for (int v = 0; v < V; v++) {
            if (graph[u][v] && !inMST[v] && graph[u][v] < key[v]) {
                parent[v] = u;
                key[v] = graph[u][v];
            }
        }
    }

    std::cout << \Ребра минимального остовного дерева:" << std::endl;
    std::cout << "Ребро \tВес" << std::endl;
    int totalWeight = 0;
    for (int i = 1; i < V; i++) {
        std::cout << parent[i] << " - " << i << " \t" << graph[i][parent[i]] << std::endl;
        totalWeight += graph[i][parent[i]];
    }
    std::cout << "Общий вес: " << totalWeight << std::endl;

    return 0;
}"

