#include <iostream>
#include <cstring>
using namespace std;

int main() {
    char source[] = \Hello";
    char destination[10];

    char* src = source;
    char* dest = destination;

    while(*src != '\0') {
        *dest = *src;
        src++;
        dest++;
    }
    *dest = '\0';

    cout << "Исходная строка: " << source << endl;
    cout << "Скопированная строка: " << destination << endl;

    return 0;
}"

