#include <iostream>
using namespace std;

int main() {
    char word[] = \POINTER";
    int length = 0;

    char* ptr = word;
    while (*ptr != '\0') {
        length++;
        ptr++;
    }

    cout << "Исходное слово: " << word << endl;
    cout << "Длина слова: " << length << endl;

    cout << "Слово в обратном порядке: ";
    ptr--;

    while (ptr >= word) {
        cout << *ptr;
        ptr--;
    }
    cout << endl;

    return 0;
}"

