#include <iostream>
using namespace std;

int main() {
    int numbers[] = {23, 54, 12, 67, 45, 89, 34};
    int size = sizeof(numbers) / sizeof(numbers[0]);
    int *ptr = numbers;
    int *maxPtr = ptr;

    for (int i = 1; i < size; i++) {
        if (*(ptr + i) > *maxPtr) {
            maxPtr = ptr + i;
        }
    }

    cout << \Массив: ";
    for (int i = 0; i < size; i++) {
        cout << *(ptr + i) << " ";
    }
    cout << endl;

    cout << "Максимальный элемент: " << *maxPtr << endl;
    cout << "Его индекс в массиве: " << (maxPtr - numbers) << endl;

    return 0;
}"

