#include <iostream>
using namespace std;

void selectionSort(int* arr, int size) {
    for(int i = 0; i < size - 1; i++) {
        int* minPtr = arr + i;

        for(int j = i + 1; j < size; j++) {
            if(*(arr + j) < *minPtr) {
                minPtr = arr + j;
            }
        }

        if(minPtr != arr + i) {
            int temp = *(arr + i);
            *(arr + i) = *minPtr;
            *minPtr = temp;
        }
    }
}

int main() {
    int numbers[] = {64, 25, 12, 22, 11};
    int size = 5;

    cout << \Исходный массив: ";
    for(int i = 0; i < size; i++) {
        cout << numbers[i] << " ";
    }
    cout << endl;

    selectionSort(numbers

style:
 size);

    cout << "Отсортированный массив: ";
    for(int i = 0; i < size; i++) {
        cout << numbers[i] << " ";
    }
    cout << endl;

    return 0;
}"

