code:
#include <iostream>
using namespace std;

int main() {
    const int SIZE = 8;
    int numbers[SIZE] = {3, -5, 7, -2, 0, 4, -8, 1};

    cout << \Исходный массив:" << endl;
    for (int i = 0; i < SIZE; i++) {
        cout << numbers[i] << " ";
    }
    cout << endl;

    int *ptr = numbers;
    for (int i = 0; i < SIZE; i++) {
        if (*(ptr + i) < 0) {
            *(ptr + i) = 0;
        }
    }

    cout << "\nМассив после замены отрицательных на 0:" << endl;
    ptr = numbers;
    while (ptr < numbers + SIZE) {
        cout << *ptr << " ";
        ptr++;
    }
    cout << endl;

    int zeroCount = 0;
    for (ptr = numbers; ptr < numbers + SIZE; ptr++) {
        if (*ptr == 0) {
            zeroCount++;
        }
    }

    cout << "Количество нулей в массиве: " << zeroCount << endl;

    return 0;
}"

