#include <iostream>
using namespace std;

int main() {
    int intVal = 42;
    float floatVal = 3.14f;
    char charVal = 'X';

    int* intPtr = &intVal;
    float* floatPtr = &floatVal;
    char* charPtr = &charVal;

    cout << \Целое число: " << *intPtr << endl;
    cout << "Дробное число: " << *floatPtr << endl;
    cout << "Символ: " << *charPtr << endl;

    *intPtr = 100;
    *floatPtr = 2.71f;
    *charPtr = 'Y';

    cout << "\nПосле изменений:" << endl;
    cout << "Целое число: " << intVal << endl;
    cout << "Дробное число: " << floatVal << endl;
    cout << "Символ: " << charVal << endl;

    cout << "\nРазмеры указателей:" << endl;
    cout << "sizeof(intPtr) = " << sizeof(intPtr) << endl;
    cout << "sizeof(floatPtr) = " << sizeof(floatPtr) << endl;
    cout << "sizeof(charPtr) = " << sizeof(charPtr) << endl;

    return 0;
}"

