#include <iostream>
using namespace std;

int main() {
    int matrix[2][3] = {{1, 2, 3}, {4, 5, 6}};

    int* ptr1 = &matrix[0][0];
    cout << \Линейный доступ: ";
    for(int i = 0; i < 6; i++) {
        cout << *(ptr1 + i) << " ";
    }
    cout << endl;

    int (*ptr2)[3] = matrix;
    cout << "Доступ по строкам:\n";
    for(int i = 0; i < 2; i++) {
        for(int j = 0; j < 3; j++) {
            cout << ptr2[i][j] << " ";
        }
        cout << endl;
    }

    int* rowPtrs[2];
    for(int i = 0; i < 2; i++) {
        rowPtrs[i] = matrix[i];
    }

    cout << "\nЧерез массив указателей на строки:\n";
    for(int i = 0; i < 2; i++) {
        for(int j = 0; j < 3; j++) {
            cout << *(rowPtrs[i] + j) << " ";
        }
        cout << endl;
    }

    ptr2[1][2] = 99;
    cout << "\nПосле ptr2[1][2] = 99: " << matrix[1][2] << endl;

    return 0;
}"

