#include <iostream>
using namespace std;

int main() {
    int a = 10, b = 20;
    int* p = &a;

    cout << \Этап 1: p указывает на a" << endl;
    cout << "  Значение a: " << a << endl;
    cout << "  Адрес a (&a): " << &a << endl;
    cout << "  Значение указателя p: " << p << endl;
    cout << "  Значение по адресу p (*p): " << *p << endl;
    cout << "  Адрес самого указателя (&p): " << &p << endl;

    p = &b;
    cout << "\nЭтап 2: p теперь указывает на b" << endl;
    cout << "  Значение b: " << b << endl;
    cout << "  Адрес b (&b): " << &b << endl;
    cout << "  Значение указателя p: " << p << endl;
    cout << "  Значение по адресу p (*p): " << *p << endl;

    *p = 99;
    cout << "\nЭтап 3: изменили *p на 99" << endl;
    cout << "  Теперь значение b: " << b << endl;
    cout << "  Значение по адресу p (*p): " << *p << endl;

    return 0;
}"

