#include <iostream>
using namespace std;

void reverseArray(int* arr, int size) {
    int* start = arr;
    int* end = arr + size - 1;

    while(start < end) {
        int temp = *start;
        *start = *end;
        *end = temp;

        start++;
        end--;
    }
}

void printArray(const int* arr, int size) {
    for(int i = 0; i < size; i++) {
        cout << *(arr + i) << \ ";
    }
    cout << endl;
}

