#include <iostream>
#include <cctype>
using namespace std;

int countVowels(const char* str) {
    int count = 0;
    const char* ptr = str;

    while(*ptr != '\0') {
        char c = tolower(*ptr);
        if(c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u' || c == 'y') {
            count++;
        }
        ptr++;
    }
    return count;
}

int main() {
    const char* text = \Hello

style:
 World! Programming in C++.";

    cout << "Текст: \"" << text << "\"" << endl;

    int vowels = countVowels(text);
    cout << "Количество гласных букв: " << vowels << endl;

    const char* ptr = text;
    int consonants = 0;

    while(*ptr != '\0') {
        char c = tolower(*ptr);
        if(isalpha(c) && !(c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u' || c == 'y')) {
            consonants++;
        }
        ptr++;
    }

    cout << "Количество согласных букв: " << consonants << endl;

    return 0;
}"

