#include <iostream>
using namespace std;

union Data {
    int intValue;
    float floatValue;
    char charValue;
};

int main() {
    Data data;
    Data* ptr = &data;

    ptr->intValue = 65;
    cout << \intValue: " << ptr->intValue << endl;

    ptr->charValue = 'A';
    cout << "charValue: " << ptr->charValue << endl;
    cout << "intValue теперь: " << ptr->intValue << " (перекрытие памяти)" << endl;

    ptr->floatValue = 3.14f;
    cout << "floatValue: " << ptr->floatValue << endl;

    int* intPtr = &data.intValue;
    char* charPtr = &data.charValue;

    *intPtr = 100;
    cout << "\nПосле *intPtr = 100:" << endl;
    cout << "*intPtr = " << *intPtr << endl;
    cout << "*charPtr = " << *charPtr << " (ASCII " << (int)*charPtr << ")" << endl;

    cout << "\nРазмер Data: " << sizeof(Data) << " байт" << endl;
    cout << "Размер указателя на Data: " << sizeof(ptr) << " байт" << endl;

    return 0;
}"

