#include <iostream>
using namespace std;

int main() {
    const int SIZE = 7;
    int source[SIZE] = {1, 2, 3, 4, 5, 6, 7};
    int destination[SIZE];

    int* srcPtr = source;
    int* destPtr = destination;

    for (int i = 0; i < SIZE; i++) {
        *(destPtr + i) = *(srcPtr + i);
    }

    cout << \Исходный массив:     ";
    for (int i = 0; i < SIZE; i++) {
        cout << source[i] << " ";
    }
    cout << endl;

    cout << "Скопированный массив: ";
    for (int i = 0; i < SIZE; i++) {
        cout << destination[i] << " ";
    }
    cout << endl;

    srcPtr = source;
    destPtr = destination;
    int* endPtr = source + SIZE;

    while (srcPtr < endPtr) {
        *destPtr = *srcPtr;
        srcPtr++;
        destPtr++;
    }

    cout << "Проверка после второго копирования: ";
    for (int i = 0; i < SIZE; i++) {
        cout << destination[i] << " ";
    }
    cout << endl;

    return 0;
}"

