#include <iostream>
using namespace std;

int main() {
    int value = 5;
    int* ptr = &value;
    int** ptrToPtr = &ptr;

    cout << \Исходная цепочка:" << endl;
    cout << "value = " << value << endl;
    cout << "ptr = " << ptr << " (указывает на value)" << endl;
    cout << "*ptr = " << *ptr << endl;
    cout << "ptrToPtr = " << ptrToPtr << " (указывает на ptr)" << endl;
    cout << "*ptrToPtr = " << *ptrToPtr << " (значение ptr)" << endl;
    cout << "**ptrToPtr = " << **ptrToPtr << " (значение value)" << endl;

    **ptrToPtr = 10;
    cout << "\nПосле **ptrToPtr = 10:" << endl;
    cout << "value = " << value << endl;

    int newValue = 20;
    *ptrToPtr = &newValue;

    cout << "\nПосле *ptrToPtr = &newValue:" << endl;
    cout << "*ptr = " << *ptr << " (теперь указывает на newValue)" << endl;
    cout << "value = " << value << " (не изменилось)" << endl;
    cout << "newValue = " << newValue << endl;

    return 0;
}"

