    std::cout << "*ptr = " << *ptr << " (теперь указывает на newValue)" << std::endl;
    std::cout << "value = " << value << " (не изменилось)" << std::endl;
    std::cout << "newValue = " << newValue << std::endl;

    return 0;
}"

