    int** matrix = new int*[rows];
    for(int i = 0; i < rows; i++) {
        matrix[i] = new int[cols];
    }

    int counter = 1;
    for(int i = 0; i < rows; i++) {
        for(int j = 0; j < cols; j++) {
            matrix[i][j] = counter++;
        }
    }

    cout << \Динамическая матрица " << rows << "x" << cols << ":" << endl;
    for(int i = 0; i < rows; i++) {
        int* rowPtr = matrix[i];
        for(int j = 0; j < cols; j++) {
            cout << *(rowPtr + j) << "\t";
        }
        cout << endl;
    }

    cout << "\nДоступ через двойной указатель:" << endl;
    cout << "matrix[1][2] = " << *(*(matrix + 1) + 2) << endl;

    *(*(matrix + 2) + 3) = 99;
    cout << "После изменения matrix[2][3] = " << matrix[2][3] << endl;

    for(int i = 0; i < rows; i++) {
        delete[] matrix[i];
    }
    delete[] matrix;

    return 0;
}"

