#include <iostream>
using namespace std;

int main() {
    int x = 5, y = 10, z = 15;
    int *p1, *p2;

    p1 = &x;
    p2 = &y;

    cout << \Исходные значения:" << endl;
    cout << "p1 = " << p1 << " (указывает на x = " << *p1 << ")" << endl;
    cout << "p2 = " << p2 << " (указывает на y = " << *p2 << ")" << endl;

    if (p1 == p2) {
        cout << "p1 и p2 указывают на одну и ту же переменную" << endl;
    } else {
        cout << "p1 и p2 указывают на разные переменные" << endl;
    }

    p2 = p1;
    cout << "\nПосле p2 = p1:" << endl;
    cout << "p1 = " << p1 << " (указывает на x = " << *p1 << ")" << endl;
    cout << "p2 = " << p2 << " (указывает на x = " << *p2 << ")" << endl;

    if (p1 == p2) {
        cout << "Теперь p1 и p2 указывают на одну переменную" << endl;
    }

    *p2 = 100;
    cout << "\nПосле *p2 = 100:" << endl;
    cout << "x = " << x << endl;
    cout << "*p1 = " << *p1 << endl;

    p1 = nullptr;
    if (p1 == nullptr) {
        cout << "\np1 теперь равен nullptr" << endl;
    }

    return 0;
}"

