#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* next;

    Node(int value) : data(value), next(nullptr) {}
};

void printList(Node* head) {
    Node* current = head;
    cout << \Список: ";
    while(current != nullptr) {
        cout << current->data << " -> ";
        current = current->next;
    }
    cout << "nullptr" << endl;
}

int main() {
    Node* head = new Node(10);
    Node* second = new Node(20);
    Node* third = new Node(30);

    head->next = second;
    second->next = third;

    printList(head);

    Node* newHead = new Node(5);
    newHead->next = head;
    head = newHead;

    cout << "\nПосле добавления в начало:" << endl;
    printList(head);

    int target = 20;
    Node* current = head;
    while(current != nullptr) {
        if(current->data == target) {
            cout << "\nНайден элемент " << target << endl;
            break;
        }
        current = current->next;
    }

    current = head;
    while(current != nullptr) {
        Node* toDelete = current;
        current = current->next;
        delete toDelete;
    }

    return 0;
}"

