#include <iostream>
using namespace std;

void insertionSort(int* arr, int size) {
    for(int i = 1; i < size; i++) {
        int key = *(arr + i);
        int* jPtr = arr + i - 1;

        while(jPtr >= arr && *jPtr > key) {
            *(jPtr + 1) = *jPtr;
            jPtr--;
        }

        *(jPtr + 1) = key;
    }
}

void printArray(const int* arr, int size) {
    for(int i = 0; i < size; i++) {
        cout << *(arr + i) << \ ";
    }
    cout << endl;
}

