#include <iostream>
using namespace std;

int* binarySearch(int* arr, int size, int target) {
    int* left = arr;
    int* right = arr + size - 1;

    while(left <= right) {
        int* mid = left + (right - left) / 2;

        if(*mid == target) {
            return mid;
        }
        else if(*mid < target) {
            left = mid + 1;
        }
        else {
            right = mid - 1;
        }
    }

    return nullptr;
}

