#include <iostream>
using namespace std;

bool findMinMax(const int* arr, int size, int* minPtr, int* maxPtr) {
    if (size <= 0 || arr == nullptr) {
        return false;
    }

    *minPtr = *arr;
    *maxPtr = *arr;

    const int* ptr = arr + 1;
    for (int i = 1; i < size; i++) {
        if (*ptr < *minPtr) {
            *minPtr = *ptr;
        }
        if (*ptr > *maxPtr) {
            *maxPtr = *ptr;
        }
        ptr++;
    }

    return true;
}

int main() {
    int numbers[] = {34, 7, 23, 32, 5, 62, 12, 45};
    int size = sizeof(numbers) / sizeof(numbers[0]);

    int minValue, maxValue;

    if (findMinMax(numbers, size, &minValue, &maxValue)) {
        cout << \Массив: ";
        for (int i = 0; i < size; i++) {
            cout << numbers[i] << " ";
        }
        cout << endl;

        cout << "Минимальный элемент: " << minValue << endl;
        cout << "Максимальный элемент: " << maxValue << endl;
    } else {
        cout << "Ошибка: пустой массив или неверные параметры." << endl;
    }

    int emptyArr[] = {};
    if (!findMinMax(emptyArr

keywords:
 &maxValue)) {
        cout << "\nОбработка пустого массива корректна." << endl;
    }

    return 0;
}"

