    cout << "Адрес ref: " << &ref << " (совпадает с адресом value)" << endl;

    ref = 100;
    cout << "После ref = 100:" << endl;
    cout << "value = " << value << endl;

    cout << "\nРабота с указателем:" << endl;
    cout << "ptr = " << ptr << " (адрес value)" << endl;
    cout << "*ptr = " << *ptr << endl;

    *ptr = 200;
    cout << "После *ptr = 200:" << value << endl;

    cout << "\nКлючевые различия:" << endl;
    cout << "1. Ссылка должна быть инициализирована при объявлении

style:
указатель - нет." << endl;
