code:
#include <iostream>
using namespace std;

const int MAX_SIZE = 5;

class Stack {
private:
    int data[MAX_SIZE];
    int* topPtr;

public:
    Stack() {
        topPtr = data;
    }

    bool push(int value) {
        if(topPtr < data + MAX_SIZE) {
            *topPtr = value;
            topPtr++;
            return true;
        }
        return false;
    }

    bool pop(int& value) {
        if(topPtr > data) {
            topPtr--;
            value = *topPtr;
            return true;
        }
        return false;
    }

    bool isEmpty() {
        return topPtr == data;
    }

    bool isFull() {
        return topPtr == data + MAX_SIZE;
    }

    void print() {
        cout << \Стек (снизу вверх): ";
        for(int* ptr = data; ptr < topPtr; ptr++) {
            cout << *ptr << " ";
        }
        cout << endl;
    }
};

int main() {
    Stack stack;

    for(int i = 1; i <= 5; i++) {
        if(stack.push(i * 10)) {
            cout << "Добавлен: " << i * 10 << endl;
        }
    }

    stack.print();

    if(!stack.push(60)) {
        cout << "Стек полон! Нельзя добавить 60" << endl;
    }

    int value;
    while(stack.pop(value)) {
        cout << "Извлечен: " << value << endl;
    }

    if(stack.isEmpty()) {
        cout << "Стек пуст" << endl;
    }

    return 0;
}"

