#include <cmath>
using namespace std;

bool solveQuadratic(double a, double b, double c, double* root1, double* root2) {
    if(a == 0) {
        return false;
    }

    double discriminant = b*b - 4*a*c;

    if(discriminant < 0) {
        return false;
    }

    *root1 = (-b + sqrt(discriminant)) / (2*a);
    *root2 = (-b - sqrt(discriminant)) / (2*a);

    return true;
}

