code:
#include <iostream>
#include <memory>
using namespace std;

class Resource {
public:
    Resource(int id) : id(id) {
        cout << \Ресурс " << id << " создан" << endl;
    }

    ~Resource() {
        cout << "Ресурс " << id << " уничтожен" << endl;
    }

    void use() {
        cout << "Используем ресурс " << id << endl;
    }

private:
    int id;
};

int main() {
    cout << "=== unique_ptr демонстрация ===" << endl;

    unique_ptr<Resource> ptr1(new Resource(1));

    ptr1->use();

    cout << "\nПеремещение владения:" << endl;
    unique_ptr<Resource> ptr2 = move(ptr1);

    if (!ptr1) {
        cout << "ptr1 теперь пуст" << endl;
    }

    if (ptr2) {
        cout << "ptr2 владеет ресурсом" << endl;
        ptr2->use();
    }

    auto ptr3 = make_unique<Resource>(3);
    ptr3->use();

    cout << "\nunique_ptr для массива:" << endl;
    unique_ptr<int[]> arrPtr(new int[5]);

    for (int i = 0; i < 5; i++) {
        arrPtr[i] = i * 10;
    }

    cout << "Массив: ";
    for (int i = 0; i < 5; i++) {
        cout << arrPtr[i] << " ";
    }
    cout << endl;

    ptr2.reset();
    cout << "После ptr2.reset()" << endl;

    Resource* rawPtr = ptr3.get();
    cout << "Сырой указатель из ptr3: " << rawPtr << endl;

    Resource* releasedPtr = ptr3.release();
    if (!ptr3) {
        cout << "После release()

style:
ptr3 пуст" << endl;
   }

   delete releasedPtr;

   cout << "\nКонец main()

topic:
 оставшиеся unique_ptr уничтожатся автоматически" << endl;

    return 0;
}"

