code:
#include <iostream>
using namespace std;

const int BUFFER_SIZE = 5;

class CircularBuffer {
private:
    int buffer[BUFFER_SIZE];
    int* head;
    int* tail;
    int count;

public:
    CircularBuffer() : head(buffer), tail(buffer), count(0) {}

    bool push(int value) {
        if(count >= BUFFER_SIZE) {
            return false;
        }

        *head = value;
        head++;
        if(head >= buffer + BUFFER_SIZE) {
            head = buffer;
        }
        count++;
        return true;
    }

    bool pop(int& value) {
        if(count <= 0) {
            return false;
        }

        value = *tail;
        tail++;
        if(tail >= buffer + BUFFER_SIZE) {
            tail = buffer;
        }
        count--;
        return true;
    }

    void print() {
        cout << \Буфер: ";
        int* ptr = tail;
        for(int i = 0; i < count; i++) {
            cout << *ptr << " ";
            ptr++;
            if(ptr >= buffer + BUFFER_SIZE) {
                ptr = buffer;
            }
        }
        cout << endl;
    }

    bool isEmpty() { return count == 0; }
    bool isFull() { return count == BUFFER_SIZE; }
};

int main() {
    CircularBuffer cb;

    for(int i = 1; i <= 5; i++) {
        if(cb.push(i * 10)) {
            cout << "Добавлен: " << i * 10 << endl;
        }
    }

    cb.print();

    if(!cb.push(60)) {
        cout << "Буфер полон! Нельзя добавить 60" << endl;
    }

    int value;
    for(int i = 0; i < 3; i++) {
        if(cb.pop(value)) {
            cout << "Извлечен: " << value << endl;
        }
    }

    cb.print();

    cb.push(100);
    cb.push(200);

    cb.print();

    while(cb.pop(value)) {
        cout << "Извлечен: " << value << endl;
    }

    if(cb.isEmpty()) {
        cout << "Буфер пуст" << endl;
    }

    return 0;
}"

#include <iostream>

const int BUFFER_SIZE = 5;

class CircularBuffer {
private:
    int buffer[BUFFER_SIZE];
    int* head;
    int* tail;
    int count;

public:
    CircularBuffer() : head(buffer), tail(buffer), count(0) {}

    bool push(int value) {
