            return false;
        }

        *head = value;
        head++;
        if(head >= buffer + BUFFER_SIZE) {
            head = buffer;
        }
        count++;
        return true;
    }

    bool pop(int& value) {
        if(count <= 0) {
            return false;
        }

        value = *tail;
        tail++;
        if(tail >= buffer + BUFFER_SIZE) {
            tail = buffer;
        }
        count--;
        return true;
    }

    void print() {
        std::cout << \Буфер: ";
        int* ptr = tail;
        for(int i = 0; i < count; i++) {
            std::cout << *ptr << " ";
            ptr++;
            if(ptr >= buffer + BUFFER_SIZE) {
                ptr = buffer;
            }
        }
        std::cout << std::endl;
    }

    bool isEmpty() { return count == 0; }
    bool isFull() { return count == BUFFER_SIZE; }
};

int main() {
    CircularBuffer cb;

    for(int i = 1; i <= 5; i++) {
        if(cb.push(i * 10)) {
            std::cout << "Добавлен: " << i * 10 << std::endl;
        }
    }

    cb.print();

    if(!cb.push(60)) {
        std::cout << "Буфер полон! Нельзя добавить 60" << std::endl;
    }

    int value;
    for(int i = 0; i < 3; i++) {
        if(cb.pop(value)) {
            std::cout << "Извлечен: " << value << std::endl;
        }
    }

    cb.print();

    cb.push(100);
    cb.push(200);

    cb.print();

    while(cb.pop(value)) {
        std::cout << "Извлечен: " << value << std::endl;
    }

    if(cb.isEmpty()) {
        std::cout << "Буфер пуст" << std::endl;
    }

    return 0;
}"

