    std::cout << "sizeof(short) = " << sizeof(short) << " байт" << std::endl;
    std::cout << "sizeof(int) = " << sizeof(int) << " байт" << std::endl;
    std::cout << "sizeof(double) = " << sizeof(double) << " байт" << std::endl;

    std::cout << "\nАдреса элементов (начало массивов):" << std::endl;
    std::cout << "chars[0]   = " << (void*)charPtr << std::endl;
    std::cout << "shorts[0]  = " << shortPtr << std::endl;
    std::cout << "ints[0]    = " << intPtr << std::endl;
    std::cout << "doubles[0] = " << doublePtr << std::endl;

    std::cout << "\nАрифметика указателей (переход к элементу с индексом 2):" << std::endl;
    std::cout << "charPtr + 2   = " << (void*)(charPtr + 2) 
              << " (смещение: " << 2 * sizeof(char) << " байт)" << std::endl;
    std::cout << "shortPtr + 2  = " << (shortPtr + 2) 
              << " (смещение: " << 2 * sizeof(short) << " байт)" << std::endl;
    std::cout << "intPtr + 2    = " << (intPtr + 2) 
              << " (смещение: " << 2 * sizeof(int) << " байт)" << std::endl;
    std::cout << "doublePtr + 2 = " << (doublePtr + 2) 
              << " (смещение: " << 2 * sizeof(double) << " байт)" << std::endl;

    std::cout << "\nЗначения элементов через указатели:" << std::endl;
    std::cout << "*(charPtr + 2)   = '" << *(charPtr + 2) << "'" << std::endl;
    std::cout << "*(shortPtr + 2)  = " << *(shortPtr + 2) << std::endl;
    std::cout << "*(intPtr + 2)    = " << *(intPtr + 2) << std::endl;
    std::cout << "*(doublePtr + 2) = " << *(doublePtr + 2) << std::endl;

    char* charPtr1 = &chars[1];
    char* charPtr2 = &chars[4];
    std::cout << "\nРазность указателей (в элементах):" << std::endl;
    std::cout << "charPtr2 - charPtr1 = " << (charPtr2 - charPtr1) 
              << " элементов char" << std::endl;

    int* intPtr1 = &ints[0];
    int* intPtr2 = &ints[3];
    std::cout << "intPtr2 - intPtr1 = " << (intPtr2 - intPtr1) 
              << " элементов int" << std::endl;

    return 0;
