#include <iostream>
#include <string>
using namespace std;

struct Logger {
    ostream& out; // Ссылка как член класса
    Logger(ostream& os) : out(os) {} // Инициализация в списке инициализации
    void log(const string& message) {
        out << \LOG: " << message << endl;
    }
};

int main() {
    Logger consoleLogger(cout);
    consoleLogger.log("Программа запущена");
    // Logger badLogger; // Ошибка: ссылка должна быть инициализирована
    return 0;
}"

#include <iostream>
#include <string>

struct Logger {
    std::ostream& out; // Ссылка как член класса
    Logger(std::ostream& os) : out(os) {} // Инициализация в списке инициализации
    void log(const std::string& message) {
        out << \LOG: " << message << std::endl;
    }
};

int main() {
    Logger consoleLogger(std::cout);
    consoleLogger.log("Программа запущена");
    // Logger badLogger; // Ошибка: ссылка должна быть инициализирована
    return 0;
}"

#include <iostream>
using namespace std;

void bitwiseNot(int& num) {
    num = ~num;
}

int main() {
    int a = 5; // 00000101 в двоичной
    cout << \До инвертирования: a = " << a << endl;

    bitwiseNot(a);
    cout << "После инвертирования: a = " << a << endl;

    int b = 0;
    cout << "\nДо инвертирования: b = " << b << endl;

    bitwiseNot(b);
    cout << "После инвертирования: b = " << b << endl;

    return 0;
}"

