    std::cout << \До инвертирования: a = " << a << std::endl;

    bitwiseNot(a);
    std::cout << "После инвертирования: a = " << a << std::endl;

    int b = 0;
    std::cout << "\nДо инвертирования: b = " << b << std::endl;

    bitwiseNot(b);
    std::cout << "После инвертирования: b = " << b << std::endl;

    return 0;
}"

#include <iostream>
using namespace std;

void printValue(const int& value) {
    // value = 10; // ошибка компиляции - нельзя изменять константную ссылку
    cout << \Значение: " << value << endl;
}

int main() {
    int a = 5;
    const int b = 10;

    printValue(a); // можно передать неконстантную переменную
    printValue(b); // можно передать константную переменную
    printValue(42); // можно передать литерал

    return 0;
}"

