#include <iostream>
using namespace std;

void decrement(int& value) {
    value--;
}

int main() {
    int a = 5;
    cout << \До decrement: a = " << a << endl;

    decrement(a);
    cout << "После decrement: a = " << a << endl;

    decrement(a);
    cout << "После второго decrement: a = " << a << endl;

    int b = 0;
    cout << "\nДо decrement: b = " << b << endl;

    decrement(b);
    cout << "После decrement: b = " << b << endl;

    return 0;
}"

