#include <iostream>
using namespace std;

void readOnly(const int& value) {
    // Можем читать, но не можем изменять
    cout << \Чтение значения: " << value << endl;
    // value = 10; // ошибка компиляции
}

void modify(int& value) {
    value = 100;
    cout << "Значение изменено на: " << value << endl;
}

int main() {
    int data = 5;

    readOnly(data); // безопасная передача
    modify(data);   // изменяем данные
    readOnly(data); // снова читаем

    return 0;
}"

