#include <iostream>
using namespace std;

void addArrays(int arr1[], int arr2[], int result[], int size) {
    for (int i = 0; i < size; i++) {
        result[i] = arr1[i] + arr2[i];
    }
}

int main() {
    int a[3] = {1, 2, 3};
    int b[3] = {4, 5, 6};
    int sum[3];

    addArrays(a, b, sum, 3);

    cout << \Результат сложения массивов: ";
    for (int i = 0; i < 3; i++) {
        cout << sum[i] << " ";
    }
    cout << endl;

    return 0;
}"

