#include <iostream>
using namespace std;

int main() {
    int globalValue = 0;
    {
        int& refInScope = globalValue;
        refInScope = 10;
        cout << \Внутри внутреннего блока: globalValue = " << globalValue << endl;
    }
    cout << "Во внешнем блоке: globalValue = " << globalValue << endl;
    int& anotherRef = globalValue;
    anotherRef++;
    cout << "После инкремента через anotherRef: globalValue = " << globalValue << endl;
    return 0;
}"

