#include <iostream>
using namespace std;

// Параметры по ссылке не могут иметь временные объекты как значения по умолчанию,
// поэтому нужна перегрузка или другие методы.
void printValue(const int& val) {
    cout << \Значение: " << val << endl;
}

// Перегруженная функция без параметров
void printValue() {
    static int defaultValue = 100;
    printValue(defaultValue);
}

int main() {
    int x = 5;
    printValue(x);
    printValue(); // Используется значение по умолчанию
    return 0;
}"

