code:
#include <iostream>
using namespace std;

void allocateMemory(int*& ptr, int size) {
    delete[] ptr; // Безопасно удаляем старую память
    ptr = new int[size]; // Модифицируем исходный указатель
    for (int i = 0; i < size; ++i) {
        ptr[i] = i * 10;
    }
}

int main() {
    int* myArray = nullptr;
    allocateMemory(myArray, 5);
    cout << \Массив: ";
    for (int i = 0; i < 5; ++i) {
        cout << myArray[i] << " ";
    }
    cout << endl;
    delete[] myArray;
    return 0;
}"

#include <iostream>

