    for (int i = 0; i < size; ++i) {
        ptr[i] = i * 10;
    }
}

int main() {
    int* myArray = nullptr;
    allocateMemory(myArray, 5);
    std::cout << \Массив: ";
    for (int i = 0; i < 5; ++i) {
        std::cout << myArray[i] << " ";
    }
    std::cout << std::endl;
    delete[] myArray;
    return 0;
}"

