#include <iostream>
using namespace std;

int main() {
    int arr[3] = {10, 20, 30};

    cout << \Исходный массив: ";
    for (int i = 0; i < 3; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    // Ссылка на первый элемент
    int& first = arr[0];
    first = 100;

    // Ссылка на второй элемент
    int& second = arr[1];
    second = 200;

    cout << "После изменений через ссылки: ";
    for (int i = 0; i < 3; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    return 0;
}"

