#include <iostream>
using namespace std;

void reverseArray(int (&arr)[5]) {
    for (int i = 0; i < 2; i++) {
        int temp = arr[i];
        arr[i] = arr[4 - i];
        arr[4 - i] = temp;
    }
}

int main() {
    int numbers[5] = {1, 2, 3, 4, 5};

    cout << \Исходный массив: ";
    for (int i = 0; i < 5; i++) {
        cout << numbers[i] << " ";
    }
    cout << endl;

    reverseArray(numbers);

    cout << "Инвертированный массив: ";
    for (int i = 0; i < 5; i++) {
        cout << numbers[i] << " ";
    }
    cout << endl;

    return 0;
}"

