    int& alias = original; // alias - псевдоним для original

    cout << \original = " << original << endl;
    cout << "alias = " << alias << endl;

    alias = 100; // меняем значение через псевдоним

    cout << "\nПосле изменения через alias:" << endl;
    cout << "original = " << original << endl;
    cout << "alias = " << alias << endl;

    // Демонстрация что это один и тот же объект
    cout << "\nАдрес original: " << &original << endl;
    cout << "Адрес alias: " << &alias << endl;

    return 0;
}"

