#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> vec = {1, 2, 3, 4, 5};
    int& ref = vec[2]; // Ссылка на третий элемент
    cout << \Исходный вектор: ";
    for (int v : vec) cout << v << " ";
    cout << "\nref = " << ref << endl;

    vec.push_back(6); // Может вызвать реаллокацию
    // ref теперь может быть инвалидирована!
    cout << "После push_back: ";
    for (int v : vec) cout << v << " ";
    cout << "\nref = " << ref << endl; // Неопределенное поведение

    // Безопасный доступ по индексу
    cout << "vec[2] = " << vec[2] << endl; // Корректно
    return 0;
}"

