#include <iostream>
using namespace std;

struct Flags {
    unsigned int isReady : 1;
    unsigned int isActive : 1;
    unsigned int : 6; // неиспользуемые биты
};

int main() {
    Flags f = {0, 1};

    // Нельзя создать ссылку на отдельный бит, но можно на весь объект
    Flags& ref = f;
    ref.isReady = 1;

    cout << \isReady: " << f.isReady << endl;
    cout << "isActive: " << f.isActive << endl;

    // Ссылка на константный объект с битовыми полями
    const Flags& constRef = f;
    // constRef.isReady = 0; // Ошибка: константная ссылка

    // Можно читать битовые поля через константную ссылку
    cout << "Чтение через constRef: " << constRef.isActive << endl;

    return 0;
}"

