#include <iostream>
using namespace std;

int globalCounter = 0;

// Возвращает ссылку на глобальную переменную
int& getGlobalCounter() {
    return globalCounter;
}

int main() {
    cout << \Начальное значение: " << globalCounter << endl;

    // Модификация через возвращаемую ссылку
    getGlobalCounter() = 10;
    cout << "После присваивания: " << globalCounter << endl;

    // Использование в выражениях
    getGlobalCounter() += 5;
    cout << "После увеличения: " << globalCounter << endl;

    // Создание новой ссылки на глобальную переменную
    int& localRef = getGlobalCounter();
    localRef++;
    cout << "После localRef++: " << globalCounter << endl;

    return 0;
}"

