#include <iostream>
using namespace std;

void process(int x) {
    cout << \process по значению: " << x << endl;
}

void process(int& x) {
    cout << "process по ссылке: " << x << endl;
    x++;
}

void process(const int& x) {
    cout << "process по константной ссылке: " << x << endl;
}

int main() {
    int a = 5;
    const int b = 10;

    process(a);       // Вызовет process(int&)
    process(b);       // Вызовет process(const int&)
    process(42);      // Вызовет process(const int&)
    process(a + 1);   // Вызовет process(const int&)

    // Явное указание нужной перегрузки
    process(static_cast<const int&>(a)); // Вызовет process(const int&)

    return 0;
}"

