#include <iostream>
using namespace std;

// Возвращает ссылку на максимальный элемент в массиве
int& findMax(int arr[], int size) {
    int maxIndex = 0;
    for (int i = 1; i < size; ++i) {
        if (arr[i] > arr[maxIndex]) {
            maxIndex = i;
        }
    }
    return arr[maxIndex]; // Возвращаем ссылку на элемент
}

int main() {
    int numbers[] = {3, 7, 2, 9, 5};
    int size = 5;
    int& maxRef = findMax(numbers, size);
    cout << \Максимальный элемент: " << maxRef << endl;
    maxRef = 100; // Модифицируем максимальный элемент через ссылку
    cout << "После изменения: ";
    for (int i = 0; i < size; ++i) {
        cout << numbers[i] << " ";
    }
    cout << endl;
    return 0;
}"

