code:
#include <iostream>
using namespace std;

class Container {
    int value;
public:
    Container(int v) : value(v) {}

    // Метод возвращает ссылку на объект для цепочки вызовов
    Container& setValue(int v) {
        value = v;
        return *this;
    }

    Container& add(int x) {
        value += x;
        return *this;
    }

    Container& multiply(int x) {
        value *= x;
        return *this;
    }

    int getValue() const { return value; }
};

int main() {
    Container c(10);

    // Цепочка вызовов благодаря возврату ссылки
    c.setValue(5).add(3).multiply(2);

    cout << \Результат: " << c.getValue() << endl; // (5 + 3) * 2 = 16

    return 0;
}"

