#include <cmath>
using namespace std;

struct CircleProperties {
    double area;
    double circumference;
};

void calculateCircle(double radius, CircleProperties& result) {
    result.area = M_PI * radius * radius;
    result.circumference = 2 * M_PI * radius;
}

int main() {
    CircleProperties props;

    calculateCircle(5.0, props);

