#include <iostream>
using namespace std;

int main() {
    int arr[5] = {1, 2, 3, 4, 5};

    cout << \Исходный массив: ";
    for (int i = 0; i < 5; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    // Изменение элементов через ссылку в цикле for
    for (int i = 0; i < 5; i++) {
        int& element = arr[i]; // ссылка на элемент массива
        element *= 2; // удваиваем значение
    }

    cout << "Массив после удвоения: ";
    for (int i = 0; i < 5; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    // Еще один способ с использованием ссылки
    for (int& elem : arr) {
        elem += 10; // добавляем 10 к каждому элементу
    }

    cout << "Массив после добавления 10: ";
    for (int i = 0; i < 5; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    return 0;
}"

