int main() {
    int value = 42;
    int* ptr = &value;
    const int*& refPtr = ptr; // Константная ссылка на указатель на константу
    // *refPtr = 100; // Ошибка: нельзя изменить значение через const int*
    int another = 100;
    // refPtr = &another; // Ошибка: refPtr - константная ссылка? Нет, это ссылка на константный указатель, но сам указатель не константный через ссылку?
    // Уточнение: refPtr - ссылка на указатель на константное int. Через refPtr нельзя изменить значение, но можно изменить адрес? На самом деле это не константная ссылка, а ссылка на указатель-на-константу.
    // Чтобы ссылка была константной: int* const& cref = ptr;
    int* const& constRef = ptr; // Константная ссылка на указатель
    // constRef = &another; // Ошибка: нельзя изменить саму ссылку (адрес в указателе)
    *constRef = 200; // А значение изменить можно
    cout << \value = " << value << endl;
    return 0;
}"

