#include <iostream>
using namespace std;

void process(int& x) {
    cout << \Обработка int&: " << x << endl;
}

void process(const int& x) {
    cout << "Обработка const int&: " << x << endl;
}

void process(double x) {
    cout << "Обработка double: " << x << endl;
}

int main() {
    int a = 5;
    const int b = 10;
    double c = 3.14;

    process(a);       // Вызовет process(int&)
    process(b);       // Вызовет process(const int&)
    process(c);       // Вызовет process(double)
    process(42);      // Вызовет process(const int&) - нет неявного преобразования в int&

    // Явное преобразование
    process(static_cast<double>(a)); // Вызовет process(double)

    // Смешанные типы
    float f = 2.5f;
    process(f);       // Вызовет process(double) из-за преобразования float -> double
    // process(static_cast<int&>(f)); // Ошибка: нельзя привести float к int&

    return 0;
}"

