code:
#include <iostream>
using namespace std;

class Counter {
    int count;
public:
    Counter(int c = 0) : count(c) {}

    // Возвращает ссылку на сам объект
    Counter& increment() {
        count++;
        return *this;
    }

    Counter& decrement() {
        count--;
        return *this;
    }

    Counter& reset() {
        count = 0;
        return *this;
    }

    int get() const { return count; }
};

// Внешняя функция тоже может возвращать ссылку на параметр
Counter& normalizeCounter(Counter& c) {
    if (c.get() < 0) c.reset();
    return c;
}

int main() {
    Counter c(5);

    // Цепочка вызовов методов
    c.increment().increment().decrement();
    cout << \Счетчик после цепочки: " << c.get() << endl;

    // Использование внешней функции
    Counter& ref = normalizeCounter(c);
    ref.increment();
    cout << "После normalize и increment: " << c.get() << endl;

    // Проверка что это один и тот же объект
    cout << "Адрес c: " << &c << endl;
    cout << "Адрес ref: " << &ref << endl;

    return 0;
}"

