code:
#include <iostream>
using namespace std;

// НЕПРАВИЛЬНО: возврат ссылки на локальную переменную
int& badFunction() {
    int localVar = 42; // Локальная переменная
    cout << \Адрес localVar: " << &localVar << endl;
    return localVar; // ОПАСНО: возвращаем ссылку на локальную переменную
}

// ПРАВИЛЬНО: возврат ссылки на статическую переменную
int& goodFunction() {
    static int staticVar = 100; // Статическая переменная
    cout << "Адрес staticVar: " << &staticVar << endl;
    return staticVar; // Безопасно
}

int main() {
    // Проблема dangling reference
    int& badRef = badFunction(); // badRef теперь висячая ссылка
    cout << "Адрес badRef: " << &badRef << endl;
    // Обращение через badRef - неопределенное поведение
    // cout << "Значение badRef: " << badRef << endl; // МОЖЕТ РАБОТАТЬ

style:
 НО НЕ НАДЕЖНО

    // Правильное использование
    int& goodRef = goodFunction();
    cout << "Значение goodRef: " << goodRef << endl;
    goodRef = 200;
    cout << "Новое значение: " << goodFunction() << endl;

    // Демонстрация что адреса совпадают
    int& ref2 = goodFunction();
    cout << "Адрес goodRef: " << &goodRef << endl;
    cout << "Адрес ref2: " << &ref2 << endl;

    return 0;
}"

