#include <iostream>
#include <vector>
using namespace std;

class Base {
public:
    virtual int& getValueRef() = 0;
    virtual const int& getValueRef() const = 0;
    virtual ~Base() {}
};

class Derived : public Base {
    int value;
public:
    Derived(int v) : value(v) {}

    int& getValueRef() override {
        return value;
    }

    const int& getValueRef() const override {
        return value;
    }
};

int main() {
    Derived d1(10), d2(20);
    vector<Base*> objects = {&d1, &d2};

    cout << \Исходные значения:\n";
    for (size_t i = 0; i < objects.size(); ++i) {
        cout << "Объект " << i << ": " << objects[i]->getValueRef() << endl;
    }

    // Модификация через ссылки
    for (size_t i = 0; i < objects.size(); ++i) {
        int& ref = objects[i]->getValueRef();
        ref *= 2;
    }

    cout << "\nПосле удвоения:\n";
    for (size_t i = 0; i < objects.size(); ++i) {
        cout << "Объект " << i << ": " << objects[i]->getValueRef() << endl;
    }

    // Работа с константными ссылками
    const Base& constRef = d1;
    cout << "\nКонстантная ссылка: " << constRef.getValueRef() << endl;
    // constRef.getValueRef() = 100; // Ошибка компиляции

    return 0;
}"

#include <iostream>
#include <vector>

class Base {
public:
    virtual int& getValueRef() = 0;
    virtual const int& getValueRef() const = 0;
    virtual ~Base() {}
};

class Derived : public Base {
    int value;
public:
    Derived(int v) : value(v) {}

    int& getValueRef() override {
        return value;
    }

    const int& getValueRef() const override {
        return value;
    }
};

int main() {
    Derived d1(10), d2(20);
    std::vector<Base*> objects = {&d1, &d2};

    std::cout << \Исходные значения:\n";
    for (size_t i = 0; i < objects.size(); ++i) {
        std::cout << "Объект " << i << ": " << objects[i]->getValueRef() << std::endl;
    }

    // Модификация через ссылки
    for (size_t i = 0; i < objects.size(); ++i) {
        int& ref = objects[i]->getValueRef();
        ref *= 2;
    }

    std::cout << "\nПосле удвоения:\n";
    for (size_t i = 0; i < objects.size(); ++i) {
        std::cout << "Объект " << i << ": " << objects[i]->getValueRef() << std::endl;
    }

    // Работа с константными ссылками
    const Base& constRef = d1;
    std::cout << "\nКонстантная ссылка: " << constRef.getValueRef() << std::endl;
    // constRef.getValueRef() = 100; // Ошибка компиляции

    return 0;
}"

#include <iostream>
#include <string>
#include <utility>
using namespace std;

class Logger {
    string name;
public:
    Logger(const string& n) : name(n) {
        cout << \Создан Logger (lvalue): " << name << endl;
    }

    Logger(string&& n) : name(move(n)) {
        cout << "Создан Logger (rvalue): " << name << endl;
    }
};

// Шаблонная функция с perfect forwarding
template<typename T>
void createLogger(T&& arg) {
    // forward сохраняет категорию значения (lvalue/rvalue)
    Logger logger(forward<T>(arg));
}

int main() {
    string lvalueName = "Мой логгер";

    cout << "Создание из lvalue:\n";
    createLogger(lvalueName); // Вызовет конструктор с const string&
    cout << "lvalueName после: " << lvalueName << endl;

    cout << "\nСоздание из rvalue:\n";
    createLogger(string("Временный логгер")); // Вызовет конструктор с string&&

    cout << "\nСоздание с move:\n";
    createLogger(move(lvalueName)); // Вызовет конструктор с string&&
    cout << "lvalueName после move: " << lvalueName << endl; // В неопределенном состоянии

    // Perfect forwarding с несколькими аргументами
    cout << "\nPerfect forwarding с move:\n";
    string another = "Еще один";
    createLogger(move(another));

    return 0;
}"

#include <iostream>
#include <string>
#include <utility>

class Logger {
    std::string name;
public:
    Logger(const std::string& n) : name(n) {
        std::cout << \Создан Logger (lvalue): " << name << std::endl;
    }

    Logger(std::string&& n) : name(std::move(n)) {
        std::cout << "Создан Logger (rvalue): " << name << std::endl;
    }
};

// Шаблонная функция с perfect forwarding
template<typename T>
void createLogger(T&& arg) {
    // forward сохраняет категорию значения (lvalue/rvalue)
    Logger logger(std::forward<T>(arg));
}

int main() {
    std::string lvalueName = "Мой логгер";

    std::cout << "Создание из lvalue:\n";
    createLogger(lvalueName); // Вызовет конструктор с const string&
    std::cout << "lvalueName после: " << lvalueName << std::endl;

    std::cout << "\nСоздание из rvalue:\n";
    createLogger(std::string("Временный логгер")); // Вызовет конструктор с string&&

    std::cout << "\nСоздание с move:\n";
    createLogger(std::move(lvalueName)); // Вызовет конструктор с string&&
    std::cout << "lvalueName после move: " << lvalueName << std::endl; // В неопределенном состоянии

    // Perfect forwarding с несколькими аргументами
    std::cout << "\nPerfect forwarding с move:\n";
    std::string another = "Еще один";
    createLogger(std::move(another));

    return 0;
}"

