#include <iostream>
using namespace std;

int removeDuplicates(int arr[], int size) {
    if (size == 0) return 0;

    int uniqueIndex = 0;

    for (int i = 1; i < size; i++) {
        if (arr[i] != arr[uniqueIndex]) {
            uniqueIndex++;
            // Используем ссылки для обмена
            int& current = arr[uniqueIndex];
            int& next = arr[i];

            int temp = current;
            current = next;
            next = temp;
        }
    }

    return uniqueIndex + 1;
}

