code:
#include <iostream>
using namespace std;

class Base {
public:
    virtual void show() const {
        cout << \Base class" << endl;
    }
    virtual ~Base() {}
};

class Derived : public Base {
public:
    void show() const override {
        cout << "Derived class" << endl;
    }
};

void processByRef(Base& obj) {
    obj.show(); // Полиморфный вызов
}

void processByPtr(Base* obj) {
    if (obj) {
        obj->show(); // Полиморфный вызов
    }
}

int main() {
    Derived derived;
    Base base;

    // Работа со ссылками
    Base& baseRef1 = base;
    Base& baseRef2 = derived; // Ссылка на базовый класс может ссылаться на производный

    cout << "Использование ссылок:\n";
    processByRef(base);
    processByRef(derived); // Полиморфизм работает
    processByRef(baseRef1);
    processByRef(baseRef2); // Вызовется Derived::show()

    // Работа с указателями
    Base* basePtr1 = &base;
    Base* basePtr2 = &derived;

    cout << "\nИспользование указателей:\n";
    processByPtr(&base);
    processByPtr(&derived);
    processByPtr(basePtr1);
    processByPtr(basePtr2);

    // Различия:
    // 1. Ссылка не может быть nullptr
    // Base& badRef = nullptr; // Ошибка компиляции
    Base* nullPtr = nullptr; // Допустимо

    // 2. Указатель можно перенаправить
    basePtr1 = &derived; // Теперь указывает на derived
    // baseRef1 = derived; // Это присваивание значения

style:
 а не перенаправление ссылки

    // 3. Для ссылки не нужен оператор ->
    baseRef1.show();    // Используется .
    basePtr1->show();   // Используется ->

    return 0;
}"

