code:
#include <iostream>
#include <string>
#include <vector>
using namespace std;

class Resource {
    string name;
public:
    Resource(const string& n) : name(n) {
        cout << \Создан ресурс: " << name << endl;
    }

    Resource(const Resource& other) : name(other.name) {
        cout << "Ресурс скопирован: " << name << endl;
    }

    Resource(Resource&& other) noexcept : name(move(other.name)) {
        cout << "Ресурс перемещен: " << name << endl;
    }

    ~Resource() {
        if (!name.empty())
            cout << "Уничтожен ресурс: " << name << endl;
    }

    string getName() const { return name; }
};

// Функция принимает rvalue ссылку
void processResource(Resource&& r) {
    cout << "Обработка временного ресурса: " << r.getName() << endl;
    // r будет уничтожен после выхода из функции
}

// Перегрузка для lvalue
void processResource(Resource& r) {
    cout << "Обработка именованного ресурса: " << r.getName() << endl;
}

int main() {
    Resource r1("Постоянный");

    // Обработка lvalue
    processResource(r1);

    // Обработка rvalue (временный объект)
    processResource(Resource("Временный"));

    // Использование move для преобразования lvalue в rvalue
    cout << "\nИспользование move:\n";
    processResource(move(r1));
    // После move r1 в неопределенном состоянии

    // Пример с вектором
    vector<Resource> resources;
    resources.reserve(3);

    cout << "\nДобавление в вектор:\n";
    resources.push_back(Resource("Первый")); // Move конструктор

    Resource r2("Второй");
    resources.push_back(move(r2)); // Явный move

    return 0;
}"

