#include <iostream>
using namespace std;

int binarySearch(int arr[], int size, int target, bool& found) {
    int left = 0;
    int right = size - 1;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        int& midValue = arr[mid]; // Ссылка на средний элемент

        if (midValue == target) {
            found = true;
            return mid;
        }

        if (midValue < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    found = false;
    return -1;
}

