#include <iostream>
#include <string>
using namespace std;

// Основной шаблон
template<typename T>
void processReference(T& value) {
    cout << \Общая обработка: " << value << endl;
    value = value; // Не делает ничего полезного
}

// Специализация для int
template<>
void processReference<int>(int& value) {
    cout << "Специализация для int: " << value << endl;
    value *= 2;
}

// Специализация для string
template<>
void processReference<string>(string& value) {
    cout << "Специализация для string: " << value << endl;
    value += " (обработано)";
}

// Шаблон с константной ссылкой
template<typename T>
void printReference(const T& value) {
    cout << "Значение: " << value << endl;
}

