#include <iostream>
#include <type_traits>
using namespace std;

// Шаблонная функция для определения типа
template<typename T>
void checkType(T param) {
    if (is_reference<T>::value) {
        cout << \Параметр является ссылкой" << endl;
    } else {
        cout << "Параметр НЕ является ссылкой" << endl;
    }

    if (is_const<remove_reference_t<T>>::value) {
        cout << "Базовый тип константный" << endl;
    }
}

// Шаблонная функция с универсальной ссылкой
template<typename T>
void universalRef(T&& param) {
    cout << "\nУниверсальная ссылка:" << endl;
    checkType(param);
}

int main() {
    int x = 5;
    const int y = 10;
    int& ref = x;
    const int& constRef = y;

    cout << "Проверка типов:\n";

    cout << "\n1. Передача int:";
    checkType(x); // T = int

    cout << "\n2. Передача const int:";
    checkType(y); // T = const int

    cout << "\n3. Передача int&:";
    checkType(ref); // T = int& (ссылка)

    cout << "\n4. Передача const int&:";
    checkType(constRef); // T = const int&

    cout << "\n5. Передача выражения:";
    checkType(x + 1); // T = int (не ссылка)

    // Универсальные ссылки
    cout << "\n\nУниверсальные ссылки:\n";
    universalRef(x);        // T = int& (lvalue)
    universalRef(42);       // T = int&& (rvalue)
    universalRef(ref);      // T = int& (lvalue)
    universalRef(constRef); // T = const int& (lvalue)
    universalRef(move(x));  // T = int&& (rvalue)

    // Проверка с помощью decltype
    cout << "\n\nИспользование decltype:\n";
    decltype(x) var1 = x;           // int
    decltype((x)) var2 = x;         // int& (скобки создают lvalue выражение)
    decltype(ref) var3 = x;         // int&
    decltype(constRef) var4 = y;    // const int&

    cout << "decltype(x): " << typeid(var1).name() << endl;
    cout << "decltype((x)): " << typeid(var2).name() << endl;
    cout << "decltype(ref): " << typeid(var3).name() << endl;

    return 0;
}"

#include <iostream>
#include <type_traits>

// Шаблонная функция для определения типа
template<typename T>
void checkType(T param) {
    if (std::is_reference<T>::value) {
        std::cout << \Параметр является ссылкой" << std::endl;
    } else {
        std::cout << "Параметр НЕ является ссылкой" << std::endl;
    }

    if (std::is_const<typename std::remove_reference<T>::type>::value) {
        std::cout << "Базовый тип константный" << std::endl;
    }
}

// Шаблонная функция с универсальной ссылкой
template<typename T>
void universalRef(T&& param) {
    std::cout << "\nУниверсальная ссылка:" << std::endl;
    checkType(param);
}

int main() {
    int x = 5;
    const int y = 10;
    int& ref = x;
    const int& constRef = y;

    std::cout << "Проверка типов:\n";

    std::cout << "\n1. Передача int:";
    checkType(x); // T = int

    std::cout << "\n2. Передача const int:";
    checkType(y); // T = const int

    std::cout << "\n3. Передача int&:";
    checkType(ref); // T = int& (ссылка)

    std::cout << "\n4. Передача const int&:";
    checkType(constRef); // T = const int&

    std::cout << "\n5. Передача выражения:";
    checkType(x + 1); // T = int (не ссылка)

    // Универсальные ссылки
    std::cout << "\n\nУниверсальные ссылки:\n";
    universalRef(x);        // T = int& (lvalue)
    universalRef(42);       // T = int&& (rvalue)
    universalRef(ref);      // T = int& (lvalue)
    universalRef(constRef); // T = const int& (lvalue)
    universalRef(std::move(x));  // T = int&& (rvalue)

    // Проверка с помощью decltype
    std::cout << "\n\nИспользование decltype:\n";
    decltype(x) var1 = x;           // int
    decltype((x)) var2 = x;         // int& (скобки создают lvalue выражение)
    decltype(ref) var3 = x;         // int&
    decltype(constRef) var4 = y;    // const int&

    std::cout << "decltype(x): " << typeid(var1).name() << std::endl;
    std::cout << "decltype((x)): " << typeid(var2).name() << std::endl;
    std::cout << "decltype(ref): " << typeid(var3).name() << std::endl;

    return 0;
}"

#include <iostream>
using namespace std;

void findIntersection(int arr1[], int size1, int arr2[], int size2, int result[], int& resultSize) {
    int i = 0, j = 0;
    resultSize = 0;

    while (i < size1 && j < size2) {
        int& val1 = arr1[i]; // Ссылка на элемент первого массива
        int& val2 = arr2[j]; // Ссылка на элемент второго массива

        if (val1 == val2) {
            // Добавляем в результат
            result[resultSize] = val1;
            resultSize++;
            i++;
            j++;
        } else if (val1 < val2) {
            i++;
        } else {
            j++;
        }
    }
}

