#include <iostream>
using namespace std;

int main() {
    int arr[5] = {1, 2, 3, 4, 5};

    // Ссылка на массив
    int (&arrRef)[5] = arr;

    // Указатель на первый элемент массива
    int* ptr = arr; // Эквивалентно int* ptr = &arr[0];

    // Указатель на массив из 5 элементов
    int (*arrPtr)[5] = &arr;

    cout << \Исходный массив: ";
    for (int i = 0; i < 5; ++i) cout << arr[i] << " ";
    cout << endl;

    // Доступ через ссылку на массив
    cout << "\nДоступ через ссылку на массив:\n";
    cout << "arrRef[2] = " << arrRef[2] << endl;
    cout << "sizeof(arrRef) = " << sizeof(arrRef) << endl; // Размер всего массива
    cout << "&arrRef = " << &arrRef << endl;
    cout << "&arrRef[0] = " << &arrRef[0] << endl;

    // Доступ через указатель на первый элемент
    cout << "\nДоступ через указатель на первый элемент:\n";
    cout << "ptr[2] = " << ptr[2] << endl;
    cout << "sizeof(ptr) = " << sizeof(ptr) << endl; // Размер указателя
    cout << "ptr = " << ptr << endl;
    cout << "&ptr = " << &ptr << endl;

    // Доступ через указатель на массив
    cout << "\nДоступ через указатель на массив:\n";
    cout << "(*arrPtr)[2] = " << (*arrPtr)[2] << endl;
    cout << "sizeof(*arrPtr) = " << sizeof(*arrPtr) << endl; // Размер массива
    cout << "arrPtr = " << arrPtr << endl;
    cout << "*arrPtr = " << *arrPtr << endl; // Адрес первого элемента

    // Арифметика указателей
    cout << "\nАрифметика указателей:\n";
    cout << "ptr + 1 = " << ptr + 1 << endl; // Следующий int
    cout << "arrPtr + 1 = " << arrPtr + 1 << endl; // Следующий массив из 5 int

    // Передача в функции
    cout << "\nРазмер в функциях:\n";
    // Функция принимает ссылку на массив
    auto func1 = [](int (&array)[5]) {
        cout << "В func1: sizeof(array) = " << sizeof(array) << endl;
    };

    // Функция принимает указатель
    auto func2 = [](int* array) {
        cout << "В func2: sizeof(array) = " << sizeof(array) << endl;
    };

    func1(arr);
    func2(arr);

    // Изменение через разные способы доступа
    arrRef[0] = 100;
    ptr[1] = 200;
    (*arrPtr)[2] = 300;

    cout << "\nПосле изменений: ";
    for (int i = 0; i < 5; ++i) cout << arr[i] << " ";
    cout << endl;

    return 0;
}"

