    std::cout << "ptr = " << ptr << std::endl;
    std::cout << "&ptr = " << &ptr << std::endl;

    // Доступ через указатель на массив
    std::cout << "\nДоступ через указатель на массив:\n";
    std::cout << "(*arrPtr)[2] = " << (*arrPtr)[2] << std::endl;
    std::cout << "sizeof(*arrPtr) = " << sizeof(*arrPtr) << std::endl; // Размер массива
    std::cout << "arrPtr = " << arrPtr << std::endl;
    std::cout << "*arrPtr = " << *arrPtr << std::endl; // Адрес первого элемента

    // Арифметика указателей
    std::cout << "\nАрифметика указателей:\n";
    std::cout << "ptr + 1 = " << ptr + 1 << std::endl; // Следующий int
    std::cout << "arrPtr + 1 = " << arrPtr + 1 << std::endl; // Следующий массив из 5 int

    // Передача в функции
    std::cout << "\nРазмер в функциях:\n";
    // Функция принимает ссылку на массив
    auto func1 = [](int (&array)[5]) {
        std::cout << "В func1: sizeof(array) = " << sizeof(array) << std::endl;
    };

    // Функция принимает указатель
    auto func2 = [](int* array) {
        std::cout << "В func2: sizeof(array) = " << sizeof(array) << std::endl;
    };

    func1(arr);
    func2(arr);

    // Изменение через разные способы доступа
    arrRef[0] = 100;
    ptr[1] = 200;
    (*arrPtr)[2] = 300;

    std::cout << "\nПосле изменений: ";
    for (int i = 0; i < 5; ++i) std::cout << arr[i] << " ";
    std::cout << std::endl;

    return 0;
