#include <iostream>
#include <typeinfo>
using namespace std;

class Base {
public:
    virtual ~Base() {}
    virtual void print() const { cout << \Base" << endl; }
};

class Derived : public Base {
public:
    void print() const override { cout << "Derived" << endl; }
    void specific() const { cout << "Derived specific method" << endl; }
};

class AnotherDerived : public Base {
public:
    void print() const override { cout << "AnotherDerived" << endl; }
};

int main() {
    Derived derived;
    Base& baseRef = derived; // Ссылка на базовый класс

    // Использование typeid со ссылкой
    cout << "typeid(baseRef): " << typeid(baseRef).name() << endl;
    cout << "typeid(derived): " << typeid(derived).name() << endl;

    // Проверка равенства type_info
    if (typeid(baseRef) == typeid(derived)) {
        cout << "typeid совпадает" << endl;
    }

    // dynamic_cast со ссылкой
    try {
        Derived& derivedRef = dynamic_cast<Derived&>(baseRef);
        cout << "dynamic_cast успешен" << endl;
        derivedRef.specific(); // Можно вызывать специфичные методы
    } catch (const bad_cast& e) {
        cout << "bad_cast: " << e.what() << endl;
    }

    // Неуспешный dynamic_cast
    AnotherDerived another;
    Base& anotherRef = another;

    try {
        Derived& failedRef = dynamic_cast<Derived&>(anotherRef);
        cout << "Этот код не выполнится" << endl;
    } catch (const bad_cast& e) {
        cout << "Ожидаемый bad_cast: " << e.what() << endl;
    }

    // Использование с полиморфизмом
    Base* polyArray[] = { &derived

style:
&another };

   for (int i = 0; i < 2; ++i) {
       Base& ref = *polyArray[i];
       ref.print();

       // Попытка downcast через dynamic_cast
       if (Derived* dptr = dynamic_cast<Derived*>(&ref)) {
           cout << "Это Derived

topic:
 вызываем specific" << endl;
            dptr->specific();
        } else {
            cout << "Это не Derived" << endl;
        }
    }

    // typeid с разыменованным указателем
    Base* ptr = &derived;
    cout << "\ntypeid(*ptr): " << typeid(*ptr).name() << endl;
    cout << "typeid(ptr): " << typeid(ptr).name() << endl; // typeid указателя

    // Проверка на нулевой указатель перед dynamic_cast ссылки
    Base* nullPtr = nullptr;
    // Derived& badRef = dynamic_cast<Derived&>(*nullPtr); // Неопределенное поведение!

    return 0;
}"

