#include <iostream>
#include <thread>
#include <vector>
#include <mutex>
#include <chrono>
using namespace std;

class ThreadSafeCounter {
private:
    int value = 0;
    mutex mtx;

public:
    // Метод для инкремента, возвращает ссылку на объект для цепочек
    ThreadSafeCounter& increment() {
        lock_guard<mutex> lock(mtx);
        ++value;
        return *this;
    }

    // Метод для получения значения (константная ссылка на объект)
    const ThreadSafeCounter& print() const {
        cout << \Текущее значение: " << value << endl;
        return *this;
    }

    // Метод для получения значения
    int getValue() const {
        lock_guard<mutex> lock(mtx);
        return value;
    }

    // Метод принимает ссылку на результат
    void getValueRef(int& result) {
        lock_guard<mutex> lock(mtx);
        result = value;
    }
};

// Функция для потока

