    cout << "\nФинальное значение счетчика: " << finalValue << endl;
    cout << "Ожидаемое значение: " << numThreads * iterations + iterations << endl;

    // Пример с reference_wrapper
    cout << "\nИспользование reference_wrapper:\n";
    ThreadSafeCounter counter2;
    reference_wrapper<ThreadSafeCounter> counterRef = counter2;

    // Работа через reference_wrapper
    counterRef.get().increment();
    cout << "counter2 значение: " << counter2.getValue() << endl;

    // Вектор reference_wrapper
    vector<reference_wrapper<ThreadSafeCounter>> counters;
    counters.push_back(counter);
    counters.push_back(counter2);

    for (auto& c : counters) {
