#include <iostream>
#include <optional>
#include <string>
using namespace std;

class User {
    string name;
    int age;
public:
    User(const string& n, int a) : name(n), age(a) {}
    string getName() const { return name; }
    int getAge() const { return age; }
};

int main() {
    optional<int> optInt = 42;

    // Получение ссылки на значение optional
    if (optInt) {
        int& ref = *optInt; // operator* возвращает ссылку
        ref = 100;
        cout << \optInt после модификации: " << *optInt << endl;
    }

    // Метод value() тоже возвращает ссылку
    optional<string> optStr = "Hello";
    string& strRef = optStr.value();
    strRef += " World!";
    cout << "optStr: " << optStr.value() << endl;

    // Константная ссылка
    const optional<string>& constOptRef = optStr;
    const string& constStrRef = constOptRef.value();
    cout << "constStrRef: " << constStrRef << endl;

    // Опасность: разыменование пустого optional
    optional<double> emptyOpt;
    try {
        double& badRef = emptyOpt.value(); // бросит bad_optional_access
    } catch (const bad_optional_access& e) {
        cout << "Ошибка: " << e.what() << endl;
    }

    // Безопасное получение ссылки
    if (emptyOpt.has_value()) {
        double& safeRef = *emptyOpt;
    } else {
        cout << "Optional пуст" << endl;
    }

    // Optional пользовательского типа
    optional<User> optUser = User("Alice"

