    // но можно если переприсвоить весь optional

    // Optional ссылок (optional<reference_wrapper>)
    int value = 777;
    optional<reference_wrapper<int>> optRef = ref(value);

    if (optRef) {
        int& refFromOpt = optRef->get();
        refFromOpt = 888;
        cout << "value после модификации через optional<ref>: " << value << endl;
    }

    // Ссылка на optional в параметре функции
    auto processOptional = [](optional<int>& opt) -> int& {
        if (!opt) {
            opt = 0; // Инициализируем если пуст
        }
        return *opt; // Возвращаем ссылку на значение
    };

    optional<int> optParam;
    int& resultRef = processOptional(optParam);
    resultRef = 999;
    cout << "optParam после processOptional: " << *optParam << endl;

    // Optional как член класса с возвратом ссылки
    class Config {
        optional<string> setting;
    public:
        string& getOrCreate(const string& defaultValue) {
            if (!setting) {
                setting = defaultValue;
            }
            return *setting; // Возвращаем ссылку
        }

        const optional<string>& getSetting() const { return setting; }
    };

    Config config;
    string& configRef = config.getOrCreate("default");
    configRef = "custom";

    if (config.getSetting()) {
        cout << "Конфигурация: " << config.getSetting().value() << endl;
    }

    return 0;
}"

