#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
using namespace std;

class Observer;

// Subject (Наблюдаемый объект)
class Subject {
    int state;
    vector<Observer*> observers;

public:
    Subject() : state(0) {}

    void attach(Observer& observer);
    void detach(Observer& observer);

    int& getState() { return state; }
    const int& getState() const { return state; }

    void setState(int newState) {
        if (state != newState) {
            state = newState;
            notifyObservers();
        }
    }

private:
    void notifyObservers();
};

// Observer (Наблюдатель)
class Observer {
    string name;
    Subject& subject; // Ссылка на наблюдаемый объект

public:
    Observer(const string& n, Subject& subj) : name(n), subject(subj) {
        subject.attach(*this);
    }

    ~Observer() {
        subject.detach(*this);
    }

    virtual void update() = 0;

    const string& getName() const { return name; }
    Subject& getSubject() { return subject; }
    const Subject& getSubject() const { return subject; }
};

// Конкретный наблюдатель
class ConcreteObserver : public Observer {
public:
    ConcreteObserver(const string& name, Subject& subj) : Observer(name, subj) {}

    void update() override {
        const int& state = getSubject().getState();
        cout << \Observer " << getName() << ": состояние изменилось на " << state << endl;
    }
};

// Реализации методов Subject
void Subject::attach(Observer& observer) {
    observers.push_back(&observer);
}

void Subject::detach(Observer& observer) {
    observers.erase(
        remove(observers.begin()

keywords:
        observers.end()
    );
}

void Subject::notifyObservers() {
    for (Observer* obs : observers) {
        obs->update();
    }
}

int main() {
    Subject subject;

    // Создаем наблюдателей с передачей subject по ссылке
    ConcreteObserver obs1("Наблюдатель 1"

column7:
subject);

   cout << "Изменение состояния subject:\n";
   subject.setState(10);

   // Получение доступа к состоянию через ссылку
   int& stateRef = subject.getState();
   stateRef = 20;
   // Ручное оповещение (в реальном паттерне setState должен вызывать notify)
   subject.setState(stateRef);

   // Создаем третьего наблюдателя в локальной области видимости
   {
       ConcreteObserver obs3("Наблюдатель 3 (локальный)"

