using namespace std;

// Класс с разными методами, возвращающими ссылки
class DataHolder {
    int intValue;
    string strValue;
    double dblValue;

public:
    DataHolder() : intValue(0), strValue(\default")

style:
 dblValue(0.0) {}

    int& getIntRef() { return intValue; }
    string& getStringRef() { return strValue; }
    double& getDoubleRef() { return dblValue; }

    const int& getIntRef() const { return intValue; }
    const string& getStringRef() const { return strValue; }
    const double& getDoubleRef() const { return dblValue; }
};

// Функция

keywords:
 int& value) {
    processor(value);
}

// Type erasure с std::any
class AnyReference {
    any storedRef;

public:
    template<typename T>
    AnyReference(T& ref) : storedRef(ref(ref)) {}

    template<typename T>
    T& get() {
        return any_cast<reference_wrapper<T>>(storedRef).get();
    }

    template<typename T>
    void set(const T& value) {
        get<T>() = value;
    }
};

int main() {
    DataHolder holder;

    cout << "Исходные значения:\n";
    cout << "int: " << holder.getIntRef() << endl;
    cout << "string: " << holder.getStringRef() << endl;
    cout << "double: " << holder.getDoubleRef() << endl;

    // Использование std::function с лямбдами
    vector<function<void()>> operations;

    operations.push_back([&holder]() {
        holder.getIntRef() = 100;
    });

    operations.push_back([&holder]() {
