    std::string& getStringRef() { return strValue; }
    double& getDoubleRef() { return dblValue; }

    const int& getIntRef() const { return intValue; }
    const std::string& getStringRef() const { return strValue; }
    const double& getDoubleRef() const { return dblValue; }
};

// Функция

keywords:
 int& value) {
    processor(value);
}

// Type erasure с std::any
class AnyReference {
    std::any storedRef;

public:
    template<typename T>
    AnyReference(T& ref) : storedRef(std::ref(ref)) {}

    template<typename T>
    T& get() {
        return std::any_cast<std::reference_wrapper<T>>(storedRef).get();
    }

    template<typename T>
    void set(const T& value) {
        get<T>() = value;
    }
};

int main() {
    DataHolder holder;

    std::cout << "Исходные значения:\n";
    std::cout << "int: " << holder.getIntRef() << std::endl;
    std::cout << "string: " << holder.getStringRef() << std::endl;
    std::cout << "double: " << holder.getDoubleRef() << std::endl;

    // Использование std::function с лямбдами
    std::vector<std::function<void()>> operations;

    operations.push_back([&holder]() {
        holder.getIntRef() = 100;
    });

    operations.push_back([&holder]() {
        holder.getStringRef() = "modified";
    });

    operations.push_back([&holder]() {
        holder.getDoubleRef() = 3.14159;
    });

    // Выполнение операций
    for (auto& op : operations) {
        op();
    }

    std::cout << "\nПосле операций через std::function:\n";
    std::cout << "int: " << holder.getIntRef() << std::endl;
    std::cout << "string: " << holder.getStringRef() << std::endl;
    std::cout << "double: " << holder.getDoubleRef() << std::endl;

    // Использование processReference
    int testValue = 5;
    std::cout << "\nДо processReference: testValue = " << testValue << std::endl;

    processReference([](int& val) { val *= 2; }

