#include <iostream>
#include <unordered_map>
#include <string>
#include <cmath>
using namespace std;

class ComputationCache {
    unordered_map<string, double> cache;

public:
    // Возвращает ссылку на кэшированное значение
    double& computeOrGet(const string& key, double value) {
        auto it = cache.find(key);
        if (it == cache.end()) {
            // Вычисление и кэширование
            double result = expensiveComputation(value);
            cache[key] = result;
            return cache[key];
        }
        return it->second;
    }

    // Возвращает константную ссылку для чтения
    const double& getCachedValue(const string& key) const {
        static const double defaultValue = 0.0;
        auto it = cache.find(key);
        if (it != cache.end()) {
            return it->second;
        }
        return defaultValue;
    }

    // Очистка кэша
    void clear() {
        cache.clear();
    }

    // Модификация кэшированного значения по ссылке
    bool updateCachedValue(const string& key, double newValue) {
        auto it = cache.find(key);
        if (it != cache.end()) {
            it->second = newValue;
            return true;
        }
        return false;
    }

private:
    double expensiveComputation(double x) {
        // Имитация дорогостоящих вычислений
        return sin(x) * cos(x) + sqrt(abs(x));
    }
};

