    FuncPtr* funcArray = new FuncPtr[2];
    funcArray[0] = &hello;
    funcArray[1] = &world;
    for(int i = 0; i < 2; i++) {
        (*funcArray[i])();
    }
    cout << endl;
    delete[] funcArray;
    return 0;
}"

