#include <iostream>
using namespace std;

int main() {
    int size = 7;
    int* arr = new int[size] {10, 20, 30, 40, 50, 60, 70};
    double median;
    if(size % 2 == 0) {
        median = (arr[size/2 - 1] + arr[size/2]) / 2.0;
    } else {
        median = arr[size/2];
    }
    cout << \Медиана: " << median << endl;
    delete[] arr;
    return 0;
}"

