#include <iostream>
using namespace std;

int main() {
    size_t count = 7;
    double* data = new double[count];
    for(size_t i = 0; i < count; i++) {
        data[i] = 1.0 / (i + 1);
    }
    cout << \Результаты:" << endl;
    for(size_t i = 0; i < count; i++) {
        cout << "1/" << i+1 << " = " << data[i] << endl;
    }
    delete[] data;
    return 0;
}"

