#include <iostream>
using namespace std;

int main() {
    int N;
    cout << \Введите N: ";
    cin >> N;
    long long* factorials = new long long[N];
    factorials[0] = 1;
    for(int i = 1; i < N; i++) {
        factorials[i] = factorials[i-1] * (i+1);
    }
    cout << "Факториалы: ";
    for(int i = 0; i < N; i++) {
        cout << factorials[i] << " ";
    }
    cout << endl;
    delete[] factorials;
    return 0;
}"

