#include <iostream>
using namespace std;

int main() {
    int size = 5;
    int* arr = new int[size] {1, 2, 3, 2, 1};
    bool isPalindrome = true;
    for(int i = 0; i < size / 2; i++) {
        if(arr[i] != arr[size - 1 - i]) {
            isPalindrome = false;
            break;
        }
    }
    cout << \Массив ";
    if(!isPalindrome) cout << "не ";
    cout << "является палиндромом." << endl;
    delete[] arr;
    return 0;
}"

