#include <iostream>
using namespace std;

int main() {
    int size = 6;
    int* arr = new int[size] {3, 1, 4, 1, 5, 9};
    int* prefix = new int[size];
    prefix[0] = arr[0];
    for(int i = 1; i < size; i++) {
        prefix[i] = prefix[i-1] + arr[i];
    }
    cout << \Префиксные суммы: ";
    for(int i = 0; i < size; i++) {
        cout << prefix[i] << " ";
    }
    cout << endl;
    delete[] arr;
    delete[] prefix;
    return 0;
}"

