using namespace std;

int main() {
    int n;
    cout << \Введите количество чисел Фибоначчи: ";
    cin >> n;
    long long* fib = new long long[n];
    if(n >= 1) fib[0] = 0;
    if(n >= 2) fib[1] = 1;
    for(int i = 2; i < n; i++) {
        fib[i] = fib[i-1] + fib[i-2];
    }
    cout << "Числа Фибоначчи: ";
    for(int i = 0; i < n; i++) {
        cout << fib[i] << " ";
    }
    cout << endl;
    delete[] fib;
    return 0;
}"

