#include <iostream>
#include <algorithm>
using namespace std;

int main() {
    int size = 8;
    int* arr = new int[size] {12, 3, 5, 7, 19, 2, 16, 4};
    int k = 3;
    partial_sort(arr, arr + k, arr + size);
    cout << k << \-й наименьший элемент: " << arr[k-1] << endl;
    cout << "Массив после частичной сортировки: ";
    for(int i = 0; i < size; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
    delete[] arr;
    return 0;
}"

