#include <iostream>
using namespace std;

int main() {
    int size = 10;
    int* data = new int[size] {1, 2, 2, 3, 1, 2, 4, 1, 2, 3};
    int maxVal = 4;
    int* freq = new int[maxVal + 1] {};
    for(int i = 0; i < size; i++) {
