    }
    cout << \Гистограмма частот:" << endl;
    for(int i = 1; i <= maxVal; i++) {
        cout << "Значение " << i << ": " << freq[i] << " раз" << endl;
    }
    delete[] data;
    delete[] freq;
    return 0;
}"

