#include <iostream>
using namespace std;

int main() {
    int size = 7;
    int* arr = new int[size + 1];
    for(int i = 0; i < size; i++) arr[i] = (i+1) * 10;
    int key = 40;
    arr[size] = key;
    int i = 0;
    while(arr[i] != key) {
        i++;
    }
    if(i < size) {
        cout << \Элемент " << key << " найден на позиции " << i << endl;
    } else {
        cout << "Элемент " << key << " не найден" << endl;
    }
    delete[] arr;
    return 0;
}"

