#include <iostream>
using namespace std;

int main() {
    int* arr = new int[5] {12, 45, 23, 67, 34};
    int first = arr[0], second = arr[0];
    for(int i = 0; i < 5; i++) {
        if(arr[i] > first) {
            second = first;
            first = arr[i];
        } else if(arr[i] > second && arr[i] != first) {
            second = arr[i];
        }
    }
    cout << \Второй по величине элемент: " << second << endl;
    delete[] arr;
    return 0;
}"

