#include <iostream>
#include <cmath>
using namespace std;

int main() {
    int* arr = new int[6] {3, -5, 7, -2, 0, -9};
    cout << \Исходный массив: ";
    for(int i = 0; i < 6; i++) cout << arr[i] << " ";
    cout << endl;
    for(int i = 0; i < 6; i++) {
        if(arr[i] < 0) arr[i] = abs(arr[i]);
    }
    cout << "Массив после замены: ";
    for(int i = 0; i < 6; i++) cout << arr[i] << " ";
    cout << endl;
    delete[] arr;
    return 0;
}"

