#include <iostream>
using namespace std;

int main() {
    int size = 5;
    int* arr = new int[size] {1, 2, 3, 4, 5};
    cout << \Исходный массив: ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    for(int i = 0; i < size / 2; i++) {
        int temp = arr[i];
        arr[i] = arr[size - 1 - i];
        arr[size - 1 - i] = temp;
    }
    cout << "Инвертированный массив: ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    delete[] arr;
    return 0;
}"

