#include <iostream>
#include <cmath>
using namespace std;

int main() {
    int size = 5;
    double* data = new double[size] {5.0, 7.0, 9.0, 11.0, 13.0};
    double sum = 0.0, mean, variance = 0.0;
    for(int i = 0; i < size; i++) sum += data[i];
    mean = sum / size;
    for(int i = 0; i < size; i++) variance += pow(data[i] - mean, 2);
    variance /= size;
    double stddev = sqrt(variance);
    cout << \Среднее: " << mean << "

style:
 стандартное отклонение: " << stddev << endl;
    delete[] data;
    return 0;
}"

