#include <iostream>
using namespace std;

int main() {
    int size = 6;
    int* arr = new int[size] {2, 3, 4, 7, 8, 10};
    int N = 10;
    bool* present = new bool[N+1] {};
    for(int i = 0; i < size; i++) {
        if(arr[i] >= 1 && arr[i] <= N) {
            present[arr[i]] = true;
        }
    }
    cout << \Пропущенные числа от 1 до " << N << ": ";
    for(int i = 1; i <= N; i++) {
        if(!present[i]) cout << i << " ";
    }
    cout << endl;
    delete[] arr;
    delete[] present;
    return 0;
}"

