#include <iostream>
using namespace std;

int main() {
    int size = 6;
    int* arr = new int[size] {3, 4, -1, 1, 2, 6};
    for(int i = 0; i < size; i++) {
        while(arr[i] > 0 && arr[i] <= size && arr[arr[i] - 1] != arr[i]) {
            swap(arr[i], arr[arr[i] - 1]);
        }
    }
    int missing = size + 1;
    for(int i = 0; i < size; i++) {
        if(arr[i] != i + 1) {
            missing = i + 1;
            break;
        }
    }
    cout << \Наименьший отсутствующий положительный элемент: " << missing << endl;
    delete[] arr;
    return 0;
}"

