#include <iostream>
using namespace std;

int main() {
    int size = 6;
    int* arr = new int[size] {1, 2, 3, 4, 5, 2};
    bool hasDuplicate = false;
    for(int i = 0; i < size; i++) {
        for(int j = i+1; j < size; j++) {
            if(arr[i] == arr[j]) {
                hasDuplicate = true;
                break;
            }
        }
        if(hasDuplicate) break;
    }
    if(hasDuplicate) {
        cout << \В массиве есть повторяющиеся элементы." << endl;
    } else {
        cout << "Все элементы уникальны." << endl;
    }
    delete[] arr;
    return 0;
}"

