#include <iostream>
using namespace std;

int main() {
    int size = 10;
    int* arr = new int[size] {1, 3, 2, 3, 4, 2, 3, 1, 3, 5};
    int maxCount = 0, frequentElement = arr[0];
    for(int i = 0; i < size; i++) {
        int count = 0;
        for(int j = 0; j < size; j++) {
            if(arr[j] == arr[i]) count++;
        }
        if(count > maxCount) {
            maxCount = count;
            frequentElement = arr[i];
        }
    }
    cout << \Наиболее частый элемент: " << frequentElement << " (встречается " << maxCount << " раз)" << endl;
    delete[] arr;
    return 0;
}"

