#include <iostream>
using namespace std;

int main() {
    int size = 5;
    int* arr = new int[size] {1, 2, 3, 4, 5};
    int k = 2;
    cout << \Исходный массив: ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    int* temp = new int[size];
    for(int i = 0; i < size; i++) {
        temp[(i + k) % size] = arr[i];
    }
    for(int i = 0; i < size; i++) arr[i] = temp[i];
    cout << "После сдвига вправо на " << k << ": ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    delete[] arr;
    delete[] temp;
    return 0;
}"

