#include <iostream>
using namespace std;

int main() {
    int size = 8;
    int* arr = new int[size] {1, 2, 3, 4, 5, 6, 7, 8};
    int left = 2, right = 5;
    cout << \Исходный массив: ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    while(left < right) {
        int temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;
        left++;
        right--;
    }
    cout << "После инверсии между индексами 2 и 5: ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    delete[] arr;
    return 0;
}"

