#include <iostream>
#include <climits>
using namespace std;

int main() {
    int size = 6;
    int* arr = new int[size] {12, 35, 1, 10, 35, 1};
    int first = INT_MIN, second = INT_MIN;
    for(int i = 0; i < size; i++) {
        if(arr[i] > first) {
            second = first;
            first = arr[i];
        } else if(arr[i] > second && arr[i] != first) {
            second = arr[i];
        }
    }
    if(second == INT_MIN) {
        cout << \Второго наибольшего элемента нет" << endl;
    } else {
        cout << "Второй наибольший элемент: " << second << endl;
    }
    delete[] arr;
    return 0;
}"

