#include <iostream>
using namespace std;

long long* computeCatalan(int n) {
    long long* catalan = new long long[n+1];
    catalan[0] = 1;
    for(int i = 1; i <= n; i++) {
        catalan[i] = 0;
        for(int j = 0; j < i; j++) {
            catalan[i] += catalan[j] * catalan[i-1-j];
        }
    }
    return catalan;
}

int main() {
    int n = 10;
    long long* catalan = computeCatalan(n);
    cout << \Первые " << n << " чисел Каталана:" << endl;
    for(int i = 0; i <= n; i++) {
        cout << "C[" << i << "] = " << catalan[i] << endl;
    }
    delete[] catalan;
    return 0;
}"

