#include <iostream>
using namespace std;

int main() {
    int size = 10;
    int* arr = new int[size] {1, 2, 2, 3, 4, 4, 4, 5, 1, 6};
    int uniqueCount = 0;
    for(int i = 0; i < size; i++) {
        bool isDuplicate = false;
        for(int j = 0; j < uniqueCount; j++) {
            if(arr[i] == arr[j]) {
                isDuplicate = true;
                break;
            }
        }
        if(!isDuplicate) {
            arr[uniqueCount++] = arr[i];
        }
    }
    cout << \Массив без дубликатов: ";
    for(int i = 0; i < uniqueCount; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
    delete[] arr;
    return 0;
}"

