#include <iostream>
using namespace std;

int main() {
    int size = 7;
    int* arr = new int[size] {64, 25, 12, 22, 11, 90, 8};
    cout << \До сортировки выбором: ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    for(int i = 0; i < size-1; i++) {
        int minIndex = i;
        for(int j = i+1; j < size; j++) {
            if(arr[j] < arr[minIndex]) minIndex = j;
        }
        int temp = arr[i];
        arr[i] = arr[minIndex];
        arr[minIndex] = temp;
    }
    cout << "После сортировки выбором: ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    delete[] arr;
    return 0;
}"

