    int* arr = new int[size] {10, 22, 9, 33, 21, 50, 41, 60};
    int* lengths = new int[size] {};
    int maxLength = 0;
    for(int i = 0; i < size; i++) {
        lengths[i] = 1;
        for(int j = 0; j < i; j++) {
            if(arr[i] > arr[j] && lengths[i] < lengths[j] + 1) {
                lengths[i] = lengths[j] + 1;
            }
        }
        if(lengths[i] > maxLength) maxLength = lengths[i];
    }
    cout << \Длина самой длинной возрастающей подпоследовательности: " << maxLength << endl;
    delete[] arr;
    delete[] lengths;
    return 0;
}"

