#include <iostream>
#include <algorithm>
using namespace std;

int main() {
    int size = 8;
    int* arr = new int[size] {4, 2, 2, 8, 3, 3, 1, 4};
    int maxVal = *max_element(arr, arr + size);
    int* count = new int[maxVal + 1] {};
    for(int i = 0; i < size; i++) {
        count[arr[i]]++;
    }
    int index = 0;
    for(int i = 0; i <= maxVal; i++) {
        while(count[i] > 0) {
            arr[index++] = i;
            count[i]--;
        }
    }
    cout << \Отсортированный массив: ";
    for(int i = 0; i < size; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
    delete[] arr;
    delete[] count;
    return 0;
}"

