#include <iostream>
#include <cmath>
using namespace std;

int main() {
    int limit;
    cout << \Введите верхнюю границу: ";
    cin >> limit;
    bool* isPrime = new bool[limit + 1];
    for(int i = 0; i <= limit; i++) isPrime[i] = true;
    isPrime[0] = isPrime[1] = false;
    for(int p = 2; p <= sqrt(limit); p++) {
        if(isPrime[p]) {
            for(int i = p * p; i <= limit; i += p) {
                isPrime[i] = false;
            }
        }
    }
    cout << "Простые числа до " << limit << ": ";
    for(int i = 2; i <= limit; i++) {
        if(isPrime[i]) cout << i << " ";
    }
    cout << endl;
    delete[] isPrime;
    return 0;
}"

