#include <iostream>
using namespace std;

int main() {
    int size = 10;
    int* arr = new int[size] {9, 8, 7, 6, 5, 4, 3, 2, 1, 0};
    cout << \Исходный массив: ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    for(int gap = size/2; gap > 0; gap /= 2) {
        for(int i = gap; i < size; i++) {
            int temp = arr[i];
            int j;
            for(j = i; j >= gap && arr[j - gap] > temp; j -= gap) {
                arr[j] = arr[j - gap];
            }
            arr[j] = temp;
        }
    }
    cout << "Отсортированный массив (Шелл): ";
    for(int i = 0; i < size; i++) cout << arr[i] << " ";
    cout << endl;
    delete[] arr;
    return 0;
}"

