#include <iostream>
#include <cmath>
using namespace std;

int main() {
    double target = 25.0;
    double low = 0.0, high = target;
    double epsilon = 1e-7;
    double* history = new double[100];
    int steps = 0;
    while(high - low > epsilon) {
        double mid = (low + high) / 2.0;
        history[steps++] = mid;
        if(mid * mid > target) {
            high = mid;
        } else {
            low = mid;
        }
    }
    double sqrtApprox = (low + high) / 2.0;
    cout << \Квадратный корень " << target << " ≈ " << sqrtApprox << endl;
    cout << "Погрешность: " << fabs(sqrtApprox - sqrt(target)) << endl;
    delete[] history;
    return 0;
}"

