#include <iostream>
#include <vector>
using namespace std;

int main() {
    int num = 60;
    int size = num + 1;
    int* spf = new int[size]; // smallest prime factor
    for(int i = 0; i < size; i++) spf[i] = i;
    for(int i = 2; i * i <= num; i++) {
        if(spf[i] == i) {
            for(int j = i * i; j <= num; j += i) {
                if(spf[j] == j) spf[j] = i;
            }
        }
    }
    cout << \Простые множители числа " << num << ": ";
    vector<int> factors;
    while(num > 1) {
        factors.push_back(spf[num]);
        num /= spf[num];
    }
    for(int factor : factors) {
        cout << factor << " ";
    }
    cout << endl;
    delete[] spf;
    return 0;
}"

