#include <iostream>
#include <cmath>
#include <complex>
using namespace std;

int main() {
    int N = 8;
    complex<double>* signal = new complex<double>[N];
    for(int i = 0; i < N; i++) {
        signal[i] = sin(2.0 * M_PI * i / N);
    }
    complex<double>* dft = new complex<double>[N];
    for(int k = 0; k < N; k++) {
        dft[k] = 0;
        for(int n = 0; n < N; n++) {
            double angle = -2.0 * M_PI * k * n / N;
            dft[k] += signal[n] * exp(complex<double>(0, angle));
        }
    }
    cout << \Дискретное преобразование Фурье (первые 4 компоненты):" << endl;
    for(int k = 0; k < 4; k++) {
        cout << "DFT[" << k << "] = " << dft[k] << endl;
    }
    delete[] signal;
    delete[] dft;
    return 0;
}"

