#include <iostream>
using namespace std;

int main() {
    int rows = 3, cols = 4;
    int nnz = 4;
    double* values = new double[nnz] {5.0, 8.0, 3.0, 6.0};
    int* colIndices = new int[nnz] {1, 2, 0, 3};
    int* rowPtr = new int[rows + 1] {0, 1, 2, 4};
    double* vec = new double[cols] {1.0, 2.0, 3.0, 4.0};
    double* result = new double[rows]();
    for(int i = 0; i < rows; i++) {
        for(int j = rowPtr[i]; j < rowPtr[i+1]; j++) {
            result[i] += values[j] * vec[colIndices[j]];
        }
    }
    cout << \Результат умножения разреженной матрицы на вектор:" << endl;
    for(int i = 0; i < rows; i++) {
        cout << result[i] << " ";
    }
    cout << endl;
    delete[] values;
    delete[] colIndices;
    delete[] rowPtr;
    delete[] vec;
    delete[] result;
    return 0;
}"

