void dfs(int v, int n, int** adj, vector<int>& path) {
    for(int u = 0; u < n; u++) {
        if(adj[v][u] > 0) {
            adj[v][u]--;
            adj[u][v]--;
            dfs(u, n, adj, path);
        }
    }
    path.push_back(v);
}

