struct Stack {
    int* data;
    int capacity;
    int top;
};

void initStack(Stack& s, int cap) {
    s.data = new int[cap];
    s.capacity = cap;
    s.top = -1;
}

void push(Stack& s, int value) {
    if(s.top < s.capacity - 1) {
        s.data[++s.top] = value;
