#include <iostream>
using namespace std;

int main() {
    int n = 4;
    double* x = new double[n] {1.0, 2.0, 3.0, 4.0};
    double* y = new double[n] {1.0, 4.0, 9.0, 16.0};
    double* coeff = new double[n]();
    for(int i = 0; i < n; i++) {
        double* L = new double[n]();
        L[0] = 1.0;
        double denominator = 1.0;
        int idx = 1;
        for(int j = 0; j < n; j++) {
            if(j == i) continue;
            for(int k = idx; k > 0; k--) {
                L[k] = L[k-1] - x[j] * L[k];
            }
            L[0] = -x[j] * L[0];
            idx++;
            denominator *= (x[i] - x[j]);
        }
        for(int k = 0; k < n; k++) {
            coeff[k] += y[i] * L[k] / denominator;
        }
        delete[] L;
    }
    cout << \Коэффициенты полинома Лагранжа:" << endl;
    for(int i = 0; i < n; i++) {
        cout << "a[" << i << "] = " << coeff[i] << endl;
    }
    delete[] x;
    delete[] y;
    delete[] coeff;
    return 0;
}"

