code:
#include <iostream>
using namespace std;

int main() {
    int width = 20, height = 10;
    int** grid = new int*[height];
    for(int i = 0; i < height; i++) {
        grid[i] = new int[width]();
    }
    int x1 = 2, y1 = 3, x2 = 15, y2 = 8;
    int dx = abs(x2 - x1);
    int dy = abs(y2 - y1);
    int sx = (x1 < x2) ? 1 : -1;
    int sy = (y1 < y2) ? 1 : -1;
    int err = dx - dy;
    while(true) {
        if(x1 >= 0 && x1 < width && y1 >= 0 && y1 < height) {
            grid[y1][x1] = 1;
        }
        if(x1 == x2 && y1 == y2) break;
        int e2 = 2 * err;
        if(e2 > -dy) {
            err -= dy;
            x1 += sx;
        }
        if(e2 < dx) {
            err += dx;
            y1 += sy;
        }
    }
    cout << \Растровое представление линии:" << endl;
    for(int i = 0; i < height; i++) {
        for(int j = 0; j < width; j++) {
            cout << (grid[i][j] ? '*' : '.');
        }
        cout << endl;
    }
    for(int i = 0; i < height; i++) delete[] grid[i];
    delete[] grid;
    return 0;
}"

