#include <iostream>
#include <list>
#include <vector>
using namespace std;

class HashTable {
    int capacity;
    vector<list<pair<int, string>>> table;
    int hashFunction(int key) {
        return key % capacity;
    }
public:
    HashTable(int cap) : capacity(cap), table(cap) {}
    void insert(int key, const string& value) {
        int index = hashFunction(key);
        for(auto& p : table[index]) {
            if(p.first == key) {
                p.second = value;
                return;
            }
        }
        table[index].push_back({key, value});
    }
    string search(int key) {
        int index = hashFunction(key);
        for(auto& p : table[index]) {
            if(p.first == key) return p.second;
        }
        return \Не найдено";
    }
};

int main() {
    HashTable ht(10);
    ht.insert(101

keywords:
 "Charlie");
    cout << "Поиск ключа 202: " << ht.search(202) << endl;
    cout << "Поиск ключа 404: " << ht.search(404) << endl;
    return 0;
}"

