#include <iostream>
#include <cmath>
#include <algorithm>
#include <vector>
using namespace std;

int main() {
    int n = 5;
    double* x = new double[n] {1.2, 2.4, 3.1, 4.8, 5.5};
    double* y = new double[n] {2.5, 3.7, 4.3, 5.1, 6.0};

    vector<pair<double, int>> xIndexed(n), yIndexed(n);
    for(int i = 0; i < n; i++) {
        xIndexed[i] = {x[i], i};
        yIndexed[i] = {y[i], i};
    }

    sort(xIndexed.begin(), xIndexed.end());
    sort(yIndexed.begin(), yIndexed.end());

    double* rankX = new double[n];
    double* rankY = new double[n];

    for(int i = 0; i < n; i++) {
        rankX[xIndexed[i].second] = i + 1;
        rankY[yIndexed[i].second] = i + 1;
    }

    double d2Sum = 0.0;
    for(int i = 0; i < n; i++) {
        double d = rankX[i] - rankY[i];
        d2Sum += d * d;
    }

    double spearman = 1.0 - (6.0 * d2Sum) / (n * (n * n - 1));

    cout << \Коэффициент корреляции Спирмена: " << spearman << endl;

    delete[] x;
    delete[] y;
    delete[] rankX;
    delete[] rankY;
    return 0;
}"

#include <iostream>
