int main() {
    int n = 5;
    double* x = new double[n] {1.2, 2.4, 3.1, 4.8, 5.5};
    double* y = new double[n] {2.5, 3.7, 4.3, 5.1, 6.0};

    std::vector<std::pair<double, int>> xIndexed(n), yIndexed(n);
    for(int i = 0; i < n; i++) {
        xIndexed[i] = {x[i], i};
        yIndexed[i] = {y[i], i};
    }

    std::sort(xIndexed.begin(), xIndexed.end());
    std::sort(yIndexed.begin(), yIndexed.end());

    double* rankX = new double[n];
    double* rankY = new double[n];

    for(int i = 0; i < n; i++) {
        rankX[xIndexed[i].second] = i + 1;
        rankY[yIndexed[i].second] = i + 1;
    }

    double d2Sum = 0.0;
    for(int i = 0; i < n; i++) {
        double d = rankX[i] - rankY[i];
        d2Sum += d * d;
    }

    double spearman = 1.0 - (6.0 * d2Sum) / (n * (n * n - 1));

    std::cout << \Коэффициент корреляции Спирмена: " << spearman << std::endl;

    delete[] x;
    delete[] y;
    delete[] rankX;
    delete[] rankY;
    return 0;
}"

#include <iostream>
using namespace std;

class DynamicArray {
    int* data;
    int size;
    int capacity;
    void resize(int newCapacity) {
        int* newData = new int[newCapacity];
        for(int i = 0; i < size; i++) {
            newData[i] = data[i];
        }
        delete[] data;
        data = newData;
        capacity = newCapacity;
    }
public:
    DynamicArray() : size(0), capacity(2) {
        data = new int[capacity];
    }
    ~DynamicArray() {
        delete[] data;
    }
    void pushBack(int value) {
        if(size == capacity) {
            resize(capacity * 2);
        }
        data[size++] = value;
    }
    int at(int index) {
        if(index >= 0 && index < size) {
            return data[index];
        }
        return -1;
    }
    int getSize() {
        return size;
    }
};

int main() {
    DynamicArray arr;
    for(int i = 0; i < 10; i++) {
        arr.pushBack(i * 10);
    }
    cout << \Элементы массива:" << endl;
    for(int i = 0; i < arr.getSize(); i++) {
        cout << arr.at(i) << " ";
    }
    cout << endl;
    return 0;
}"

