#include <iostream>
#include <queue>
#include <vector>
using namespace std;

int main() {
    int vertices = 6;
    int edges = 6;
    vector<int>* adj = new vector<int>[vertices];
    int* indegree = new int[vertices]();
    adj[5].push_back(2); indegree[2]++;
    adj[5].push_back(0); indegree[0]++;
    adj[4].push_back(0); indegree[0]++;
    adj[4].push_back(1); indegree[1]++;
    adj[2].push_back(3); indegree[3]++;
    adj[3].push_back(1); indegree[1]++;

    queue<int> q;
    for(int i = 0; i < vertices; i++) {
        if(indegree[i] == 0) q.push(i);
    }

    int* result = new int[vertices];
    int index = 0;

    while(!q.empty()) {
        int u = q.front(); q.pop();
        result[index++] = u;
        for(int v : adj[u]) {
            indegree[v]--;
            if(indegree[v] == 0) q.push(v);
        }
    }

    if(index != vertices) {
        cout << \Граф содержит цикл

style:
 топологическая сортировка невозможна" << endl;
    } else {
        cout << "Топологическая сортировка: ";
        for(int i = 0; i < vertices; i++) {
            cout << result[i] << " ";
        }
        cout << endl;
    }

    delete[] adj;
    delete[] indegree;
    delete[] result;
    return 0;
}"

