#include <iostream>
#include <cstring>
using namespace std;

int* computeLPS(const char* pattern) {
    int m = strlen(pattern);
    int* lps = new int[m];
    lps[0] = 0;
    int len = 0, i = 1;
    while(i < m) {
        if(pattern[i] == pattern[len]) {
            len++;
            lps[i] = len;
            i++;
        } else {
            if(len != 0) {
                len = lps[len-1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }
    return lps;
}

void KMPSearch(const char* text, const char* pattern) {
    int n = strlen(text);
    int m = strlen(pattern);
    int* lps = computeLPS(pattern);
    int i = 0, j = 0;
    while(i < n) {
        if(pattern[j] == text[i]) {
            i++;
            j++;
        }
        if(j == m) {
            cout << \Найдено в позиции " << i - j << endl;
            j = lps[j-1];
        } else if(i < n && pattern[j] != text[i]) {
            if(j != 0) {
                j = lps[j-1];
            } else {
                i++;
            }
        }
    }
    delete[] lps;
}

