#include <iostream>
#include <cmath>
using namespace std;

int main() {
    int rows = 3, cols = 3;
    double** matrix = new double*[rows];
    for(int i = 0; i < rows; i++) matrix[i] = new double[cols];
    matrix[0][0]=1; matrix[0][1]=2; matrix[0][2]=3;
    matrix[1][0]=4; matrix[1][1]=5; matrix[1][2]=6;
    matrix[2][0]=7; matrix[2][1]=8; matrix[2][2]=9;
    int rank = rows;
    for(int r = 0; r < rank; r++) {
        if(abs(matrix[r][r]) < 1e-10) {
            bool reduce = true;
            for(int i = r+1; i < rows; i++) {
                if(abs(matrix[i][r]) > 1e-10) {
                    swap(matrix[r], matrix[i]);
                    reduce = false;
                    break;
                }
            }
            if(reduce) {
                rank--;
                for(int i = 0; i < rows; i++) {
                    matrix[i][r] = matrix[i][rank];
                }
                r--;
            }
        } else {
            for(int i = r+1; i < rows; i++) {
                double factor = matrix[i][r] / matrix[r][r];
                for(int j = r; j < cols; j++) {
                    matrix[i][j] -= factor * matrix[r][j];
                }
            }
        }
    }
    cout << \Ранг матрицы: " << rank << endl;
    for(int i = 0; i < rows; i++) delete[] matrix[i];
    delete[] matrix;
    return 0;
}"

