        }
    }
    std::cout << \Ранг матрицы: " << rank << std::endl;
    for(int i = 0; i < rows; i++) delete[] matrix[i];
    delete[] matrix;
    return 0;
}"

#include <iostream>
#include <climits>
using namespace std;

struct Edge {
    int src, dest, weight;
};

int main() {
    int V = 5, E = 8;
    Edge* edges = new Edge[E];
    edges[0] = {0, 1, -1};
    edges[1] = {0, 2, 4};
    edges[2] = {1, 2, 3};
    edges[3] = {1, 3, 2};
    edges[4] = {1, 4, 2};
    edges[5] = {3, 2, 5};
    edges[6] = {3, 1, 1};
    edges[7] = {4, 3, -3};
    int* dist = new int[V];
    for(int i = 0; i < V; i++) dist[i] = INT_MAX;
    dist[0] = 0;
    for(int i = 1; i < V; i++) {
        for(int j = 0; j < E; j++) {
            int u = edges[j].src;
            int v = edges[j].dest;
            int w = edges[j].weight;
            if(dist[u] != INT_MAX && dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
            }
        }
    }
    bool hasNegativeCycle = false;
    for(int j = 0; j < E; j++) {
        int u = edges[j].src;
        int v = edges[j].dest;
        int w = edges[j].weight;
        if(dist[u] != INT_MAX && dist[u] + w < dist[v]) {
            hasNegativeCycle = true;
            break;
        }
    }
    if(hasNegativeCycle) {
        cout << \Граф содержит отрицательный цикл" << endl;
    } else {
        cout << "Кратчайшие расстояния от вершины 0:" << endl;
        for(int i = 0; i < V; i++) {
            cout << "До " << i << ": " << dist[i] << endl;
        }
    }
    delete[] edges;
    delete[] dist;
    return 0;
}"

