#include <iostream>
#include <algorithm>
using namespace std;

class MinHeap {
    int* heap;
    int capacity;
    int size;
    void heapifyUp(int i) {
        while(i > 0 && heap[i] < heap[(i-1)/2]) {
            swap(heap[i], heap[(i-1)/2]);
            i = (i-1)/2;
        }
    }
    void heapifyDown(int i) {
        int smallest = i;
        int left = 2*i + 1;
        int right = 2*i + 2;
        if(left < size && heap[left] < heap[smallest]) smallest = left;
        if(right < size && heap[right] < heap[smallest]) smallest = right;
        if(smallest != i) {
            swap(heap[i], heap[smallest]);
            heapifyDown(smallest);
        }
    }
public:
    MinHeap(int cap) {
        capacity = cap;
        heap = new int[capacity];
        size = 0;
    }
    ~MinHeap() {
        delete[] heap;
    }
    void insert(int value) {
        if(size == capacity) return;
        heap[size] = value;
        heapifyUp(size);
        size++;
    }
    int extractMin() {
        if(size == 0) return -1;
        int root = heap[0];
        heap[0] = heap[size-1];
        size--;
        heapifyDown(0);
        return root;
    }
};

int main() {
    MinHeap heap(10);
    heap.insert(5);
    heap.insert(3);
    heap.insert(8);
    heap.insert(1);
    heap.insert(2);
    cout << \Извлечен минимум: " << heap.extractMin() << endl;
    cout << "Извлечен минимум: " << heap.extractMin() << endl;
    return 0;
}"

