using namespace std;

int main() {
    int vertices = 5;
    int** graph = new int*[vertices];
    for(int i = 0; i < vertices; i++) {
        graph[i] = new int[vertices];
        for(int j = 0; j < vertices; j++) {
            graph[i][j] = (i == j) ? 0 : INT_MAX/2;
        }
    }
    graph[0][1] = 10; graph[1][0] = 10;
    graph[0][3] = 5;  graph[3][0] = 5;
    graph[1][2] = 1;  graph[2][1] = 1;
    graph[1][3] = 2;  graph[3][1] = 2;
    graph[2][4] = 4;  graph[4][2] = 4;
    graph[3][2] = 3;  graph[2][3] = 3;
    graph[3][4] = 2;  graph[4][3] = 2;

    int start = 0;
    int* dist = new int[vertices];
    bool* visited = new bool[vertices]();
    for(int i = 0; i < vertices; i++) dist[i] = INT_MAX/2;
    dist[start] = 0;

    for(int count = 0; count < vertices; count++) {
        int u = -1;
        for(int i = 0; i < vertices; i++) {
            if(!visited[i] && (u == -1 || dist[i] < dist[u])) {
                u = i;
            }
