#include <iostream>
#include <cmath>
using namespace std;

int main() {
    int n = 5;
    int m = 3;
    double** data = new double*[n];
    for(int i = 0; i < n; i++) {
        data[i] = new double[m];
    }
    data[0][0]=1.0; data[0][1]=2.0; data[0][2]=3.0;
    data[1][0]=2.0; data[1][1]=3.0; data[1][2]=5.0;
    data[2][0]=3.0; data[2][1]=4.0; data[2][2]=7.0;
    data[3][0]=4.0; data[3][1]=5.0; data[3][2]=9.0;
    data[4][0]=5.0; data[4][1]=6.0; data[4][2]=11.0;

    double* mean = new double[m]();
    for(int j = 0; j < m; j++) {
        for(int i = 0; i < n; i++) {
            mean[j] += data[i][j];
        }
        mean[j] /= n;
    }

    double** corr = new double*[m];
    for(int i = 0; i < m; i++) corr[i] = new double[m]();

    for(int i = 0; i < m; i++) {
        for(int j = 0; j < m; j++) {
            double cov = 0.0, var1 = 0.0, var2 = 0.0;
            for(int k = 0; k < n; k++) {
                double dev1 = data[k][i] - mean[i];
                double dev2 = data[k][j] - mean[j];
                cov += dev1 * dev2;
                var1 += dev1 * dev1;
                var2 += dev2 * dev2;
            }
            if(var1 > 0 && var2 > 0) {
                corr[i][j] = cov / sqrt(var1 * var2);
            } else {
                corr[i][j] = 0.0;
            }
        }
    }

    cout << \Матрица корреляции Пирсона:" << endl;
    for(int i = 0; i < m; i++) {
        for(int j = 0; j < m; j++) {
            cout << corr[i][j] << "\t";
        }
        cout << endl;
    }

    for(int i = 0; i < n; i++) delete[] data[i];
    delete[] data;
    for(int i = 0; i < m; i++) delete[] corr[i];
    delete[] corr;
    delete[] mean;
    return 0;
}"

