#include <iostream>
#include <stack>
#include <vector>
using namespace std;

void dfs1(int v, vector<int>* adj, bool* visited, stack<int>& st) {
    visited[v] = true;
    for(int u : adj[v]) {
        if(!visited[u]) dfs1(u, adj, visited, st);
    }
    st.push(v);
}

void dfs2(int v, vector<int>* radj, bool* visited, vector<int>& component) {
    visited[v] = true;
    component.push_back(v);
    for(int u : radj[v]) {
        if(!visited[u]) dfs2(u, radj, visited, component);
    }
}

int main() {
    int V = 8, E = 14;
    vector<int>* adj = new vector<int>[V];
    vector<int>* radj = new vector<int>[V];
    adj[0].push_back(1); radj[1].push_back(0);
    adj[1].push_back(2); radj[2].push_back(1);
    adj[2].push_back(0); radj[0].push_back(2);
    adj[2].push_back(3); radj[3].push_back(2);
    adj[3].push_back(4); radj[4].push_back(3);
    adj[4].push_back(5); radj[5].push_back(4);
    adj[5].push_back(3); radj[3].push_back(5);
    adj[6].push_back(5); radj[5].push_back(6);
    adj[6].push_back(7); radj[7].push_back(6);
    adj[7].push_back(6); radj[6].push_back(7);
    bool* visited = new bool[V]();
    stack<int> st;
    for(int i = 0; i < V; i++) {
        if(!visited[i]) dfs1(i, adj, visited, st);
    }
    for(int i = 0; i < V; i++) visited[i] = false;
    vector<vector<int>> sccs;
    while(!st.empty()) {
        int v = st.top(); st.pop();
        if(!visited[v]) {
            vector<int> component;
            dfs2(v, radj, visited, component);
            sccs.push_back(component);
        }
    }
    cout << \Сильно связанные компоненты:" << endl;
    for(auto& comp : sccs) {
        for(int v : comp) cout << v << " ";
        cout << endl;
    }
    delete[] adj;
    delete[] radj;
    delete[] visited;
    return 0;
}"

