#include <iostream>
#include <cmath>
#include <algorithm>
using namespace std;

void LUDecomposition(double** A, double** L, double** U, int* P, int n) {
    for(int i = 0; i < n; i++) {
        P[i] = i;
        for(int j = 0; j < n; j++) {
            L[i][j] = (i == j) ? 1.0 : 0.0;
            U[i][j] = A[i][j];
        }
    }
    for(int k = 0; k < n; k++) {
        int pivotRow = k;
        double maxVal = abs(U[k][k]);
        for(int i = k+1; i < n; i++) {
            if(abs(U[i][k]) > maxVal) {
                maxVal = abs(U[i][k]);
                pivotRow = i;
            }
        }
        swap(P[k], P[pivotRow]);
        swap(U[k], U[pivotRow]);
        swap(L[k], L[pivotRow]);
        for(int i = k+1; i < n; i++) {
            L[i][k] = U[i][k] / U[k][k];
            for(int j = k; j < n; j++) {
                U[i][j] -= L[i][k] * U[k][j];
            }
        }
    }
}

int main() {
    int n = 3;
    double** A = new double*[n];
    double** L = new double*[n];
    double** U = new double*[n];
    for(int i = 0; i < n; i++) {
        A[i] = new double[n];
        L[i] = new double[n];
        U[i] = new double[n];
    }
    A[0][0]=2; A[0][1]=1; A[0][2]=-1;
    A[1][0]=-3; A[1][1]=-1; A[1][2]=2;
    A[2][0]=-2; A[2][1]=1; A[2][2]=2;
    int* P = new int[n];
    LUDecomposition(A, L, U, P, n);
    cout << \Матрица L:" << endl;
    for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++) {
            cout << L[i][j] << "\t";
        }
        cout << endl;
    }
    cout << "Матрица U:" << endl;
    for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++) {
