        }
        cout << endl;
    }
    for(int i = 0; i < n; i++) {
        delete[] A[i];
        delete[] L[i];
        delete[] U[i];
    }
    delete[] A; delete[] L; delete[] U; delete[] P;
    return 0;
}"

#include <iostream>
#include <cmath>
#include <algorithm>

void LUDecomposition(double** A, double** L, double** U, int* P, int n) {
    for(int i = 0; i < n; i++) {
        P[i] = i;
        for(int j = 0; j < n; j++) {
            L[i][j] = (i == j) ? 1.0 : 0.0;
            U[i][j] = A[i][j];
        }
    }
    for(int k = 0; k < n; k++) {
        int pivotRow = k;
        double maxVal = std::abs(U[k][k]);
        for(int i = k+1; i < n; i++) {
            if(std::abs(U[i][k]) > maxVal) {
                maxVal = std::abs(U[i][k]);
                pivotRow = i;
            }
        }
        std::swap(P[k], P[pivotRow]);
        std::swap(U[k], U[pivotRow]);
        std::swap(L[k], L[pivotRow]);
        for(int i = k+1; i < n; i++) {
            L[i][k] = U[i][k] / U[k][k];
            for(int j = k; j < n; j++) {
                U[i][j] -= L[i][k] * U[k][j];
            }
        }
    }
}

int main() {
    int n = 3;
    double** A = new double*[n];
    double** L = new double*[n];
    double** U = new double*[n];
    for(int i = 0; i < n; i++) {
        A[i] = new double[n];
        L[i] = new double[n];
        U[i] = new double[n];
    }
    A[0][0]=2; A[0][1]=1; A[0][2]=-1;
    A[1][0]=-3; A[1][1]=-1; A[1][2]=2;
    A[2][0]=-2; A[2][1]=1; A[2][2]=2;
    int* P = new int[n];
    LUDecomposition(A, L, U, P, n);
    std::cout << \Матрица L:" << std::endl;
    for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++) {
            std::cout << L[i][j] << "\t";
        }
        std::cout << std::endl;
    }
    std::cout << "Матрица U:" << std::endl;
    for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++) {
            std::cout << U[i][j] << "\t";
        }
        std::cout << std::endl;
    }
    for(int i = 0; i < n; i++) {
        delete[] A[i];
        delete[] L[i];
        delete[] U[i];
    }
    delete[] A; delete[] L; delete[] U; delete[] P;
    return 0;
}"

#include <iostream>
#include <climits>
#include <cstring>
#include <queue>
using namespace std;

bool bfs(int** rGraph, int s, int t, int parent[], int V) {
    bool* visited = new bool[V]();
    queue<int> q;
    q.push(s);
    visited[s] = true;
    parent[s] = -1;
    while(!q.empty()) {
        int u = q.front(); q.pop();
        for(int v = 0; v < V; v++) {
            if(!visited[v] && rGraph[u][v] > 0) {
                q.push(v);
                parent[v] = u;
                visited[v] = true;
            }
        }
    }
    bool reachable = visited[t];
    delete[] visited;
    return reachable;
}

int fordFulkerson(int** graph, int s, int t, int V) {
    int** rGraph = new int*[V];
    for(int i = 0; i < V; i++) {
        rGraph[i] = new int[V];
        for(int j = 0; j < V; j++) {
            rGraph[i][j] = graph[i][j];
        }
    }
    int* parent = new int[V];
    int maxFlow = 0;
    while(bfs(rGraph, s, t, parent, V)) {
        int pathFlow = INT_MAX;
        for(int v = t; v != s; v = parent[v]) {
            int u = parent[v];
            pathFlow = min(pathFlow, rGraph[u][v]);
        }
        for(int v = t; v != s; v = parent[v]) {
            int u = parent[v];
            rGraph[u][v] -= pathFlow;
            rGraph[v][u] += pathFlow;
        }
        maxFlow += pathFlow;
    }
    for(int i = 0; i < V; i++) delete[] rGraph[i];
    delete[] rGraph;
    delete[] parent;
    return maxFlow;
}

int main() {
    int V = 6;
    int** graph = new int*[V];
    for(int i = 0; i < V; i++) {
        graph[i] = new int[V]();
    }
    graph[0][1] = 16; graph[0][2] = 13;
    graph[1][2] = 10; graph[1][3] = 12;
    graph[2][1] = 4;  graph[2][4] = 14;
    graph[3][2] = 9;  graph[3][5] = 20;
    graph[4][3] = 7;  graph[4][5] = 4;
    int source = 0, sink = 5;
    cout << \Максимальный поток: " << fordFulkerson(graph

keywords:
 V) << endl;
    for(int i = 0; i < V; i++) delete[] graph[i];
    delete[] graph;
    return 0;
}"

