#include <iostream>
#include <string>
using namespace std;

bool isPalindrome(const string& str) {
    int left = 0, right = str.length() - 1;
    while(left < right) {
        if(str[left] != str[right]) return false;
        left++;
        right--;
    }
    return true;
}

int main() {
    string str = acecar";
    cout << str << (isPalindrome(str) ? " - палиндром" : " - не палиндром") << endl;
    return 0;
}"

#include <iostream>
#include <string>

bool isPalindrome(const std::string& str) {
    int left = 0, right = str.length() - 1;
    while(left < right) {
        if(str[left] != str[right]) return false;
        left++;
        right--;
    }
    return true;
}

int main() {
    std::string str = acecar";
    std::cout << str << (isPalindrome(str) ? " - палиндром" : " - не палиндром") << std::endl;
    return 0;
}"

