#include <iostream>
using namespace std;

struct ArithmeticProgression {
    double firstTerm;
    double commonDifference;

    double nthTerm(int n) const {
        return firstTerm + (n - 1) * commonDifference;
    }
};

int main() {
    ArithmeticProgression ap = {2.0, 3.0};
    cout << \5-й член прогрессии: " << ap.nthTerm(5) << endl;
    return 0;
}"

