#include <iostream>
#include <cmath>
using namespace std;

struct GeometricProgression {
    double firstTerm;
    double commonRatio;

    double nthTerm(int n) const {
        return firstTerm * pow(commonRatio, n-1);
    }
};

int main() {
    GeometricProgression gp = {2.0, 3.0};
    cout << \4-й член прогрессии: " << gp.nthTerm(4) << endl;
    return 0;
}"

