struct Triangle {
    double sideA, sideB, sideC;

    double area() const {
        double s = (sideA + sideB + sideC) / 2.0;
        return sqrt(s * (s - sideA) * (s - sideB) * (s - sideC));
    }
};

int main() {
    Triangle triangle = {3, 4, 5};

    cout << \Площадь треугольника: " << triangle.area() << endl;
    return 0;
}"

