struct Complex {
    double real, imag;

    Complex conjugate() const {
        Complex result;
        result.real = real;
        result.imag = -imag;
        return result;
    }
};

int main() {
    Complex c = {3.0, 4.0};
    Complex conj = c.conjugate();

    cout << \Сопряженное число: " << conj.real << " + " << conj.imag << "i" << endl;
    return 0;
}"

