struct Matrix2x2 {
    double m11, m12;
    double m21, m22;

    double trace() const {
        return m11 + m22;
    }

    double determinant() const {
        return m11 * m22 - m12 * m21;
    }
};

int main() {
    Matrix2x2 mat = {1, 2, 3, 4};

    cout << \След матрицы: " << mat.trace() << endl;
    cout << "Определитель матрицы: " << mat.determinant() << endl;

    return 0;
}"

