#include <iostream>
#include <cmath>
using namespace std;

struct Segment {
    double x1, y1, x2, y2;

    double slope() const {
        if (x2 == x1) {
            return INFINITY;
        }
        return (y2 - y1) / (x2 - x1);
    }
};

int main() {
    Segment seg1 = {0, 0, 2, 2};
    Segment seg2 = {1, 1, 1, 3};

    cout << \Наклон seg1: " << seg1.slope() << endl;
    cout << "Наклон seg2: " << seg2.slope() << endl;
    return 0;
}"

