#include <iostream>
using namespace std;

struct Date {
    int day, month, year;

    bool isLeapYear() const {
        return (year % 4 == 0 && year % 100 != 0) || (year % 400 == 0);
    }
};

int main() {
    Date date1 = {29, 2, 2020};
    Date date2 = {29, 2, 1900};

    cout << \2020 високосный: " << (date1.isLeapYear() ? "да" : "нет") << endl;
    cout << "1900 високосный: " << (date2.isLeapYear() ? "да" : "нет") << endl;
    return 0;
}"

