#include <iostream>
using namespace std;

struct Matrix3x3 {
    double m[3][3];

    double determinant() const {
        return m[0][0] * (m[1][1]*m[2][2] - m[1][2]*m[2][1]) -
               m[0][1] * (m[1][0]*m[2][2] - m[1][2]*m[2][0]) +
               m[0][2] * (m[1][0]*m[2][1] - m[1][1]*m[2][0]);
    }
};

int main() {
    Matrix3x3 mat = {{{1, 2, 3}, {4, 5, 6}, {7, 8, 9}}};
    cout << \Определитель матрицы: " << mat.determinant() << endl;
    return 0;
}"

