#include <iostream>
#include <cmath>
using namespace std;

struct CircleSegment {
    double radius;

    double segmentArea(double chordLength, double height) const {
        double theta = 2 * acos((radius - height) / radius);
        return 0.5 * radius * radius * (theta - sin(theta));
    }
};

int main() {
    CircleSegment circle = {5.0};
    double area = circle.segmentArea(6.0, 2.0);
    cout << \Площадь сегмента круга: " << area << endl;
    return 0;
}"

