#include <iostream>
using namespace std;

struct FloatInterval {
    double start, end;

    double length() const {
        return end - start;
    }

    bool contains(double value) const {
        return value >= start && value <= end;
    }
};

int main() {
    FloatInterval interval = {1.5, 5.5};
    cout << \Длина интервала: " << interval.length() << endl;
    cout << "Число 3.0 в интервале: " << (interval.contains(3.0) ? "да" : "нет") << endl;
    return 0;
}"

