#include <iostream>
#include <cmath>
using namespace std;

struct Point {
    double x, y;
};

struct LineSegment {
    Point start;
    Point end;
};

double length(const LineSegment& segment) {
    double dx = segment.end.x - segment.start.x;
    double dy = segment.end.y - segment.start.y;
    return sqrt(dx * dx + dy * dy);
}

int main() {
    LineSegment segment = {{0.0, 0.0}, {3.0, 4.0}};

    cout << \Длина отрезка: " << length(segment) << endl;
    return 0;
}"

