using namespace std;

struct Time {
    int hours, minutes, seconds;

    int totalSeconds() const {
        return hours * 3600 + minutes * 60 + seconds;
    }

    int difference(const Time& other) const {
        return abs(totalSeconds() - other.totalSeconds());
    }
};

int main() {
    Time t1 = {10, 30, 0};
    Time t2 = {12, 15, 45};

    cout << \Разница в секундах: " << t1.difference(t2) << endl;
    return 0;
}"

