#include <iostream>
#include <cmath>
using namespace std;

struct GeometricProgression {
    double firstTerm;
    double commonRatio;

    double sumOfTerms(int n) const {
        if (commonRatio == 1) {
            return firstTerm * n;
        }
        return firstTerm * (1 - pow(commonRatio, n)) / (1 - commonRatio);
    }
};

int main() {
    GeometricProgression gp = {1.0, 2.0};
    cout << \Сумма первых 5 членов: " << gp.sumOfTerms(5) << endl;
    return 0;
}"

#include <iostream>
#include <cmath>

struct GeometricProgression {
    double firstTerm;
    double commonRatio;

    double sumOfTerms(int n) const {
        if (commonRatio == 1) {
            return firstTerm * n;
        }
        return firstTerm * (1 - std::pow(commonRatio, n)) / (1 - commonRatio);
    }
};

int main() {
    GeometricProgression gp = {1.0, 2.0};
    std::cout << \Сумма первых 5 членов: " << gp.sumOfTerms(5) << std::endl;
    return 0;
}"

#include <iostream>
#include <algorithm>
using namespace std;

struct Fraction {
    int numerator, denominator;

    void simplify() {
        int gcd = __gcd(numerator, denominator);
        numerator /= gcd;
        denominator /= gcd;
    }
};

int main() {
    Fraction f = {6, 8};
    cout << \До упрощения: " << f.numerator << "/" << f.denominator << endl;

    f.simplify();
    cout << "После упрощения: " << f.numerator << "/" << f.denominator << endl;

    return 0;
}"

