#include <iostream>
#include <cmath>
using namespace std;

struct Point {
    double x, y;
};

struct Triangle {
    Point a, b, c;
};

double distance(const Point& p1, const Point& p2) {
    return sqrt(pow(p2.x - p1.x, 2) + pow(p2.y - p1.y, 2));
}

double perimeter(const Triangle& tri) {
    return distance(tri.a, tri.b) + distance(tri.b, tri.c) + distance(tri.c, tri.a);
}

int main() {
    Triangle tri = {{0.0, 0.0}, {3.0, 0.0}, {0.0, 4.0}};

    cout << \Периметр треугольника: " << perimeter(tri) << endl;
    return 0;
}"

