#include <iostream>
using namespace std;

struct Counter {
    int value;

    void increment() {
        ++value;
    }

    void decrement() {
        --value;
    }

    void reset() {
        value = 0;
    }

    void print() const {
        cout << \Текущее значение счетчика: " << value << endl;
    }
};

int main() {
    Counter counter = {5};

    counter.print();
    counter.increment();
    counter.print();
    counter.decrement();
    counter.print();
    counter.reset();
    counter.print();

    return 0;
}"

