#include <iostream>
#include <cmath>
using namespace std;

struct Triangle {
    double sideA, sideB, sideC;

    bool isAcute() const {
        double a2 = sideA * sideA;
        double b2 = sideB * sideB;
        double c2 = sideC * sideC;

        return (a2 + b2 > c2) && (a2 + c2 > b2) && (b2 + c2 > a2);
    }
};

int main() {
    Triangle tri1 = {3, 4, 5};
    Triangle tri2 = {5, 5, 5};

    cout << 	ri1 остроугольный: " << (tri1.isAcute() ? "да" : "нет") << endl;
    cout << "tri2 остроугольный: " << (tri2.isAcute() ? "да" : "нет") << endl;
    return 0;
}"

