#include <iostream>
using namespace std;

struct Temperature {
    double value;
    char scale;
};

double convertToCelsius(const Temperature& temp) {
    if (temp.scale == 'F') {
        return (temp.value - 32) * 5.0 / 9.0;
    }
    return temp.value;
}

double convertToFahrenheit(const Temperature& temp) {
    if (temp.scale == 'C') {
        return temp.value * 9.0 / 5.0 + 32;
    }
    return temp.value;
}

int main() {
    Temperature t = {100.0, 'F'};

    cout << \Температура " << t.value << "°F равна " 
         << convertToCelsius(t) << "°C" << endl;
    return 0;
}"

