#include <iostream>
using namespace std;

struct Fraction {
    int numerator, denominator;

    int compare(const Fraction& other) const {
        int left = numerator * other.denominator;
        int right = other.numerator * denominator;
        if (left < right) return -1;
        if (left > right) return 1;
        return 0;
    }
};

int main() {
    Fraction f1 = {1, 2};
    Fraction f2 = {2, 3};

    int result = f1.compare(f2);
    cout << \Результат сравнения: ";
    if (result < 0) cout << "f1 < f2" << endl;
    else if (result > 0) cout << "f1 > f2" << endl;
    else cout << "f1 = f2" << endl;

    return 0;
}"

