#include <iostream>
#include <cmath>
using namespace std;

struct Point {
    double x, y;
};

struct Polygon {
    Point vertices[10];
    int vertexCount;

    double perimeter() const {
        double p = 0;
        for (int i = 0; i < vertexCount; ++i) {
            int j = (i + 1) % vertexCount;
            double dx = vertices[j].x - vertices[i].x;
            double dy = vertices[j].y - vertices[i].y;
            p += sqrt(dx*dx + dy*dy);
        }
        return p;
    }
};

int main() {
    Polygon poly = {{{0,0}, {4,0}, {4,3}}, 3};

    cout << \Периметр многоугольника: " << poly.perimeter() << endl;
    return 0;
}"

#include <iostream>
#include <cmath>

struct Point {
    double x, y;
};

struct Polygon {
    Point vertices[10];
    int vertexCount;

    double perimeter() const {
        double p = 0;
        for (int i = 0; i < vertexCount; ++i) {
            int j = (i + 1) % vertexCount;
            double dx = vertices[j].x - vertices[i].x;
            double dy = vertices[j].y - vertices[i].y;
            p += std::sqrt(dx*dx + dy*dy);
        }
        return p;
    }
};

int main() {
