#include <iostream>
using namespace std;

struct Rational {
    int numerator;
    int denominator;

    void reduce() {
        int a = numerator;
        int b = denominator;
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        int gcd = a;
        numerator /= gcd;
        denominator /= gcd;
    }

    void print() const {
        cout << numerator << /" << denominator << endl;
    }
};

int main() {
    Rational r = {6

style:
 8};
    cout << "До сокращения: ";
    r.print();

    r.reduce();
    cout << "После сокращения: ";
    r.print();

    return 0;
}"

