#include <iostream>
using namespace std;

struct MeterReading {
    double previousReading;
    double currentReading;
    double tariff;
};

double calculateConsumption(const MeterReading& reading) {
    return reading.currentReading - reading.previousReading;
}

double calculateCost(const MeterReading& reading) {
    return calculateConsumption(reading) * reading.tariff;
}

int main() {
    MeterReading reading = {1000.0, 1050.0, 5.0};

    cout << \Потребление: " << calculateConsumption(reading) << " единиц" << endl;
    cout << "Стоимость: " << calculateCost(reading) << " рублей" << endl;

    return 0;
}"

