#include <iostream>
#include <cmath>
using namespace std;

struct Point {
    double x, y;
};

struct Circle {
    Point center;
    double radius;
};

bool isInside(const Circle& circle, const Point& point) {
    double dx = point.x - circle.center.x;
    double dy = point.y - circle.center.y;
    return (dx * dx + dy * dy) <= (circle.radius * circle.radius);
}

int main() {
    Circle circle = {{0.0, 0.0}, 5.0};
    Point point = {3.0, 4.0};

    if (isInside(circle, point)) {
        cout << \Точка находится внутри круга." << endl;
    } else {
        cout << "Точка находится вне круга." << endl;
    }
    return 0;
}"

