#include <iostream>
#include <cmath>
using namespace std;

struct Date {
    int day, month, year;

    int daysSinceEpoch() const {
        int m = month;
        int y = year;
        if (m < 3) {
            m += 12;
            y -= 1;
        }
        return day + (153 * m - 457) / 5 + 365 * y + y / 4 - y / 100 + y / 400 - 306;
    }

    int daysDifference(const Date& other) const {
        return abs(daysSinceEpoch() - other.daysSinceEpoch());
    }
};

int main() {
    Date date1 = {15, 10, 2023};
    Date date2 = {25, 10, 2023};

    cout << \Разница между датами: " << date1.daysDifference(date2) << " дней" << endl;
    return 0;
}"

#include <iostream>
