struct Date {
    int day, month, year;

    int daysSinceEpoch() const {
        int m = month;
        int y = year;
        if (m < 3) {
            m += 12;
            y -= 1;
        }
        return day + (153 * m - 457) / 5 + 365 * y + y / 4 - y / 100 + y / 400 - 306;
    }

    int daysDifference(const Date& other) const {
        return std::abs(daysSinceEpoch() - other.daysSinceEpoch());
    }
};

int main() {
    Date date1 = {15, 10, 2023};
    Date date2 = {25, 10, 2023};

    std::cout << \Разница между датами: " << date1.daysDifference(date2) << " дней" << std::endl;
    return 0;
}"

#include <iostream>
using namespace std;

struct LineSegment {
    double start, end;

    bool intersects(const LineSegment& other) const {
        return !(end < other.start || start > other.end);
    }

    double length() const {
        return end - start;
    }
};

int main() {
    LineSegment seg1 = {1.0, 5.0};
    LineSegment seg2 = {3.0, 7.0};
    LineSegment seg3 = {6.0, 8.0};

    cout << \seg1 пересекается с seg2: " << (seg1.intersects(seg2) ? "да" : "нет") << endl;
    cout << "Длина seg1: " << seg1.length() << endl;
    cout << "seg1 пересекается с seg3: " << (seg1.intersects(seg3) ? "да" : "нет") << endl;

    return 0;
}"

