struct Circle {
    double centerX, centerY;
    double radius;

    bool intersects(const Circle& other) const {
        double dx = centerX - other.centerX;
        double dy = centerY - other.centerY;
        double distance = sqrt(dx*dx + dy*dy);
        return distance <= (radius + other.radius);
    }
};

