#include <iostream>
#include <cmath>
using namespace std;

struct Circle {
    double radius;

    double arcLength(double angleDegrees) const {
        double angleRadians = angleDegrees * M_PI / 180.0;
        return radius * angleRadians;
    }

    double sectorArea(double angleDegrees) const {
        double angleRadians = angleDegrees * M_PI / 180.0;
        return 0.5 * radius * radius * angleRadians;
    }
};

int main() {
    Circle circle = {5.0};
    double angle = 60.0;

    cout << \Длина дуги для угла " << angle << " градусов: " << circle.arcLength(angle) << endl;
    cout << "Площадь сектора: " << circle.sectorArea(angle) << endl;

    return 0;
}"

