#include <iostream>
using namespace std;

struct Line {
    double slope;
    double intercept;

    bool findIntersection(const Line& other, double& x, double& y) const {
        if (slope == other.slope) {
            return false;
        }
        x = (other.intercept - intercept) / (slope - other.slope);
        y = slope * x + intercept;
        return true;
    }
};

int main() {
    Line line1 = {2.0, 1.0};
    Line line2 = {-1.0, 3.0};
    double x, y;

    if (line1.findIntersection(line2, x, y)) {
        cout << \Точка пересечения: (" << x << "

style:
 " << y << ")" << endl;
    } else {
        cout << "Прямые параллельны" << endl;
    }

    return 0;
}"

