#include <iostream>
#include <cmath>
using namespace std;

struct PrimeNumber {
    int value;

    bool isPrime() const {
        if (value <= 1) return false;
        if (value == 2) return true;
        if (value % 2 == 0) return false;

        int limit = static_cast<int>(sqrt(value));
        for (int i = 3; i <= limit; i += 2) {
            if (value % i == 0) return false;
        }
        return true;
    }
};

int main() {
    PrimeNumber num1 = {17};
    PrimeNumber num2 = {18};

    cout << num1.value << \ простое: " << (num1.isPrime() ? "да" : "нет") << endl;
    cout << num2.value << " простое: " << (num2.isPrime() ? "да" : "нет") << endl;

    return 0;
}"

