struct Rectangle {
    double x, y;
    double width, height;

    bool contains(const Rectangle& other) const {
        return (other.x >= x) &&
               (other.y >= y) &&
               (other.x + other.width <= x + width) &&
               (other.y + other.height <= y + height);
    }
};

