#include <iostream>
#include <cmath>
using namespace std;

struct Triangle {
    double sideA, sideB, sideC;

    double inradius() const {
        double s = (sideA + sideB + sideC) / 2.0;
        double area = sqrt(s * (s - sideA) * (s - sideB) * (s - sideC));
        return area / s;
    }

    double circumradius() const {
        double s = (sideA + sideB + sideC) / 2.0;
        double area = sqrt(s * (s - sideA) * (s - sideB) * (s - sideC));
        return (sideA * sideB * sideC) / (4 * area);
    }
};

int main() {
    Triangle tri = {3, 4, 5};

    cout << \Радиус вписанной окружности: " << tri.inradius() << endl;
    cout << "Радиус описанной окружности: " << tri.circumradius() << endl;

    return 0;
}"

