#include <iostream>
using namespace std;

struct Date {
    int day, month, year;

    bool isLastDayOfMonth() const {
        if (month == 2) {
            bool isLeap = (year % 4 == 0 && year % 100 != 0) || (year % 400 == 0);
            return day == (isLeap ? 29 : 28);
        }
        if (month == 4 || month == 6 || month == 9 || month == 11) {
            return day == 30;
        }
        return day == 31;
    }
};

int main() {
    Date date1 = {31, 12, 2023};
    Date date2 = {28, 2, 2023};

    cout << \date1 последний день месяца: " << (date1.isLastDayOfMonth() ? "да" : "нет") << endl;
    cout << "date2 последний день месяца: " << (date2.isLastDayOfMonth() ? "да" : "нет") << endl;
    return 0;
}"

