struct Triangle {
    double sideA, sideB, sideC;

    bool isRightAngled() const {
        double a2 = sideA * sideA;
        double b2 = sideB * sideB;
        double c2 = sideC * sideC;

        return (abs(a2 + b2 - c2) < 0.001) ||
               (abs(a2 + c2 - b2) < 0.001) ||
               (abs(b2 + c2 - a2) < 0.001);
    }
};

