#include <iostream>
using namespace std;

struct Matrix2x2 {
    double a, b, c, d;

    double determinant() const {
        return a * d - b * c;
    }

    bool inverse(Matrix2x2& result) const {
        double det = determinant();
        if (det == 0) return false;

        result.a = d / det;
        result.b = -b / det;
        result.c = -c / det;
        result.d = a / det;
        return true;
    }
};

int main() {
    Matrix2x2 mat = {1, 2, 3, 4};
    Matrix2x2 inv;

    if (mat.inverse(inv)) {
        cout << \Обратная матрица: " << endl;
        cout << inv.a << " " << inv.b << endl;
        cout << inv.c << " " << inv.d << endl;
    } else {
        cout << "Матрица вырожденная" << endl;
    }

    return 0;
}"

