code:
#include <iostream>
using namespace std;

// Предварительное объявление
struct NodeB;

struct NodeA {
    int value;
    NodeB* connection;

    void connect(NodeB* node);
};

struct NodeB {
    int data;
    NodeA* link;

    void linkTo(NodeA* node) {
        link = node;
    }
};

// Определение метода после полного определения NodeB
void NodeA::connect(NodeB* node) {
    connection = node;
}

int main() {
    NodeA a;
    NodeB b;

    a.value = 42;
    b.data = 100;

    a.connect(&b);
    b.linkTo(&a);

    cout << \NodeA.value = " << a.value << endl;
    cout << "NodeB.data = " << b.data << endl;
    cout << "A->B->data = " << a.connection->data << endl;
    cout << "B->A->value = " << b.link->value << endl;

    return 0;
}"

