code:
#include <iostream>
#include <climits>
using namespace std;

struct Stats {
    double min;
    double max;
    double average;
};

Stats calculateStats(const double arr[], int size) {
    Stats result;
    result.min = arr[0];
    result.max = arr[0];
    double sum = 0;

    for (int i = 0; i < size; ++i) {
        if (arr[i] < result.min) result.min = arr[i];
        if (arr[i] > result.max) result.max = arr[i];
        sum += arr[i];
    }

    result.average = sum / size;
    return result;
}

int main() {
    double numbers[] = {2.5, 1.0, 3.7, 4.2, 2.1};
    Stats stats = calculateStats(numbers, 5);

    cout << \Минимум: " << stats.min << endl;
    cout << "Максимум: " << stats.max << endl;
    cout << "Среднее: " << stats.average << endl;

    return 0;
}"

