#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* next;

    void append(int value) {
        Node* newNode = new Node{value, nullptr};
        Node* current = this;
        while (current->next != nullptr) {
            current = current->next;
        }
        current->next = newNode;
    }

    void printList() const {
        const Node* current = this;
        while (current != nullptr) {
            cout << current->data << \ ";
            current = current->next;
        }
        cout << endl;
    }
};

