struct Triangle {
    double sideA, sideB, sideC;

    string type() const {
        if (sideA == sideB && sideB == sideC) {
            return \Равносторонний";
        } else if (sideA == sideB || sideB == sideC || sideA == sideC) {
            return "Равнобедренный";
        } else {
            return "Разносторонний";
        }
    }

    bool isValid() const {
        return (sideA + sideB > sideC) &&
               (sideA + sideC > sideB) &&
               (sideB + sideC > sideA);
    }
};

