#include <iostream>
using namespace std;

struct ArrayStatistics {
    int positiveCount;
    int negativeCount;
    int zeroCount;
};

ArrayStatistics analyzeArray(const int arr[], int size) {
    ArrayStatistics stats = {0, 0, 0};
    for (int i = 0; i < size; ++i) {
        if (arr[i] > 0) {
            stats.positiveCount++;
        } else if (arr[i] < 0) {
            stats.negativeCount++;
        } else {
            stats.zeroCount++;
        }
    }
    return stats;
}

int main() {
    int numbers[] = {1, -2, 0, 5, -3, 0, 4};
    ArrayStatistics stats = analyzeArray(numbers, 7);

    cout << \Положительных: " << stats.positiveCount << endl;
    cout << "Отрицательных: " << stats.negativeCount << endl;
    cout << "Нулевых: " << stats.zeroCount << endl;

    return 0;
}"

