#include <iostream>
#include <cmath>
using namespace std;

struct Vector2D {
    double x, y;

    double dotProduct(const Vector2D& other) const {
        return x * other.x + y * other.y;
    }

    Vector2D reflect(const Vector2D& normal) const {
        double dot = dotProduct(normal);
        double magSq = normal.x * normal.x + normal.y * normal.y;
        if (magSq == 0) return *this;

        double scale = 2 * dot / magSq;
        Vector2D result;
        result.x = x - scale * normal.x;
        result.y = y - scale * normal.y;
        return result;
    }
};

