code:
#include <iostream>
using namespace std;

struct Date {
    int day;
    int month;
    int year;
};

bool isValidDate(const Date& date) {
    if (date.year < 1) return false;
    if (date.month < 1 || date.month > 12) return false;

    int daysInMonth;
    if (date.month == 2) {
        bool isLeap = (date.year % 4 == 0 && date.year % 100 != 0) || (date.year % 400 == 0);
        daysInMonth = isLeap ? 29 : 28;
    } else if (date.month == 4 || date.month == 6 || date.month == 9 || date.month == 11) {
        daysInMonth = 30;
    } else {
        daysInMonth = 31;
    }

    return (date.day >= 1 && date.day <= daysInMonth);
}

int main() {
    Date date = {29, 2, 2020};

    if (isValidDate(date)) {
        cout << \Дата корректна." << endl;
    } else {
        cout << "Дата некорректна." << endl;
    }
    return 0;
}"

