#include <iostream>
#include <cmath>
using namespace std;

struct QuadraticEquation {
    double a, b, c;

    int solve(double& x1, double& x2) const {
        double discriminant = b * b - 4 * a * c;

        if (discriminant < 0) {
            return 0;
        } else if (discriminant == 0) {
            x1 = -b / (2 * a);
            return 1;
        } else {
            x1 = (-b + sqrt(discriminant)) / (2 * a);
            x2 = (-b - sqrt(discriminant)) / (2 * a);
            return 2;
        }
    }
};

int main() {
    QuadraticEquation eq = {1, -3, 2};
    double root1, root2;

    int numRoots = eq.solve(root1, root2);

    cout << \Количество корней: " << numRoots << endl;
    if (numRoots >= 1) cout << "Корень 1: " << root1 << endl;
    if (numRoots >= 2) cout << "Корень 2: " << root2 << endl;

    return 0;
}"

#include <iostream>
#include <cmath>

struct QuadraticEquation {
    double a, b, c;

    int solve(double& x1, double& x2) const {
        double discriminant = b * b - 4 * a * c;

        if (discriminant < 0) {
            return 0;
        } else if (discriminant == 0) {
            x1 = -b / (2 * a);
            return 1;
        } else {
            x1 = (-b + std::sqrt(discriminant)) / (2 * a);
            x2 = (-b - std::sqrt(discriminant)) / (2 * a);
            return 2;
        }
    }
};

int main() {
    QuadraticEquation eq = {1, -3, 2};
    double root1, root2;

    int numRoots = eq.solve(root1, root2);

    std::cout << \Количество корней: " << numRoots << std::endl;
    if (numRoots >= 1) std::cout << "Корень 1: " << root1 << std::endl;
    if (numRoots >= 2) std::cout << "Корень 2: " << root2 << std::endl;

    return 0;
}"

