#include <iostream>
using namespace std;

struct TimeInterval {
    int startHour, startMinute;
    int endHour, endMinute;

    bool overlaps(const TimeInterval& other) const {
        int thisStart = startHour * 60 + startMinute;
        int thisEnd = endHour * 60 + endMinute;
        int otherStart = other.startHour * 60 + other.startMinute;
        int otherEnd = other.endHour * 60 + other.endMinute;

        return !(thisEnd <= otherStart || thisStart >= otherEnd);
    }
};

int main() {
    TimeInterval interval1 = {9, 0, 12, 0};
    TimeInterval interval2 = {11, 0, 14, 0};
    TimeInterval interval3 = {14, 0, 16, 0};

    cout << \Интервал 1 пересекается с интервалом 2: " 
         << (interval1.overlaps(interval2) ? "да" : "нет") << endl;
    cout << "Интервал 1 пересекается с интервалом 3: " 
         << (interval1.overlaps(interval3) ? "да" : "нет") << endl;

    return 0;
}"

