#include <iostream>
#include <cmath>
using namespace std;

struct GeoCoordinate {
    double latitude;
    double longitude;

    double distanceTo(const GeoCoordinate& other) const {
        const double R = 6371.0;
        double dLat = (other.latitude - latitude) * M_PI / 180.0;
        double dLon = (other.longitude - longitude) * M_PI / 180.0;
        double lat1 = latitude * M_PI / 180.0;
        double lat2 = other.latitude * M_PI / 180.0;

        double a = sin(dLat/2) * sin(dLat/2) +
                   sin(dLon/2) * sin(dLon/2) * cos(lat1) * cos(lat2);
        double c = 2 * atan2(sqrt(a), sqrt(1-a));
        return R * c;
    }
};

int main() {
    GeoCoordinate moscow = {55.7558, 37.6176};
    GeoCoordinate saintPetersburg = {59.9343, 30.3351};

    cout << \Расстояние между Москвой и Санкт-Петербургом: "
         << moscow.distanceTo(saintPetersburg) << " км" << endl;
    return 0;
}"

