#include <iostream>
using namespace std;

struct TreeNode {
    int value;
    TreeNode* left;
    TreeNode* right;

    void insert(int newValue) {
        if (newValue < value) {
            if (left == nullptr) {
                left = new TreeNode{newValue, nullptr, nullptr};
            } else {
                left->insert(newValue);
            }
        } else {
            if (right == nullptr) {
                right = new TreeNode{newValue, nullptr, nullptr};
            } else {
                right->insert(newValue);
            }
        }
    }
};

void printInOrder(TreeNode* node) {
    if (node != nullptr) {
        printInOrder(node->left);
        cout << node->value << \ ";
        printInOrder(node->right);
    }
}

int main() {
    TreeNode* root = new TreeNode{5

topic:
 nullptr};
    root->insert(3);
    root->insert(7);
    root->insert(2);
    root->insert(4);

    cout << "Обход дерева: ";
    printInOrder(root);
    cout << endl;

    delete root->left->left;
    delete root->left->right;
    delete root->left;
    delete root->right;
    delete root;

    return 0;
}"

