#include <iostream>
#include <cmath>
using namespace std;

struct HSLColor {
    double hue;        
    double saturation; 
    double lightness;  
};

struct RGBColor {
    int red, green, blue;
};

RGBColor hslToRgb(const HSLColor& hsl) {
    double c = (1 - abs(2*hsl.lightness - 1)) * hsl.saturation;
    double x = c * (1 - abs(fmod(hsl.hue / 60.0, 2) - 1));
    double m = hsl.lightness - c/2;

    double r, g, b;
    if (hsl.hue < 60) {
        r = c; g = x; b = 0;
    } else if (hsl.hue < 120) {
        r = x; g = c; b = 0;
    } else if (hsl.hue < 180) {
        r = 0; g = c; b = x;
    } else if (hsl.hue < 240) {
        r = 0; g = x; b = c;
    } else if (hsl.hue < 300) {
        r = x; g = 0; b = c;
    } else {
        r = c; g = 0; b = x;
    }

    RGBColor rgb;
    rgb.red = static_cast<int>((r + m) * 255);
    rgb.green = static_cast<int>((g + m) * 255);
    rgb.blue = static_cast<int>((b + m) * 255);
    return rgb;
}

