#include <iostream>
#include <vector>
#include <queue>
#include <set>
#include <map>

class Graph {
    std::map<int, std::vector<int>> adjacencyList;
public:
    void addEdge(int from, int to) {
        adjacencyList[from].push_back(to);
    }
    std::vector<int> getNeighbors(int node) {
        return adjacencyList[node];
    }
    bool hasPath(int start, int end) {
        std::queue<int> q;
        std::set<int> visited;
        q.push(start);
        visited.insert(start);

        while(!q.empty()) {
            int current = q.front();
            q.pop();
            if(current == end) return true;
            for(int neighbor : adjacencyList[current]) {
                if(visited.find(neighbor) == visited.end()) {
                    visited.insert(neighbor);
                    q.push(neighbor);
                }
            }
        }
        return false;
    }
};

int main() {
    Graph g;
    g.addEdge(1, 2);
    g.addEdge(1, 3);
    g.addEdge(2, 4);
    g.addEdge(3, 4);

    std::cout << \Путь от 1 до 4 существует? " << (g.hasPath(1

style:
 4) ? "Да" : "Нет") << std::endl;
    std::cout << "Соседи узла 1: ";
    for (int neighbor : g.getNeighbors(1)) {
        std::cout << neighbor << " ";
    }
    std::cout << std::endl;

    return 0;
}"

