#include <iostream>
#include <memory>
#include <string>
using namespace std;

enum class Color { RED, BLACK };

template<typename T>
class RBTree {
private:
    struct Node {
        T data;
        Color color;
        shared_ptr<Node> left, right, parent;

        Node(T val) : data(val), color(Color::RED), 
                     left(nullptr), right(nullptr), parent(nullptr) {}
    };

    shared_ptr<Node> root;

    void rotateLeft(shared_ptr<Node> x) {
        auto y = x->right;
        x->right = y->left;

        if (y->left != nullptr) {
            y->left->parent = x;
        }

        y->parent = x->parent;

        if (x->parent == nullptr) {
            root = y;
        } else if (x == x->parent->left) {
            x->parent->left = y;
        } else {
            x->parent->right = y;
        }

        y->left = x;
        x->parent = y;
    }

    void rotateRight(shared_ptr<Node> x) {
        auto y = x->left;
        x->left = y->right;

        if (y->right != nullptr) {
            y->right->parent = x;
        }

        y->parent = x->parent;

        if (x->parent == nullptr) {
            root = y;
        } else if (x == x->parent->right) {
            x->parent->right = y;
        } else {
            x->parent->left = y;
        }

        y->right = x;
        x->parent = y;
    }

    void fixInsert(shared_ptr<Node> k) {
        shared_ptr<Node> u;
        while (k->parent != nullptr && k->parent->color == Color::RED) {
            if (k->parent == k->parent->parent->right) {
                u = k->parent->parent->left;
                if (u != nullptr && u->color == Color::RED) {
                    u->color = Color::BLACK;
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    k = k->parent->parent;
                } else {
                    if (k == k->parent->left) {
                        k = k->parent;
                        rotateRight(k);
                    }
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    rotateLeft(k->parent->parent);
                }
            } else {
                u = k->parent->parent->right;
                if (u != nullptr && u->color == Color::RED) {
                    u->color = Color::BLACK;
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    k = k->parent->parent;
                } else {
                    if (k == k->parent->right) {
                        k = k->parent;
                        rotateLeft(k);
                    }
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    rotateRight(k->parent->parent);
                }
            }
            if (k == root) break;
        }
        root->color = Color::BLACK;
    }

    void inorderHelper(shared_ptr<Node> node) {
        if (node != nullptr) {
            inorderHelper(node->left);
            cout << node->data << \(" << (node->color == Color::RED ? "R" : "B") << ") ";
            inorderHelper(node->right);
        }
    }

public:
    RBTree() : root(nullptr) {}

    void insert(T val) {
        auto node = make_shared<Node>(val);

        shared_ptr<Node> y = nullptr;
        auto x = root;

        while (x != nullptr) {
            y = x;
            if (node->data < x->data) {
                x = x->left;
            } else {
                x = x->right;
            }
        }

        node->parent = y;

        if (y == nullptr) {
            root = node;
        } else if (node->data < y->data) {
            y->left = node;
        } else {
            y->right = node;
        }

        if (node->parent == nullptr) {
            node->color = Color::BLACK;
            return;
        }

        if (node->parent->parent == nullptr) {
            return;
        }

        fixInsert(node);
    }

    void printInorder() {
        inorderHelper(root);
        cout << endl;
    }

    bool search(T val) {
        auto current = root;
        while (current != nullptr) {
            if (val == current->data) {
                return true;
            } else if (val < current->data) {
                current = current->left;
            } else {
                current = current->right;
            }
        }
        return false;
    }
};

int main() {
    RBTree<int> tree;

    tree.insert(10);
    tree.insert(20);
    tree.insert(30);
    tree.insert(15);
    tree.insert(25);
    tree.insert(5);
    tree.insert(35);

    cout << "Обход красно-черного дерева: ";
    tree.printInorder();

    cout << "Поиск 25: " << (tree.search(25) ? "Найдено" : "Не найдено") << endl;
    cout << "Поиск 40: " << (tree.search(40) ? "Найдено" : "Не найдено") << endl;

    return 0;
}"

#include <iostream>
#include <memory>
#include <string>

enum class Color { RED, BLACK };

template<typename T>
class RBTree {
private:
    struct Node {
        T data;
        Color color;
        std::shared_ptr<Node> left, right, parent;

        Node(T val) : data(val), color(Color::RED), 
                     left(nullptr), right(nullptr), parent(nullptr) {}
    };

    std::shared_ptr<Node> root;

    void rotateLeft(std::shared_ptr<Node> x) {
        auto y = x->right;
        x->right = y->left;

        if (y->left != nullptr) {
            y->left->parent = x;
        }

        y->parent = x->parent;

        if (x->parent == nullptr) {
            root = y;
        } else if (x == x->parent->left) {
            x->parent->left = y;
        } else {
            x->parent->right = y;
        }

        y->left = x;
        x->parent = y;
    }

    void rotateRight(std::shared_ptr<Node> x) {
        auto y = x->left;
        x->left = y->right;

        if (y->right != nullptr) {
            y->right->parent = x;
        }

        y->parent = x->parent;

        if (x->parent == nullptr) {
            root = y;
        } else if (x == x->parent->right) {
            x->parent->right = y;
        } else {
            x->parent->left = y;
        }

        y->right = x;
        x->parent = y;
    }

    void fixInsert(std::shared_ptr<Node> k) {
        std::shared_ptr<Node> u;
        while (k->parent != nullptr && k->parent->color == Color::RED) {
            if (k->parent == k->parent->parent->right) {
                u = k->parent->parent->left;
                if (u != nullptr && u->color == Color::RED) {
                    u->color = Color::BLACK;
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    k = k->parent->parent;
                } else {
                    if (k == k->parent->left) {
                        k = k->parent;
                        rotateRight(k);
                    }
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    rotateLeft(k->parent->parent);
                }
            } else {
                u = k->parent->parent->right;
                if (u != nullptr && u->color == Color::RED) {
                    u->color = Color::BLACK;
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    k = k->parent->parent;
                } else {
                    if (k == k->parent->right) {
                        k = k->parent;
                        rotateLeft(k);
                    }
                    k->parent->color = Color::BLACK;
                    k->parent->parent->color = Color::RED;
                    rotateRight(k->parent->parent);
                }
            }
            if (k == root) break;
        }
        root->color = Color::BLACK;
    }

    void inorderHelper(std::shared_ptr<Node> node) {
        if (node != nullptr) {
            inorderHelper(node->left);
            std::cout << node->data << \(" << (node->color == Color::RED ? "R" : "B") << ") ";
            inorderHelper(node->right);
        }
    }

public:
    RBTree() : root(nullptr) {}

    void insert(T val) {
        auto node = std::make_shared<Node>(val);

        std::shared_ptr<Node> y = nullptr;
        auto x = root;

        while (x != nullptr) {
            y = x;
            if (node->data < x->data) {
                x = x->left;
            } else {
                x = x->right;
            }
        }

        node->parent = y;

        if (y == nullptr) {
            root = node;
        } else if (node->data < y->data) {
            y->left = node;
        } else {
            y->right = node;
        }

        if (node->parent == nullptr) {
            node->color = Color::BLACK;
            return;
        }

        if (node->parent->parent == nullptr) {
            return;
        }

        fixInsert(node);
    }

    void printInorder() {
        inorderHelper(root);
        std::cout << std::endl;
    }

    bool search(T val) {
        auto current = root;
        while (current != nullptr) {
            if (val == current->data) {
                return true;
            } else if (val < current->data) {
                current = current->left;
            } else {
                current = current->right;
            }
        }
        return false;
    }
};

int main() {
    RBTree<int> tree;

    tree.insert(10);
    tree.insert(20);
    tree.insert(30);
    tree.insert(15);
    tree.insert(25);
    tree.insert(5);
    tree.insert(35);

    std::cout << "Обход красно-черного дерева: ";
    tree.printInorder();

    std::cout << "Поиск 25: " << (tree.search(25) ? "Найдено" : "Не найдено") << std::endl;
    std::cout << "Поиск 40: " << (tree.search(40) ? "Найдено" : "Не найдено") << std::endl;

    return 0;
}"

