#include <iostream>
using namespace std;

union Number {
    int int_val;
    double double_val;
};

int main() {
    Number num;
    bool is_int = true;

    if (is_int) {
        num.int_val = 42;
        cout << \Целое число: " << num.int_val << endl;
    } else {
        num.double_val = 3.14;
        cout << "Дробное число: " << num.double_val << endl;
    }

    cout << "\nДемонстрация перезаписи:" << endl;
    num.int_val = 100;
    cout << "int: " << num.int_val << endl;

    num.double_val = 2.718;
    cout << "double: " << num.double_val << endl;
    cout << "int после double: " << num.int_val << " (мусор)" << endl;

    cout << "\nРазмер union: " << sizeof(Number) << " байт" << endl;

    return 0;
}"

