code:
#include <iostream>
#include <string>
using namespace std;

union Data {
    int intValue;
    double doubleValue;
    char stringValue[20];

    // Конструкторы
    Data() : intValue(0) {}
    Data(int val) : intValue(val) {}
    Data(double val) : doubleValue(val) {}
    Data(const char* str) {
        strncpy(stringValue, str, 19);
        stringValue[19] = '\0';
    }

    // Деструктор не нужен для POD типов
};

int main() {
    Data d1;
    Data d2(42);
    Data d3(3.14);
    Data d4(\Hello");

    cout << "d1.intValue = " << d1.intValue << endl;
    cout << "d2.intValue = " << d2.intValue << endl;
    cout << "d3.doubleValue = " << d3.doubleValue << endl;
    cout << "d4.stringValue = " << d4.stringValue << endl;

    cout << "\nРазмер Data: " << sizeof(Data) << " байт" << endl;

    return 0;
}"

