#include <iostream>
using namespace std;

union NumberParts {
    uint32_t value32;
    uint16_t parts16[2];
    uint8_t parts8[4];
};

int main() {
    NumberParts num;
    num.value32 = 0x12345678;

    cout << \Полное значение: 0x" << hex << num.value32 << dec << endl;
    cout << "\nКак 16-битные части:" << endl;
    cout << "parts16[0] = 0x" << hex << num.parts16[0] << dec << endl;
    cout << "parts16[1] = 0x" << hex << num.parts16[1] << dec << endl;

    cout << "\nКак 8-битные байты:" << endl;
    for (int i = 0; i < 4; i++) {
        cout << "parts8[" << i << "] = 0x" << hex << (int)num.parts8[i] << dec << endl;
    }

    // Изменяем один байт
    num.parts8[1] = 0xFF;
    cout << "\nПосле изменения parts8[1] = 0xFF:" << endl;
    cout << "Новое значение: 0x" << hex << num.value32 << dec << endl;

    cout << "\nРазмер union: " << sizeof(NumberParts) << " байт" << endl;

    return 0;
}"

