#include <iostream>
#include <cstdint>
using namespace std;

union EmbeddedData {
    struct {
        uint16_t temperature;
        uint16_t humidity;
        uint8_t status;
    } sensor;

    struct {
        uint8_t command;
        uint8_t data[5];
    } message;

    uint8_t raw[6];
};

int main() {
    EmbeddedData data;

    data.sensor.temperature = 235;
    data.sensor.humidity = 650;
    data.sensor.status = 0x03;

    cout << \Режим сенсора:" << endl;
    cout << "Температура: " << data.sensor.temperature / 10.0 << "°C" << endl;
    cout << "Влажность: " << data.sensor.humidity / 10.0 << "%" << endl;
    cout << "Сырые байты: ";
    for (int i = 0; i < 6; i++) {
        cout << (int)data.raw[i] << " ";
    }
    cout << endl;

    data.message.command = 0xA1;
    data.message.data[0] = 0x10;

    cout << "\nРежим сообщения:" << endl;
    cout << "Команда: 0x" << hex << (int)data.message.command << dec << endl;

    return 0;
}"

