#include <iostream>
using namespace std;

union StatusRegister {
    uint16_t raw;
    struct {
        uint16_t carry : 1;
        uint16_t zero : 1;
        uint16_t interrupt : 1;
        uint16_t decimal : 1;
        uint16_t break_cmd : 1;
        uint16_t unused : 1;
        uint16_t overflow : 1;
        uint16_t negative : 1;
        uint16_t reserved : 8;
    } flags;
};

int main() {
    StatusRegister sr;
    sr.raw = 0xD5; // Устанавливаем флаги

    cout << \Сырое значение регистра: 0x" << hex << sr.raw << dec << endl;
    cout << "\nФлаги:" << endl;
    cout << "Carry: " << sr.flags.carry << endl;
    cout << "Zero: " << sr.flags.zero << endl;
    cout << "Interrupt: " << sr.flags.interrupt << endl;
    cout << "Decimal: " << sr.flags.decimal << endl;
    cout << "Break: " << sr.flags.break_cmd << endl;
    cout << "Overflow: " << sr.flags.overflow << endl;
    cout << "Negative: " << sr.flags.negative << endl;

    // Модификация через структуру
    sr.flags.carry = 1;
    sr.flags.zero = 0;
    cout << "\nНовое сырое значение: 0x" << hex << sr.raw << dec << endl;

    return 0;
}"

