#include <iostream>
#include <cstring>
#include <cstdint>
#include <arpa/inet.h>
using namespace std;

#pragma pack(push, 1)
union NetworkPacket {
    struct {
        uint8_t dest_mac[6];
        uint8_t src_mac[6];
        uint16_t ethertype;
    } ethernet;

    struct {
        uint8_t version_ihl;
        uint8_t tos;
        uint16_t total_length;
        uint16_t identification;
        uint16_t flags_fragment;
        uint8_t ttl;
        uint8_t protocol;
        uint16_t checksum;
        uint32_t src_ip;
        uint32_t dest_ip;
    } ip;

    uint8_t raw_data[60];
};
#pragma pack(pop)

int main() {
    NetworkPacket packet;
    memset(&packet, 0, sizeof(packet));

    packet.ethernet.ethertype = 0x0800;
    packet.ip.version_ihl = 0x45;
    packet.ip.total_length = htons(60);
    packet.ip.ttl = 64;
    packet.ip.protocol = 6;
    packet.ip.src_ip = 0xC0A80101;
    packet.ip.dest_ip = 0xC0A80102;

    cout << \Размер пакета: " << sizeof(packet) << " байт" << endl;
    cout << "Ethertype: 0x" << hex << packet.ethernet.ethertype << dec << endl;
    cout << "IP версия: " << (packet.ip.version_ihl >> 4) << endl;
    cout << "Протокол: " << (int)packet.ip.protocol << endl;

    return 0;
}"

