#include <iostream>
#include <cstring>
using namespace std;

struct TaggedData {
    enum DataType { INTEGER, DOUBLE, TEXT } type;

    union {
        int int_value;
        double double_value;
        char* text_value;
    };

    TaggedData(int val) : type(INTEGER) { int_value = val; }
    TaggedData(double val) : type(DOUBLE) { double_value = val; }
    TaggedData(const char* text) : type(TEXT) {
        text_value = new char[strlen(text) + 1];
        strcpy(text_value, text);
    }

    ~TaggedData() {
        if (type == TEXT) {
            delete[] text_value;
        }
    }

    TaggedData(const TaggedData& other) : type(other.type) {
        switch (type) {
            case INTEGER: int_value = other.int_value; break;
            case DOUBLE: double_value = other.double_value; break;
            case TEXT: 
                text_value = new char[strlen(other.text_value) + 1];
                strcpy(text_value, other.text_value);
                break;
        }
    }

    void print() const {
        switch (type) {
            case INTEGER: cout << \Integer: " << int_value; break;
            case DOUBLE: cout << "Double: " << double_value; break;
            case TEXT: cout << "Text: \"" << text_value << "\""; break;
        }
        cout << endl;
    }
};

int main() {
    TaggedData data1(42);
    TaggedData data2(3.14159);
    TaggedData data3("Hello World");

    cout << "Данные:" << endl;
    data1.print();
    data2.print();
    data3.print();

    TaggedData data4 = data3;
    cout << "\nСкопированные данные:" << endl;
    data4.print();

    cout << "\nРазмер TaggedData: " << sizeof(TaggedData) << " байт" << endl;

    return 0;
}"

