#include <iostream>
#include <cmath>
using namespace std;

struct Shape {
    enum Type { CIRCLE, RECTANGLE, TRIANGLE } type;

    union {
        struct { double radius; } circle;
        struct { double width, height; } rectangle;
        struct { double a, b, c; } triangle;
    } data;

    Shape(double r) : type(CIRCLE) { data.circle.radius = r; }
    Shape(double w, double h) : type(RECTANGLE) {
        data.rectangle.width = w;
        data.rectangle.height = h;
    }
    Shape(double a, double b, double c) : type(TRIANGLE) {
        data.triangle.a = a;
        data.triangle.b = b;
        data.triangle.c = c;
    }

    double area() const {
        switch (type) {
            case CIRCLE: 
                return M_PI * data.circle.radius * data.circle.radius;
            case RECTANGLE: 
                return data.rectangle.width * data.rectangle.height;
            case TRIANGLE: {
                double p = (data.triangle.a + data.triangle.b + data.triangle.c) / 2;
                return sqrt(p * (p - data.triangle.a) * (p - data.triangle.b) * (p - data.triangle.c));
            }
            default: return 0;
        }
    }

    double perimeter() const {
        switch (type) {
            case CIRCLE: return 2 * M_PI * data.circle.radius;
            case RECTANGLE: return 2 * (data.rectangle.width + data.rectangle.height);
            case TRIANGLE: return data.triangle.a + data.triangle.b + data.triangle.c;
            default: return 0;
        }
    }
};

int main() {
    Shape circle(5.0);
    Shape rectangle(4.0, 6.0);
    Shape triangle(3.0, 4.0, 5.0);

    cout << \Геометрические фигуры:" << endl;
    cout << "\nКруг (радиус=5):" << endl;
    cout << "Площадь: " << circle.area() << endl;
    cout << "Периметр: " << circle.perimeter() << endl;

    cout << "\nПрямоугольник (4x6):" << endl;
    cout << "Площадь: " << rectangle.area() << endl;
    cout << "Периметр: " << rectangle.perimeter() << endl;

    cout << "\nТреугольник (3-4-5):" << endl;
    cout << "Площадь: " << triangle.area() << endl;
    cout << "Периметр: " << triangle.perimeter() << endl;

    cout << "\nРазмер структуры Shape: " << sizeof(Shape) << " байт" << endl;

    return 0;
}"

