#include <iostream>
#include <cstring>
using namespace std;

union ConfigValue {
    int int_val;
    double double_val;
    bool bool_val;
    char str_val[32];
};

struct ConfigEntry {
    enum ValueType { INT, DOUBLE, BOOL, STRING } type;
    char key[32];
    ConfigValue value;

    void serialize(char* buffer) const {
        char* ptr = buffer;

        strcpy(ptr, key);
        ptr += strlen(key) + 1;

        *reinterpret_cast<int*>(ptr) = type;
        ptr += sizeof(int);

        switch (type) {
            case INT:
                *reinterpret_cast<int*>(ptr) = value.int_val;
                ptr += sizeof(int);
                break;
            case DOUBLE:
                *reinterpret_cast<double*>(ptr) = value.double_val;
                ptr += sizeof(double);
                break;
            case BOOL:
                *ptr = value.bool_val ? 1 : 0;
                ptr += 1;
                break;
            case STRING:
                strcpy(ptr, value.str_val);
                ptr += strlen(value.str_val) + 1;
                break;
        }
    }

    void print() const {
        cout << key << \ = ";
        switch (type) {
            case INT: cout << value.int_val; break;
            case DOUBLE: cout << value.double_val; break;
            case BOOL: cout << (value.bool_val ? "true" : "false"); break;
            case STRING: cout << '"' << value.str_val << '"'; break;
        }
        cout << endl;
    }
};

