union AudioSample {
    short int16;
    unsigned short uint16;
    int int32;
    float float32;
    signed char int8;
    unsigned char uint8;
    unsigned char bytes[4];

    AudioSample() : int32(0) {}

    void from_float(float value) {
        float32 = value;
        normalize_to_int16();
        normalize_to_int8();
    }

    void normalize_to_int16() {
        if (float32 >= 1.0f) int16 = 32767;
        else if (float32 <= -1.0f) int16 = -32768;
        else int16 = static_cast<short>(float32 * 32767.0f);
    }

    void normalize_to_int8() {
        if (float32 >= 1.0f) int8 = 127;
        else if (float32 <= -1.0f) int8 = -128;
        else int8 = static_cast<signed char>(float32 * 127.0f);
    }

    void to_uint16() {
        uint16 = static_cast<unsigned short>(int16 + 32768);
    }

    void to_uint8() {
        uint8 = static_cast<unsigned char>(int8 + 128);
    }

    void print_formats() const {
        cout << \Аудио семпл в разных форматах:" << endl;
        cout << "  Float32: " << float32 << endl;
        cout << "  Int32: " << int32 << endl;
        cout << "  Int16: " << int16 << endl;
        cout << "  UInt16: " << uint16 << endl;
        cout << "  Int8: " << (int)int8 << endl;
        cout << "  UInt8: " << (int)uint8 << endl;
        cout << "  Байты: ";
