union WidgetData {
    struct {
        int min_value;
        int max_value;
        int current_value;
    } slider;

    struct {
        char items[5][32];
        int selected_index;
    } dropdown;

    struct {
        char text[128];
        bool multiline;
        int max_length;
    } textbox;

    struct {
        bool checked;
        char label[32];
    } checkbox;
};

struct GUIWidget {
    enum WidgetType { SLIDER, DROPDOWN, TEXTBOX, CHECKBOX } type;
    char id[32];
    WidgetData data;

    void initialize_slider(int min_val, int max_val, int current) {
        type = SLIDER;
        data.slider.min_value = min_val;
        data.slider.max_value = max_val;
        data.slider.current_value = current;
    }

    void initialize_dropdown(const char* items[], int count, int selected) {
        type = DROPDOWN;
        data.dropdown.selected_index = selected;
        for (int i = 0; i < count && i < 5; i++) {
            strncpy(data.dropdown.items[i], items[i], 31);
            data.dropdown.items[i][31] = '\0';
        }
    }

    void print() const {
        cout << \Widget '" << id << "' (";
        switch (type) {
            case SLIDER:
                cout << "Slider): " << data.slider.current_value 
                     << " [" << data.slider.min_value << "-" 
                     << data.slider.max_value << "]";
                break;
            case DROPDOWN:
                cout << "Dropdown): выбрано '" 
                     << data.dropdown.items[data.dropdown.selected_index] << "'";
                break;
            case TEXTBOX:
                cout << "Textbox): \"" << data.textbox.text << "\"";
                break;
            case CHECKBOX:
                cout << "Checkbox): " << (data.checkbox.checked ? "✓ " : "✗ ") 
                     << data.checkbox.label;
                break;
        }
        cout << endl;
    }
};

