#include <iostream>
#include <cmath>
using namespace std;

union Vector3D {
    struct {
        double x, y, z;
    } cartesian;

    struct {
        double radius, theta, phi;
    } spherical;

    struct {
        double rho, phi, z;
    } cylindrical;

    Vector3D(double a = 0, double b = 0, double c = 0, int system = 0) {
        switch (system) {
            case 0: // Декартова
                cartesian.x = a;
                cartesian.y = b;
                cartesian.z = c;
                convert_to_spherical();
                convert_to_cylindrical();
                break;
            case 1: // Сферическая
                spherical.radius = a;
                spherical.theta = b;
                spherical.phi = c;
                convert_to_cartesian_from_spherical();
                convert_to_cylindrical();
                break;
            case 2: // Цилиндрическая
                cylindrical.rho = a;
                cylindrical.phi = b;
                cylindrical.z = c;
                convert_to_cartesian_from_cylindrical();
                convert_to_spherical_from_cartesian();
                break;
        }
    }

    void convert_to_spherical() {
        spherical.radius = sqrt(cartesian.x*cartesian.x + cartesian.y*cartesian.y + cartesian.z*cartesian.z);
        spherical.theta = atan2(sqrt(cartesian.x*cartesian.x + cartesian.y*cartesian.y), cartesian.z);
        spherical.phi = atan2(cartesian.y, cartesian.x);
    }

    void convert_to_cylindrical() {
        cylindrical.rho = sqrt(cartesian.x*cartesian.x + cartesian.y*cartesian.y);
        cylindrical.phi = atan2(cartesian.y, cartesian.x);
        cylindrical.z = cartesian.z;
    }

    void convert_to_cartesian_from_spherical() {
        cartesian.x = spherical.radius * sin(spherical.theta) * cos(spherical.phi);
        cartesian.y = spherical.radius * sin(spherical.theta) * sin(spherical.phi);
        cartesian.z = spherical.radius * cos(spherical.theta);
    }

    void convert_to_cartesian_from_cylindrical() {
        cartesian.x = cylindrical.rho * cos(cylindrical.phi);
        cartesian.y = cylindrical.rho * sin(cylindrical.phi);
        cartesian.z = cylindrical.z;
    }

    void convert_to_spherical_from_cartesian() {
        convert_to_spherical();
    }

    void print(const char* name) const {
        cout << name << \:" << endl;
        cout << "  Декартова: (" << cartesian.x << "

column8:
 z=" << cylindrical.z << ")" << endl;
    }
};

int main() {
    Vector3D v1(1

column13:
 1); // Сферические координаты

    v1.print("Вектор v1");
    cout << endl;
    v2.print("Вектор v2");

    cout << "\nРазмер Vector3D: " << sizeof(Vector3D) << " байт" << endl;

    return 0;
}"

