#include <iostream>
#include <cmath>

union Vector3D {
    struct {
        double x, y, z;
    } cartesian;

    struct {
        double radius, theta, phi;
    } spherical;

    struct {
        double rho, phi, z;
    } cylindrical;

    Vector3D(double a = 0, double b = 0, double c = 0, int system = 0) {
        switch (system) {
            case 0:
                cartesian.x = a;
                cartesian.y = b;
                cartesian.z = c;
                convert_to_spherical();
                convert_to_cylindrical();
                break;
            case 1:
                spherical.radius = a;
                spherical.theta = b;
                spherical.phi = c;
                convert_to_cartesian_from_spherical();
                convert_to_cylindrical();
                break;
            case 2:
                cylindrical.rho = a;
                cylindrical.phi = b;
                cylindrical.z = c;
                convert_to_cartesian_from_cylindrical();
                convert_to_spherical_from_cartesian();
                break;
        }
    }

    void convert_to_spherical() {
        spherical.radius = std::sqrt(cartesian.x*cartesian.x + cartesian.y*cartesian.y + cartesian.z*cartesian.z);
        spherical.theta = std::atan2(std::sqrt(cartesian.x*cartesian.x + cartesian.y*cartesian.y), cartesian.z);
        spherical.phi = std::atan2(cartesian.y, cartesian.x);
    }

    void convert_to_cylindrical() {
        cylindrical.rho = std::sqrt(cartesian.x*cartesian.x + cartesian.y*cartesian.y);
        cylindrical.phi = std::atan2(cartesian.y, cartesian.x);
