#include <iostream>
#include <cmath>
using namespace std;

union Matrix2x2 {
    struct {
        double a11, a12;
        double a21, a22;
    } elements;

    struct {
        double m[2][2];
    } array;

    struct {
        double trace;
        double determinant;
        double angle;
        double scale;
    } properties;

    Matrix2x2(double a = 1, double b = 0, double c = 0, double d = 1) {
        elements.a11 = a;
        elements.a12 = b;
        elements.a21 = c;
        elements.a22 = d;
        update_properties();
    }

    void update_properties() {
        properties.trace = elements.a11 + elements.a22;
        properties.determinant = elements.a11 * elements.a22 - elements.a12 * elements.a21;

        // Для масштаба и угла поворота (для матриц поворота)
        properties.scale = sqrt(elements.a11 * elements.a11 + elements.a21 * elements.a21);
        properties.angle = atan2(elements.a21, elements.a11);
    }

    void set_from_rotation(double angle) {
        elements.a11 = cos(angle);
        elements.a12 = -sin(angle);
        elements.a21 = sin(angle);
        elements.a22 = cos(angle);
        update_properties();
    }

    void set_from_scale(double sx, double sy) {
        elements.a11 = sx;
        elements.a12 = 0;
        elements.a21 = 0;
        elements.a22 = sy;
        update_properties();
    }

    Matrix2x2 multiply(const Matrix2x2& other) const {
        Matrix2x2 result;
        result.elements.a11 = elements.a11 * other.elements.a11 + elements.a12 * other.elements.a21;
        result.elements.a12 = elements.a11 * other.elements.a12 + elements.a12 * other.elements.a22;
        result.elements.a21 = elements.a21 * other.elements.a11 + elements.a22 * other.elements.a21;
        result.elements.a22 = elements.a21 * other.elements.a12 + elements.a22 * other.elements.a22;
        result.update_properties();
        return result;
    }

    void print(const char* name) const {
        cout << name << \:" << endl;
        cout << "  Элементы: [[" << elements.a11 << "

keywords:
 " << elements.a22 << "]]" << endl;
        cout << "  След: " << properties.trace << endl;
        cout << "  Определитель: " << properties.determinant << endl;
        cout << "  Масштаб: " << properties.scale << endl;
        cout << "  Угол: " << properties.angle << " радиан" << endl;
    }
};

