code:
#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

union MoneyAmount {
    struct {
        long long minor_units; // Количество минимальных единиц (копеек, центов)
    } precise;

    struct {
        double amount;
    } floating;

    struct {
        int dollars;
        int cents;
    } usd;

    struct {
        int euros;
        int euro_cents;
    } eur;

    struct {
        int rubles;
        int kopecks;
    } rub;

    MoneyAmount(double amount = 0.0) {
        floating.amount = amount;
        convert_to_precise();
        convert_to_currencies();
    }

    void convert_to_precise() {
        precise.minor_units = static_cast<long long>(round(floating.amount * 100.0));
    }

    void convert_to_currencies() {
        // USD
        usd.dollars = static_cast<int>(floating.amount);
        usd.cents = static_cast<int>(round((floating.amount - usd.dollars) * 100.0));

        // EUR (те же вычисления, разные названия)
        eur.euros = usd.dollars;
        eur.euro_cents = usd.cents;

        // RUB (конвертация по курсу ~90 RUB за 1 USD)
        double rub_amount = floating.amount * 90.0;
        rub.rubles = static_cast<int>(rub_amount);
        rub.kopecks = static_cast<int>(round((rub_amount - rub.rubles) * 100.0));
    }

    void set_usd(int dollars, int cents) {
        usd.dollars = dollars;
        usd.cents = cents;
        floating.amount = dollars + cents / 100.0;
        convert_to_precise();
        convert_to_currencies();
    }

    void set_eur(int euros, int euro_cents) {
        eur.euros = euros;
        eur.euro_cents = euro_cents;
        floating.amount = euros + euro_cents / 100.0;
        convert_to_precise();
        convert_to_currencies();
    }

    void add(const MoneyAmount& other) {
        precise.minor_units += other.precise.minor_units;
        floating.amount = precise.minor_units / 100.0;
        convert_to_currencies();
    }

    void subtract(const MoneyAmount& other) {
        precise.minor_units -= other.precise.minor_units;
