#include <iostream>
#include <cmath>
#include <iomanip>

union MoneyAmount {
    struct {
        long long minor_units;
    } precise;

    struct {
        double amount;
    } floating;

    struct {
        int dollars;
        int cents;
    } usd;

    struct {
        int euros;
        int euro_cents;
    } eur;

    struct {
        int rubles;
        int kopecks;
    } rub;

    MoneyAmount(double amount = 0.0) {
        floating.amount = amount;
        convert_to_precise();
        convert_to_currencies();
    }

    void convert_to_precise() {
        precise.minor_units = static_cast<long long>(std::round(floating.amount * 100.0));
    }

    void convert_to_currencies() {
        usd.dollars = static_cast<int>(floating.amount);
        usd.cents = static_cast<int>(std::round((floating.amount - usd.dollars) * 100.0));

        eur.euros = usd.dollars;
        eur.euro_cents = usd.cents;

        double rub_amount = floating.amount * 90.0;
        rub.rubles = static_cast<int>(rub_amount);
        rub.kopecks = static_cast<int>(std::round((rub_amount - rub.rubles) * 100.0));
    }

    void set_usd(int dollars, int cents) {
        usd.dollars = dollars;
        usd.cents = cents;
        floating.amount = dollars + cents / 100.0;
        convert_to_precise();
        convert_to_currencies();
    }

    void set_eur(int euros, int euro_cents) {
        eur.euros = euros;
        eur.euro_cents = euro_cents;
        floating.amount = euros + euro_cents / 100.0;
        convert_to_precise();
        convert_to_currencies();
    }

    void add(const MoneyAmount& other) {
        precise.minor_units += other.precise.minor_units;
        floating.amount = precise.minor_units / 100.0;
        convert_to_currencies();
    }

    void subtract(const MoneyAmount& other) {
        precise.minor_units -= other.precise.minor_units;
        floating.amount = precise.minor_units / 100.0;
        convert_to_currencies();
    }

    void print() const {
        std::cout << std::fixed << std::setprecision(2);
        std::cout << \Финансовая сумма:" << std::endl;
        std::cout << "  Точно (копейки): " << precise.minor_units << " коп." << std::endl;
        std::cout << "  С плавающей точкой: " << floating.amount << std::endl;
        std::cout << "  USD: $" << usd.dollars << "." << std::setfill('0') << std::setw(2) << usd.cents << std::endl;
        std::cout << "  EUR: €" << eur.euros << "." << std::setfill('0') << std::setw(2) << eur.euro_cents << std::endl;
        std::cout << "  RUB: " << rub.rubles << "

style:
" << std::setfill('0') << std::setw(2) << rub.kopecks << " руб." << std::endl;
        std::cout << std::setfill(' ');
    }
};

int main() {
    std::cout << "Финансовые суммы в разных валютах:" << std::endl;
    std::cout << "===================================" << std::endl;

