            cout << "  >> Система " << (arg.bool_value ? "активна" : "неактивна") << endl;
        }
    }
};

class CommandInterpreter {
private:
    vector<Command> command_history;

public:
    void add_command(const Command& cmd) {
        command_history.push_back(cmd);
    }

    void execute_all() {
        cout << "\nВыполнение всех команд:" << endl;
        cout << "=======================" << endl;
        for (const auto& cmd : command_history) {
            cmd.execute();
        }
    }

    void show_history() const {
        cout << "\nИстория команд:" << endl;
        for (size_t i = 0; i < command_history.size(); i++) {
            cout << i + 1 << ". " << command_history[i].name << endl;
        }
    }
};

