#include <iostream>
#include <cstring>
#include <iomanip>
using namespace std;

#pragma pack(push, 1)
union ProtocolPacket {
    // Заголовок пакета
    struct {
        unsigned char packet_type;
        unsigned short packet_length;
        unsigned int sequence_number;
    } header;

    // Пакет данных
    struct {
        unsigned char type;      // Должно быть 0x01
        unsigned short length;   // Размер данных
        unsigned int seq_num;
        unsigned char data[32];  // Полезная нагрузка
    } data_packet;

    // Пакет подтверждения
    struct {
        unsigned char type;      // Должно быть 0x02
        unsigned short length;   // Всегда 4
        unsigned int ack_number; // Номер подтверждаемого пакета
    } ack_packet;

    // Пакет ошибки
    struct {
        unsigned char type;      // Должно быть 0x03
        unsigned short length;   // Размер сообщения об ошибке
        unsigned int error_code;
        char error_message[32];
    } error_packet;

    // Сырые байты
    unsigned char raw_bytes[64];

    ProtocolPacket() {
        memset(raw_bytes, 0, sizeof(raw_bytes));
    }

    void set_data_packet(unsigned int seq, const char* data) {
        data_packet.type = 0x01;
        data_packet.seq_num = seq;
        strncpy((char*)data_packet.data, data, 31);
        data_packet.length = 4 + (unsigned short)strlen(data) + 1; // header + data + null
    }

    void set_ack_packet(unsigned int ack_num) {
        ack_packet.type = 0x02;
        ack_packet.length = 4;
        ack_packet.ack_number = ack_num;
    }

    void set_error_packet(unsigned int code, const char* message) {
        error_packet.type = 0x03;
        error_packet.error_code = code;
        strncpy(error_packet.error_message, message, 31);
        error_packet.length = 4 + (unsigned short)strlen(message) + 1;
    }

    void print_hex() const {
        cout << \Пакет в hex (" << sizeof(ProtocolPacket) << " байт):" << endl;
        for (int i = 0; i < 32; i++) {
            if (i % 16 == 0) cout << "  " << hex << setw(4) << setfill('0') << i << ": ";
            cout << hex << setw(2) << setfill('0') << (int)raw_bytes[i] << " ";
            if (i % 16 == 15) cout << endl;
        }
        cout << dec << setfill(' ') << endl;
    }

    void print_human() const {
        cout << "Интерпретация пакета:" << endl;

        switch (header.packet_type) {
            case 0x01:
                cout << "  Тип: DATA пакет" << endl;
                cout << "  Длина: " << data_packet.length << " байт" << endl;
                cout << "  Последовательность: " << data_packet.seq_num << endl;
                cout << "  Данные: '" << data_packet.data << "'" << endl;
                break;
            case 0x02:
                cout << "  Тип: ACK пакет" << endl;
                cout << "  Длина: " << ack_packet.length << " байт" << endl;
                cout << "  Подтверждение: " << ack_packet.ack_number << endl;
                break;
            case 0x03:
                cout << "  Тип: ERROR пакет" << endl;
                cout << "  Длина: " << error_packet.length << " байт" << endl;
                cout << "  Код ошибки: " << error_packet.error_code << endl;
                cout << "  Сообщение: '" << error_packet.error_message << "'" << endl;
                break;
            default:
                cout << "  Тип: Неизвестный (0x" << hex << (int)header.packet_type << dec << ")" << endl;
                break;
        }
    }
};
#pragma pack(pop)

int main() {
    cout << "Бинарные протокольные пакеты с разными типами:" << endl;
    cout << "==============================================" << endl;

    ProtocolPacket packet1;
    packet1.set_data_packet(1001

topic:
