code:
#include <iostream>
#include <vector>
#include <cstring>
using namespace std;

const int MAX_VERTICES = 10;

union GraphRepresentation {
    // Матрица смежности
    struct {
        int vertices;
        bool adjacency_matrix[MAX_VERTICES][MAX_VERTICES];
    } adjacency;

    // Список ребер
    struct {
        int vertices;
        int edges;
        struct {
            int from;
            int to;
            int weight;
        } edge_list[MAX_VERTICES * MAX_VERTICES];
    } edge_list;

    // Матрица инцидентности
    struct {
        int vertices;
        int edges;
        bool incidence_matrix[MAX_VERTICES][MAX_VERTICES * MAX_VERTICES];
    } incidence;

    GraphRepresentation(int v = 0) {
        memset(this, 0, sizeof(GraphRepresentation));
        adjacency.vertices = v;
        edge_list.vertices = v;
        incidence.vertices = v;
    }

    void add_edge_adjacency(int from, int to, bool directed = false) {
        if (from >= 0 && from < adjacency.vertices && to >= 0 && to < adjacency.vertices) {
            adjacency.adjacency_matrix[from][to] = true;
            if (!directed) {
                adjacency.adjacency_matrix[to][from] = true;
            }
        }
    }

    void add_edge_list(int from, int to, int weight = 1) {
        if (edge_list.edges < MAX_VERTICES * MAX_VERTICES) {
            edge_list.edge_list[edge_list.edges].from = from;
            edge_list.edge_list[edge_list.edges].to = to;
            edge_list.edge_list[edge_list.edges].weight = weight;
            edge_list.edges++;
        }
    }

    void add_edge_incidence(int from, int to, bool directed = false) {
        if (incidence.edges < MAX_VERTICES * MAX_VERTICES) {
            incidence.incidence_matrix[from][incidence.edges] = 1;
            incidence.incidence_matrix[to][incidence.edges] = directed ? -1 : 1;
            incidence.edges++;
        }
    }

    void print_adjacency() const {
        cout << \Матрица смежности (" << adjacency.vertices << " вершин):" << endl;
        cout << "   ";
        for (int i = 0; i < adjacency.vertices; i++) cout << i << " ";
        cout << endl;

        for (int i = 0; i < adjacency.vertices; i++) {
            cout << i << ": ";
            for (int j = 0; j < adjacency.vertices; j++) {
                cout << adjacency.adjacency_matrix[i][j] << " ";
            }
            cout << endl;
        }
    }

    void print_edge_list() const {
        cout << "Список ребер (" << edge_list.vertices << " вершин

style:
" 
            << edge_list.edges << " ребер):" << endl;
       for (int i = 0; i < edge_list.edges; i++) {
           cout << "  " << edge_list.edge_list[i].from << " -> " 
                << edge_list.edge_list[i].to << " (вес: " 
                << edge_list.edge_list[i].weight << ")" << endl;
       }
