#include <iostream>
#include <ctime>
#include <cstring>
#include <vector>
using namespace std;

union EventData {
    struct {
        int key_code;
        int modifiers;
    } keyboard_event;

    struct {
        int x, y;
        int button;
    } mouse_event;

    struct {
        char message[64];
    } message_event;

    struct {
        int error_code;
        char description[64];
    } error_event;

    struct {
        double value;
        char unit[16];
    } sensor_event;

    unsigned char raw_data[128];
};

struct Event {
    enum EventType { KEYBOARD, MOUSE, MESSAGE, ERROR, SENSOR } type;
    time_t timestamp;
    char source[32];
    EventData data;

    Event(EventType t, const char* src) : type(t) {
        timestamp = time(nullptr);
        strncpy(source, src, 31);
        source[31] = '\0';
        memset(&data, 0, sizeof(data));
    }

    void set_keyboard(int key_code, int modifiers) {
        type = KEYBOARD;
        data.keyboard_event.key_code = key_code;
        data.keyboard_event.modifiers = modifiers;
    }

    void set_mouse(int x, int y, int button) {
        type = MOUSE;
        data.mouse_event.x = x;
        data.mouse_event.y = y;
        data.mouse_event.button = button;
    }

    void set_message(const char* msg) {
        type = MESSAGE;
        strncpy(data.message_event.message, msg, 63);
        data.message_event.message[63] = '\0';
    }

    void set_error(int code, const char* desc) {
        type = ERROR;
        data.error_event.error_code = code;
        strncpy(data.error_event.description, desc, 63);
        data.error_event.description[63] = '\0';
    }

    void set_sensor(double value, const char* unit) {
        type = SENSOR;
        data.sensor_event.value = value;
        strncpy(data.sensor_event.unit, unit, 15);
        data.sensor_event.unit[15] = '\0';
    }

    void print() const {
        char time_str[26];
        ctime_r(&timestamp, time_str);
        time_str[24] = '\0'; // Убираем перевод строки

        cout << \[" << time_str << "] " << source << ": ";

        switch (type) {
            case KEYBOARD:
                cout << "Клавиатура - Код: " << data.keyboard_event.key_code
                     << "

style:
Модификаторы: " << data.keyboard_event.modifiers;
               break;
           case MOUSE:
               cout << "Мышь - X: " << data.mouse_event.x
                    << "

keywords:
 Кнопка: " << data.mouse_event.button;
                break;
            case MESSAGE:
                cout << "Сообщение: '" << data.message_event.message << "'";
                break;
            case ERROR:
                cout << "Ошибка " << data.error_event.error_code
                     << ": " << data.error_event.description;
                break;
            case SENSOR:
                cout << "Датчик: " << data.sensor_event.value
                     << " " << data.sensor_event.unit;
                break;
        }
        cout << endl;
    }
};

class EventLogger {
private:
    vector<Event> events;

public:
    void log_event(const Event& event) {
        events.push_back(event);
    }

    void print_all() const {
        cout << "\nЛог событий (" << events.size() << " событий):" << endl;
        cout << "========================================" << endl;
        for (const auto& event : events) {
            event.print();
        }
    }

    void print_by_type(Event::EventType type) const {
        const char* type_names[] = {"Клавиатура"

column9:
 "Датчик"};
        cout << "\nСобытия типа '" << type_names[type] << "':" << endl;

        int count = 0;
        for (const auto& event : events) {
            if (event.type == type) {
                event.print();
                count++;
            }
        }
        cout << "Всего: " << count << " событий" << endl;
    }

    void clear() {
        events.clear();
    }
};

int main() {
    EventLogger logger;

    // Логируем разные события
    Event e1(Event::KEYBOARD

column19:
 "°C");

    logger.log_event(e1);
    logger.log_event(e2);
    logger.log_event(e3);
    logger.log_event(e4);
    logger.log_event(e5);

    logger.print_all();
    logger.print_by_type(Event::KEYBOARD);
    logger.print_by_type(Event::ERROR);

    cout << "\nРазмер Event: " << sizeof(Event) << " байт" << endl;
    cout << "Размер EventData: " << sizeof(EventData) << " байт" << endl;

    return 0;
}"

