#include <iostream>
#include <bitset>
using namespace std;

union PermissionSet {
    struct {
        unsigned int read : 1;
        unsigned int write : 1;
        unsigned int execute : 1;
        unsigned int delete_perm : 1;
        unsigned int share : 1;
        unsigned int modify : 1;
        unsigned int admin : 1;
        unsigned int owner : 1;
        unsigned int reserved : 24;
    } flags;

    unsigned int bitmask;

    PermissionSet(unsigned int mask = 0) : bitmask(mask) {
        // Автоматически разбираем битовую маску в структуру
    }

    void set_permission(const char* perm_name, bool value) {
        if (strcmp(perm_name, ead") == 0) flags.read = value;
        else if (strcmp(perm_name

column9:
"owner") == 0) flags.owner = value;

       update_bitmask();
   }

   bool check_permission(const char* perm_name) const {
       if (strcmp(perm_name

column17:
 "owner") == 0) return flags.owner;
        return false;
    }

    void update_bitmask() {
        // Копируем биты из структуры в bitmask
        bitmask = 0;
        bitmask |= (flags.read << 0);
        bitmask |= (flags.write << 1);
        bitmask |= (flags.execute << 2);
        bitmask |= (flags.delete_perm << 3);
        bitmask |= (flags.share << 4);
        bitmask |= (flags.modify << 5);
        bitmask |= (flags.admin << 6);
        bitmask |= (flags.owner << 7);
    }

    void update_flags_from_bitmask() {
        // Обновляем структуру из bitmask
        flags.read = (bitmask >> 0) & 1;
        flags.write = (bitmask >> 1) & 1;
        flags.execute = (bitmask >> 2) & 1;
        flags.delete_perm = (bitmask >> 3) & 1;
        flags.share = (bitmask >> 4) & 1;
        flags.modify = (bitmask >> 5) & 1;
        flags.admin = (bitmask >> 6) & 1;
        flags.owner = (bitmask >> 7) & 1;
    }

    void print() const {
        cout << "Права доступа (битовая маска: 0x" << hex << bitmask 
             << dec << " или " << bitset<32>(bitmask) << "):" << endl;
        cout << "  Read:      " << (flags.read ? "✓" : "✗") << endl;
        cout << "  Write:     " << (flags.write ? "✓" : "✗") << endl;
        cout << "  Execute:   " << (flags.execute ? "✓" : "✗") << endl;
        cout << "  Delete:    " << (flags.delete_perm ? "✓" : "✗") << endl;
        cout << "  Share:     " << (flags.share ? "✓" : "✗") << endl;
        cout << "  Modify:    " << (flags.modify ? "✓" : "✗") << endl;
        cout << "  Admin:     " << (flags.admin ? "✓" : "✗") << endl;
        cout << "  Owner:     " << (flags.owner ? "✓" : "✗") << endl;
    }

    PermissionSet combine(const PermissionSet& other) const {
        PermissionSet result;
        result.bitmask = bitmask | other.bitmask;
        result.update_flags_from_bitmask();
        return result;
    }

    PermissionSet intersect(const PermissionSet& other) const {
        PermissionSet result;
        result.bitmask = bitmask & other.bitmask;
        result.update_flags_from_bitmask();
        return result;
    }
};

