using namespace std;

enum TaskStatus { PENDING, IN_PROGRESS, COMPLETED };

int main() {
    TaskStatus task1 = PENDING;
    TaskStatus task2 = COMPLETED;

    cout << \Задача 1: " << task1 << endl;
    cout << "Задача 2: " << task2 << endl;

    if (task1 != task2) {
        cout << "Задачи имеют разный статус" << endl;
    }

