#include <iostream>
using namespace std;

enum ErrorCode {
 SUCCESS = 0,
 FILE_NOT_FOUND = 10,
 PERMISSION_DENIED = 20,
 INVALID_DATA = 30,
 TIMEOUT = 40,
 UNKNOWN_ERROR = 99
};

void printErrorIfInRange(int code) {
 if (code >= FILE_NOT_FOUND && code <= TIMEOUT) {
 cout << \Код ошибки в ожидаемом диапазоне: " << code << endl;
 } else {
 cout << "Код ошибки вне диапазона: " << code << endl;
 }
}

int main() {
 printErrorIfInRange(FILE_NOT_FOUND);
 printErrorIfInRange(SUCCESS);
 printErrorIfInRange(25);
 printErrorIfInRange(UNKNOWN_ERROR);
 return 0;
}"

