#include <iostream>
using namespace std;

enum ShapeType {
 CIRCLE,
 RECTANGLE,
 TRIANGLE
};

struct Shape {
 ShapeType type;
 double dimension1;
 double dimension2;
};

double calculateArea(const Shape& s) {
 switch(s.type) {
 case CIRCLE:
 return 3.14159 * s.dimension1 * s.dimension1;
 case RECTANGLE:
 return s.dimension1 * s.dimension2;
 case TRIANGLE:
 return 0.5 * s.dimension1 * s.dimension2;
 default:
 return 0.0;
 }
}

int main() {
 Shape circle = {CIRCLE, 5.0, 0.0};
 Shape rectangle = {RECTANGLE, 4.0, 6.0};
 cout << \Площадь круга: " << calculateArea(circle) << endl;
 cout << "Площадь прямоугольника: " << calculateArea(rectangle) << endl;
 return 0;
}"

