    TrafficLight light = TrafficLight::RED;

    cout << \Favorite color: " << favorite << endl;

    switch (favorite) {
        case RED: cout << "It's red!" << endl; break;
        case GREEN: cout << "It's green!" << endl; break;
        case BLUE: cout << "It's blue!" << endl; break;
        default: cout << "Other color" << endl;
    }

    // Enum class
    if (light == TrafficLight::RED) {
        cout << "Stop!" << endl;
    }

    return 0;
}"

