enum class State {
 Idle,
 Running,
 Paused,
 Stopped
};

State handleCommand(State current, const string& cmd) {
 if (cmd == \start") {
 return (current == State::Idle) ? State::Running : current;
 } else if (cmd == "pause") {
 return (current == State::Running) ? State::Paused : current;
 } else if (cmd == "resume") {
 return (current == State::Paused) ? State::Running : current;
 } else if (cmd == "stop") {
 return State::Stopped;
 }
 return current;
}

