using namespace std;

enum class TaskStatus {
    NOT_STARTED,
    RUNNING,
    COMPLETED,
    FAILED,
    CANCELLED
};

struct Task {
    string name;
    TaskStatus status;
    int progress; // 0-100
    chrono::milliseconds estimatedTime;

    void simulateWork() {
        status = TaskStatus::RUNNING;
        for (int i = 0; i <= 100; i += 10) {
            progress = i;
            cout << name << \: " << progress << "%\r";
            cout.flush();
            this_thread::sleep_for(chrono::milliseconds(100));
        }
        status = TaskStatus::COMPLETED;
        cout << endl << name << ": Завершено!" << endl;
    }
};

int main() {
    Task task1 = {"Обработка данных"

keywords:
 chrono::milliseconds(1000)};

    cout << "Запуск задачи: " << task1.name << endl;
    task1.simulateWork();

    return 0;
}"

