    std::string name;
    TaskStatus status;
    int progress;
    std::chrono::milliseconds estimatedTime;

    void simulateWork() {
        status = TaskStatus::RUNNING;
        for (int i = 0; i <= 100; i += 10) {
            progress = i;
            std::cout << name << \: " << progress << "%\r";
            std::cout.flush();
            std::this_thread::sleep_for(std::chrono::milliseconds(100));
        }
        status = TaskStatus::COMPLETED;
        std::cout << std::endl << name << ": Завершено!" << std::endl;
    }
};

int main() {
    Task task1 = {"Обработка данных"

keywords:
 std::chrono::milliseconds(1000)};

    std::cout << "Запуск задачи: " << task1.name << std::endl;
    task1.simulateWork();

    return 0;
}"

