#include <iostream>
using namespace std;

enum DeviceConfig {
 CONFIG_NONE = 0,
 CONFIG_ENABLED = 1 << 0,
 CONFIG_AUTO_START = 1 << 1,
 CONFIG_LOG_ENABLED = 1 << 2,
 CONFIG_MODE_MASK = 0xF0, // Маска для режима работы
 CONFIG_MODE_LOW = 0x10, // Низкий режим
 CONFIG_MODE_MEDIUM = 0x20, // Средний режим
 CONFIG_MODE_HIGH = 0x40 // Высокий режим
};

void printConfig(int config) {
 cout << \Конфигурация: 0x" << hex << config << dec << endl;

 if (config & CONFIG_ENABLED) cout << "- Устройство включено" << endl;
 if (config & CONFIG_AUTO_START) cout << "- Автозапуск активен" << endl;
 if (config & CONFIG_LOG_ENABLED) cout << "- Логирование включено" << endl;

 int mode = config & CONFIG_MODE_MASK;
 switch(mode) {
 case CONFIG_MODE_LOW: cout << "- Режим: Низкий" << endl; break;
 case CONFIG_MODE_MEDIUM: cout << "- Режим: Средний" << endl; break;
 case CONFIG_MODE_HIGH: cout << "- Режим: Высокий" << endl; break;
 default: cout << "- Режим: Не задан" << endl; break;
 }
}

int main() {
 int config1 = CONFIG_ENABLED | CONFIG_AUTO_START | CONFIG_MODE_HIGH;
 int config2 = CONFIG_ENABLED | CONFIG_LOG_ENABLED | CONFIG_MODE_MEDIUM;

 cout << "=== Конфигурация 1 ===" << endl;
 printConfig(config1);

 cout << "\n=== Конфигурация 2 ===" << endl;
 printConfig(config2);

 return 0;
}"

