#include <string>
using namespace std;

enum class DataType { INTEGER, FLOAT, STRING, BOOLEAN };

bool validateData(const string& input, DataType expectedType) {
    switch(expectedType) {
        case DataType::INTEGER:
            for (char c : input) {
                if (!isdigit(c) && c != '-') return false;
            }
            return true;

        case DataType::FLOAT:
            bool hasDot = false;
            for (char c : input) {
                if (!isdigit(c)) {
                    if (c == '.' && !hasDot) {
                        hasDot = true;
                    } else if (c != '-') {
                        return false;
                    }
                }
            }
            return hasDot;

        case DataType::BOOLEAN:
            return (input == 	rue" || input == "false" || 
                    input == "1" || input == "0");

        case DataType::STRING:
            return true; // Всегда валидно для строк
    }
    return false;
}

