#include <iostream>
#include <cstring>
using namespace std;

enum class PacketType : uint8_t {
    HANDSHAKE,
    DATA,
    ACK,
    ERROR,
    HEARTBEAT
};

struct NetworkPacket {
    PacketType type;
    uint16_t size;
    uint32_t sequence;
    char data[100];

    void serialize(char* buffer) const {
        memcpy(buffer, &type, sizeof(type));
        memcpy(buffer + sizeof(type), &size, sizeof(size));
        memcpy(buffer + sizeof(type) + sizeof(size), &sequence, sizeof(sequence));
        memcpy(buffer + sizeof(type) + sizeof(size) + sizeof(sequence), data, size);
    }

    static NetworkPacket deserialize(const char* buffer) {
        NetworkPacket packet;
        memcpy(&packet.type, buffer, sizeof(packet.type));
        memcpy(&packet.size, buffer + sizeof(packet.type), sizeof(packet.size));
        memcpy(&packet.sequence, buffer + sizeof(packet.type) + sizeof(packet.size), sizeof(packet.sequence));
        memcpy(packet.data, buffer + sizeof(packet.type) + sizeof(packet.size) + sizeof(packet.sequence), packet.size);
        return packet;
    }

    void print() const {
        cout << \Тип пакета: " << static_cast<int>(type) << endl;
        cout << "Размер: " << size << " байт" << endl;
        cout << "Последовательность: " << sequence << endl;
        cout << "Данные: " << data << endl;
    }
};

int main() {
    NetworkPacket original = {PacketType::DATA

keywords:
 "Hello"};

    char buffer[200];
    original.serialize(buffer);

    NetworkPacket restored = NetworkPacket::deserialize(buffer);

    cout << "Оригинальный пакет:" << endl;
    original.print();

    cout << "\nВосстановленный пакет:" << endl;
    restored.print();

    return 0;
}"

