#include <iostream>
#include <string>
#include <ctime>
using namespace std;

class Cache {
    mutable string cachedValue;
    mutable bool isValid;
    string computeValue() const {
        return \Computed at: " + to_string(time(nullptr));
    }
public:
    Cache() : isValid(false) {}
    string getValue() const {
        if(!isValid) {
            cachedValue = computeValue();
            isValid = true;
            cout << "Value computed and cached" << endl;
        }
        return cachedValue;
    }
    void invalidate() const { isValid = false; }
};

int main() {
    const Cache cache;
    cout << cache.getValue() << endl;
    cout << cache.getValue() << endl;
    cache.invalidate();
    cout << cache.getValue() << endl;
    return 0;
}"

