#include <iostream>
using namespace std;

class Variant {
    enum class Type { INT, DOUBLE, CHAR } type;
    union {
        int intValue;
        double doubleValue;
        char charValue;
    };
public:
    Variant(int value) : type(Type::INT) { intValue = value; }
    Variant(double value) : type(Type::DOUBLE) { doubleValue = value; }
    Variant(char value) : type(Type::CHAR) { charValue = value; }
    void display() const {
        switch(type) {
            case Type::INT: cout << \int: " << intValue; break;
            case Type::DOUBLE: cout << "double: " << doubleValue; break;
            case Type::CHAR: cout << "char: " << charValue; break;
        }
        cout << endl;
    }
};

int main() {
    Variant v1(42);
    Variant v2(3.14);
    Variant v3('X');
    v1.display();
    v2.display();
    v3.display();
    return 0;
}"

