#include <iostream>
using namespace std;

class Number {
    enum { INT, DOUBLE } type;
    union {
        int i;
        double d;
    };
public:
    Number(int value) : type(INT), i(value) {}
    Number(double value) : type(DOUBLE), d(value) {}
    bool isInt() const { return type == INT; }
    bool isDouble() const { return type == DOUBLE; }
    friend ostream& operator<<(ostream& os, const Number& num) {
        if(num.isInt()) os << num.i;
        else os << num.d;
        return os;
    }
};

int main() {
    Number n1(42);
    Number n2(3.14159);
    cout << 
1: " << n1 << " (int: " << n1.isInt() << ")" << endl;
    cout << "n2: " << n2 << " (double: " << n2.isDouble() << ")" << endl;
    return 0;
}"

