#include <iostream>
#include <string>
using namespace std;

class SmartHomeDevice {
    string deviceName, room, deviceType;
    bool isOn, isConnected;
    double powerConsumption;
public:
    SmartHomeDevice(string name, string rm, string type, double power) : deviceName(name), room(rm), deviceType(type), isOn(false), isConnected(true), powerConsumption(power) {}
    void turnOn() {
        isOn = true;
    }
    void turnOff() {
        isOn = false;
    }
    void disconnect() {
        isConnected = false;
        isOn = false;
    }
    void displayDevice() {
        cout << deviceName << \ (" << deviceType << ") in " << room << endl;
        cout << "Status: " << (isOn ? "ON" : "OFF") << endl;
        cout << "Connected: " << (isConnected ? "Yes" : "No") << endl;
        cout << "Power: " << powerConsumption << "W" << endl;
    }
    bool isEnergyEfficient() {
        return powerConsumption < 50.0;
    }
    double getDailyConsumption(int hours) {
        return isOn ? powerConsumption * hours / 1000.0 : 0;
    }
};

int main() {
    SmartHomeDevice light("Living Room Light"

