#include <iostream>
#include <string>
using namespace std;

class SecuritySystem {
    string systemName, location;
    bool isArmed, isAlarmTriggered;
    int securityLevel;
public:
    SecuritySystem(string name, string loc) : systemName(name), location(loc), isArmed(false), isAlarmTriggered(false), securityLevel(1) {}
    void armSystem() {
        isArmed = true;
        isAlarmTriggered = false;
    }
    void disarmSystem() {
        isArmed = false;
        isAlarmTriggered = false;
    }
    void triggerAlarm() {
        if(isArmed) isAlarmTriggered = true;
    }
    void displayStatus() {
        cout << \Security System: " << systemName << " at " << location << endl;
        cout << "Armed: " << (isArmed ? "Yes" : "No") << endl;
        cout << "Alarm: " << (isAlarmTriggered ? "TRIGGERED" : "Normal") << endl;
        cout << "Security Level: " << securityLevel << endl;
    }
    bool isHighSecurity() {
        return securityLevel >= 3;
    }
    void increaseSecurityLevel() {
        if(securityLevel < 5) securityLevel++;
    }
};

int main() {
    SecuritySystem system("HomeGuard"

