 auto course = findCourseByCode(gradePair.first);
 if(course) {
 totalPoints += gradePair.second * course->credits;
 totalCredits += course->credits;
 }
 }

 if(totalCredits > 0) {
 student->gpa = totalPoints / totalCredits;
 }
 }

