class CycleCounter {
    int count;
public:
    CycleCounter() : count(0) {}
    void tick() { 
        count++; 
        cout << \Tick! Count: " << count << endl;
    }
    void reset() {
        count = 0;
        cout << "Counter reset" << endl;
    }
    int getCount() const { 
        return count; 
    }
};

int main() {
    CycleCounter counter;
    counter.tick();
    counter.tick();
    cout << "Current count: " << counter.getCount() << endl;
    counter.reset();
    cout << "After reset: " << counter.getCount() << endl;
    return 0;
}"

