class MemoryInfo {
public:
    long total, used;
    MemoryInfo(long t, long u) : total(t), used(u) {}
    void display() const {
        cout << \Memory: " << used << "MB used / " << total << "MB total" << endl;
    }
    long free() const {
        return total - used;
    }
    double usagePercentage() const {
        return (static_cast<double>(used) / total) * 100.0;
    }
};

