#include <iostream>
#include <utility>
#include <cstddef>

class RuleOfFive {
    int* data;
    std::size_t size;
public:
    explicit RuleOfFive(std::size_t s = 0) : size(s) {
        data = (s > 0) ? new int[s] : nullptr;
        std::cout << \Default constructor" << std::endl;
    }
    ~RuleOfFive() { // 1. Деструктор
        delete[] data;
        std::cout << "Destructor" << std::endl;
    }
    RuleOfFive(const RuleOfFive& other) : size(other.size) { // 2. Конструктор копирования
        data = (size > 0) ? new int[size] : nullptr;
        for(std::size_t i = 0; i < size; i++) data[i] = other.data[i];
        std::cout << "Copy constructor" << std::endl;
    }
    RuleOfFive& operator=(const RuleOfFive& other) { // 3. Копирующее присваивание
        if(this != &other) {
            delete[] data;
            size = other.size;
            data = (size > 0) ? new int[size] : nullptr;
            for(std::size_t i = 0; i < size; i++) data[i] = other.data[i];
        }
        std::cout << "Copy assignment" << std::endl;
        return *this;
    }
    RuleOfFive(RuleOfFive&& other) noexcept : data(other.data)

style:
 size(other.size) { // 4. Конструктор перемещения
        other.data = nullptr;
        other.size = 0;
        std::cout << "Move constructor" << std::endl;
    }
    RuleOfFive& operator=(RuleOfFive&& other) noexcept { // 5. Перемещающее присваивание
        if(this != &other) {
            delete[] data;
            data = other.data;
            size = other.size;
            other.data = nullptr;
            other.size = 0;
        }
        std::cout << "Move assignment" << std::endl;
        return *this;
    }
};

int main() {
    RuleOfFive obj1(5);
    RuleOfFive obj2 = obj1; // Конструктор копирования
    RuleOfFive obj3(3);
    obj3 = obj1; // Копирующее присваивание
    RuleOfFive obj4 = std::move(obj1); // Конструктор перемещения
    RuleOfFive obj5(2);
    obj5 = std::move(obj2); // Перемещающее присваивание
    return 0;
}"

