#include <iostream>
#include <vector>
#include <utility>
using namespace std;

class Resource {
private:
    vector<int> data;

public:
    Resource(size_t size) : data(size) {
        cout << \Конструктор: выделено " << size << " элементов" << endl;
    }

    // Конструктор перемещения
    Resource(Resource&& other) noexcept : data(move(other.data)) {
        cout << "Конструктор перемещения" << endl;
    }

    // Оператор перемещения
    Resource& operator=(Resource&& other) noexcept {
        cout << "Оператор перемещения" << endl;
        if (this != &other) {
            data = move(other.data);
        }
        return *this;
    }

    // Запрещаем копирование
    Resource(const Resource&) = delete;
    Resource& operator=(const Resource&) = delete;

    void print() const {
        cout << "Размер данных: " << data.size() << endl;
    }
};

Resource createResource() {
    return Resource(1000); // RVO/move semantics
}

int main() {
    cout << "Создание ресурса 1..." << endl;
    Resource res1(1000);

    cout << "\nСоздание ресурса 2 через перемещение..." << endl;
    Resource res2 = move(res1);

    cout << "\nРесурс 1 после перемещения:" << endl;
    res1.print();

    cout << "\nРесурс 2 после перемещения:" << endl;
    res2.print();

    cout << "\nСоздание ресурса через функцию..." << endl;
    Resource res3 = createResource();

    return 0;
}"

