#include <iostream>
using namespace std;

class Animal {
public:
    virtual Animal* clone() const {
        return new Animal(*this);
    }
    virtual void speak() const {
        cout << \Animal sound" << endl;
    }
    virtual ~Animal() = default;
};

class Dog : public Animal {
public:
    Dog* clone() const override {
        return new Dog(*this);
    }
    void speak() const override {
        cout << "Woof!" << endl;
    }
};

int main() {
    Dog dog;
    Animal* animal = &dog;
    Dog* clonedDog = dog.clone();
    Animal* clonedAnimal = animal->clone();
    clonedDog->speak();
    clonedAnimal->speak();
    delete clonedDog;
    delete clonedAnimal;
    return 0;
}"

