class Any {
    struct Base {
        virtual ~Base() = default;
        virtual std::unique_ptr<Base> clone() = 0;
    };
    template<typename T>
    struct Derived : Base {
        T value;
        Derived(const T& v) : value(v) {}
        std::unique_ptr<Base> clone() override {
            return std::make_unique<Derived<T>>(value);
        }
    };
    std::unique_ptr<Base> ptr;
public:
    template<typename T>
    Any(const T& value) : ptr(std::make_unique<Derived<T>>(value)) {}
    Any(const Any& other) : ptr(other.ptr->clone()) {}
};

int main() {
    Any a1 = 42;
    Any a2 = std::string(\Hello");
    Any a3 = a1;
    return 0;
}"

#include <iostream>
using namespace std;

class Shape {
public:
    virtual double area() = 0; // Чисто виртуальная функция
    virtual ~Shape() {}
};

class Circle : public Shape {
private:
    double radius;

public:
    Circle(double r) : radius(r) {}

    double area() override {
        return 3.14159 * radius * radius;
    }
};

class Rectangle : public Shape {
private:
    double width, height;

public:
    Rectangle(double w, double h) : width(w), height(h) {}

    double area() override {
        return width * height;
    }
};

