    shapes[0] = new Circle(5.0);
    shapes[1] = new Rectangle(4.0, 6.0);

    for (int i = 0; i < 2; i++) {
        cout << \Площадь фигуры " << i + 1 << ": " << shapes[i]->area() << endl;
        delete shapes[i];
    }

    return 0;
}"

