#include <iostream>
using namespace std;

class BankAccount {
private:
 string ownerName;
 double balance;
public:
 BankAccount(string name, double initialBalance) {
 ownerName = name;
 if(initialBalance >= 0) balance = initialBalance;
 else balance = 0;
 }
 double getBalance() const { return balance; }
 void deposit(double amount) {
 if(amount > 0) balance += amount;
 }
 bool withdraw(double amount) {
 if(amount > 0 && amount <= balance) {
 balance -= amount;
 return true;
 }
 return false;
 }
};

int main() {
 BankAccount acc(\Alice"

style:
 1000.0);
 acc.deposit(500.0);
 cout << "Balance after deposit: " << acc.getBalance() << endl;
 if(acc.withdraw(200.0)) {
 cout << "Withdrawal successful. New balance: " << acc.getBalance() << endl;
 }
 return 0;
}"

