 for(int i = 0; i < size; i++) data[i] = other.data[i];
 }
 MyArray& operator=(const MyArray& other) { // Оператор присваивания
 if(this != &other) {
 delete[] data;
 size = other.size;
 data = new int[size];
 for(int i = 0; i < size; i++) data[i] = other.data[i];
 }
 return *this;
 }
 ~MyArray() { delete[] data; }
 void setValue(int index, int value) { data[index] = value; }
 int getValue(int index) const { return data[index]; }
};

int main() {
 MyArray a1(3);
 a1.setValue(0, 10); a1.setValue(1, 20); a1.setValue(2, 30);
 MyArray a2(1);
 a2 = a1; // Использование оператора присваивания
 std::cout << \a2[0] = " << a2.getValue(0) << std::endl;
 return 0;
}"

#include <iostream>
using namespace std;

class Fraction {
 int numerator, denominator;
public:
 Fraction(int n, int d) : numerator(n), denominator(d) {}
 double value() const { return static_cast<double>(numerator) / denominator; }
 bool operator==(const Fraction& other) const {
 return value() == other.value();
 }
 bool operator!=(const Fraction& other) const {
 return !(*this == other);
 }
 bool operator<(const Fraction& other) const {
 return value() < other.value();
 }
 bool operator>(const Fraction& other) const {
 return value() > other.value();
 }
 bool operator<=(const Fraction& other) const {
 return value() <= other.value();
 }
 bool operator>=(const Fraction& other) const {
 return value() >= other.value();
 }
};

int main() {
 Fraction f1(1, 2), f2(2, 4), f3(3, 4);
 cout << boolalpha;
 cout <<  1 == f2: " << (f1 == f2) << endl;
 cout << "f1 != f3: " << (f1 != f3) << endl;
 cout << "f1 < f3: " << (f1 < f3) << endl;
 cout << "f3 > f1: " << (f3 > f1) << endl;
 return 0;
}"

