#include <iostream>
#include <string>

class Resource {
 std::string name;
public:
 Resource(const std::string& n) : name(n) {
 std::cout << \Resource " << name << " created" << std::endl;
 }
 ~Resource() {
 std::cout << "Resource " << name << " destroyed" << std::endl;
 }
 void use() const {
 std::cout << "Using resource " << name << std::endl;
 }
 void setName(const std::string& n) {
 name = n;
 std::cout << "Resource renamed to " << name << std::endl;
 }
};

class SmartPointer {
 Resource* ptr;
public:
 SmartPointer(Resource* p = nullptr) : ptr(p) {}
 ~SmartPointer() {
 delete ptr;
 }
 // Запрещаем копирование
 SmartPointer(const SmartPointer&) = delete;
 SmartPointer& operator=(const SmartPointer&) = delete;
 // Разрешаем перемещение
 SmartPointer(SmartPointer&& other) noexcept : ptr(other.ptr) {
 other.ptr = nullptr;
 }
 SmartPointer& operator=(SmartPointer&& other) noexcept {
 if(this != &other) {
 delete ptr;
 ptr = other.ptr;
 other.ptr = nullptr;
 }
 return *this;
 }
 // Оператор ->
 Resource* operator->() {
 return ptr;
 }
 Resource& operator*() {
 return *ptr;
 }
 explicit operator bool() const {
 return ptr != nullptr;
 }
};

int main() {
 SmartPointer sp(new Resource("Database"));
 if(sp) {
 sp->use(); // Использование ->
 sp->setName("NewDB");
 (*sp).use(); // Использование *
 }
 return 0;
}"

