using namespace std;

class Celsius {
 double temperature;
public:
 Celsius(double temp) : temperature(temp) {}
 double getTemp() const { return temperature; }
};

class Fahrenheit {
 double temperature;
public:
 Fahrenheit(double temp) : temperature(temp) {}
 // Оператор преобразования в Celsius
 operator Celsius() const {
 return Celsius((temperature - 32) * 5.0 / 9.0);
 }
 double getTemp() const { return temperature; }
};

class Kelvin {
 double temperature;
public:
 Kelvin(double temp) : temperature(temp) {}
 // Явное преобразование из Celsius
 explicit Kelvin(const Celsius& c) : temperature(c.getTemp() + 273.15) {}
 double getTemp() const { return temperature; }
};

