 Fahrenheit f(100); // 100°F
 Celsius c = f; // Неявное преобразование через operator Celsius()
 // Kelvin k = c; // Ошибка: преобразование явное
 Kelvin k = Kelvin(c); // Явное преобразование
 cout << f.getTemp() << \°F = " << c.getTemp() << "°C = " << k.getTemp() << "K" << endl;
 return 0;
}"

