#include <iostream>
#include <iomanip>
using namespace std;

class Time {
 int hours, minutes, seconds;
 void normalize() {
 minutes += seconds / 60;
 seconds %= 60;
 hours += minutes / 60;
 minutes %= 60;
 hours %= 24;
 }
public:
 Time(int h = 0, int m = 0, int s = 0) : hours(h), minutes(m), seconds(s) {
 normalize();
 }
 // Префиксный инкремент
 Time& operator++() {
 seconds++;
 normalize();
 return *this;
 }
 // Постфиксный инкремент
 Time operator++(int) {
 Time temp = *this;
 seconds++;
 normalize();
 return temp;
 }
 // Сложение времени
 Time operator+(const Time& other) const {
 return Time(hours + other.hours, minutes + other.minutes, seconds + other.seconds);
 }
 // Вычитание времени
 Time operator-(const Time& other) const {
 int totalSeconds = (hours * 3600 + minutes * 60 + seconds) -
 (other.hours * 3600 + other.minutes * 60 + other.seconds);
 return Time(0, 0, totalSeconds);
 }
 // Сравнение
 bool operator==(const Time& other) const {
 return hours == other.hours && minutes == other.minutes && seconds == other.seconds;
 }
 bool operator<(const Time& other) const {
 if(hours != other.hours) return hours < other.hours;
 if(minutes != other.minutes) return minutes < other.minutes;
 return seconds < other.seconds;
 }
 bool operator>(const Time& other) const {
 return other < *this;
 }
 // Приведение к секундам
 operator int() const {
 return hours * 3600 + minutes * 60 + seconds;
 }
 friend ostream& operator<<(ostream& os, const Time& t) {
 return os << setfill('0') << setw(2) << t.hours << \:"
 << setw(2) << t.minutes << ":" << setw(2) << t.seconds;
 }
};

