code:
#include <iostream>
#include <vector>
#include <cmath>
using namespace std;

class Polynomial {
 vector<double> coefficients; // coefficients[0] - свободный член
public:
 Polynomial(initializer_list<double> coeffs) : coefficients(coeffs) {
 // Удаляем ведущие нули
 while(coefficients.size() > 1 && coefficients.back() == 0) {
 coefficients.pop_back();
 }
 }
 // Степень полинома
 size_t degree() const {
 return coefficients.size() - 1;
 }
 // Вычисление значения
 double operator()(double x) const {
 double result = 0;
 double power = 1;
 for(double coeff : coefficients) {
 result += coeff * power;
 power *= x;
 }
 return result;
 }
 // Сложение полиномов
 Polynomial operator+(const Polynomial& other) const {
 vector<double> resultCoeffs(max(coefficients.size(), other.coefficients.size()), 0);
 for(size_t i = 0; i < coefficients.size(); i++) {
 resultCoeffs[i] += coefficients[i];
 }
 for(size_t i = 0; i < other.coefficients.size(); i++) {
 resultCoeffs[i] += other.coefficients[i];
 }
 return Polynomial(resultCoeffs.begin(), resultCoeffs.end());
 }
 // Умножение на скаляр
 Polynomial operator*(double scalar) const {
 vector<double> resultCoeffs = coefficients;
 for(double& coeff : resultCoeffs) {
 coeff *= scalar;
 }
 return Polynomial(resultCoeffs.begin(), resultCoeffs.end());
 }
 friend Polynomial operator*(double scalar, const Polynomial& poly) {
 return poly * scalar;
 }
 // Производная
 Polynomial derivative() const {
 if(coefficients.size() <= 1) return Polynomial{0};
 vector<double> derivCoeffs(coefficients.size() - 1);
 for(size_t i = 1; i < coefficients.size(); i++) {
 derivCoeffs[i-1] = coefficients[i] * i;
 }
 return Polynomial(derivCoeffs.begin(), derivCoeffs.end());
 }
 friend ostream& operator<<(ostream& os, const Polynomial& poly) {
 for(int i = poly.coefficients.size() - 1; i >= 0; i--) {
 if(poly.coefficients[i] != 0) {
 if(i < poly.coefficients.size() - 1) {
 os << (poly.coefficients[i] > 0 ? \ + " : " - ");
 }
 double absCoeff = abs(poly.coefficients[i]);
 if(absCoeff != 1 || i == 0) {
 os << absCoeff;
 }
 if(i > 0) {
 os << "x";
 if(i > 1) os << "^" << i;
 }
 }
 }
 return os;
 }
};

int main() {
 Polynomial p1{1

keywords:
 -1}; // x - 1
 cout << "p1(x) = " << p1 << endl;
 cout << "p2(x) = " << p2 << endl;
 cout << "p1 + p2 = " << (p1 + p2) << endl;
 cout << "p1(2) = " << p1(2) << endl;
 cout << "p1' = " << p1.derivative() << endl;
 cout << "3 * p1 = " << (3 * p1) << endl;
 return 0;
}"

