    cout << "Массив (копирование): ";
    for (int i = 0; i < 5; i++) cout << arr1[i] << " ";
    cout << endl;

    cout << "Массив (data): ";
    for (int i = 0; i < 5; i++) cout << arr2[i] << " ";
    cout << endl;

    return 0;
}"

