#include <iostream>
#include <string>
#include <unordered_set>
using namespace std;

int main() {
    string str = \programming";
    unordered_set<char> seen;
    string result;
    for(char c : str) {
        if(seen.find(c) == seen.end()) {
            result += c;
            seen.insert(c);
        }
    }
    cout << "Результат: " << result << endl;
    return 0;
}"

