code:
#include <iostream>
#include <cmath>
#include <vector>
using namespace std;

int main() {
    vector<double> returns = {0.1, 0.05, -0.02, 0.08, -0.01};
    double riskFreeRate = 0.02;
    double downsideDev = 0.0;

    for (double r : returns) {
        if (r < riskFreeRate) {
            downsideDev += pow(r - riskFreeRate, 2);
        }
    }
    downsideDev = sqrt(downsideDev / returns.size());

    double avgReturn = 0.0;
    for (double r : returns) avgReturn += r;
    avgReturn /= returns.size();

    double sortinoRatio = (avgReturn - riskFreeRate) / downsideDev;
    cout << \Коэффициент Сортино: " << sortinoRatio << endl;
    return 0;
}"

