    }
    std::cout << std::endl;

    return 0;
}"

#include <iostream>
#include <string>
#include <cstdint>
using namespace std;

uint32_t crc32(const string& data) {
    uint32_t crc = 0xFFFFFFFF;

    for(char c : data) {
        crc ^= static_cast<uint32_t>(c);
        for(int i = 0; i < 8; i++) {
            crc = (crc >> 1) ^ (0xEDB88320 & -(crc & 1));
        }
    }

    return ~crc;
}

int main() {
    string data = \Hello World";
    cout << "CRC32: " << hex << crc32(data) << endl;
    return 0;
}"

#include <iostream>
#include <string>
#include <cstdint>

uint32_t crc32(const std::string& data) {
    uint32_t crc = 0xFFFFFFFF;

    for(char c : data) {
        crc ^= static_cast<uint32_t>(c);
        for(int i = 0; i < 8; i++) {
            crc = (crc >> 1) ^ (0xEDB88320 & -(crc & 1));
        }
    }

    return ~crc;
}

int main() {
    std::string data = \Hello World";
    std::cout << "CRC32: " << std::hex << crc32(data) << std::endl;
    return 0;
}"

