#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    vector<int> numbers = {5, 2, 8, 1, 9, 3};

    sort(numbers.begin(), numbers.end());
    auto it = find(numbers.begin(), numbers.end(), 8);

    if(it != numbers.end()) {
        cout << \Найдено: " << *it << endl;
    }

    cout << "Отсортированный вектор: ";
    for(int num : numbers) {
        cout << num << " ";
    }
    cout << endl;
    return 0;
}"

