#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class IntContainer {
 vector<int> data;
public:
 void add(int value) { data.push_back(value); }
 // Методы для итераторов
 auto begin() { return data.begin(); }
 auto end() { return data.end(); }
 auto begin() const { return data.begin(); }
 auto end() const { return data.end(); }
 // Перегрузка оператора индексации
 int& operator[](size_t index) { return data[index]; }
 const int& operator[](size_t index) const { return data[index]; }
 size_t size() const { return data.size(); }
};

int main() {
 IntContainer container;
 for(int i = 0; i < 10; i++) {
 container.add(i * i);
 }
 // Использование range-based for loop
 cout << \Elements: ";
 for(int value : container) {
 cout << value << " ";
 }
 cout << endl;
 // Использование STL алгоритмов
 auto it = find(container.begin()

keywords:
 it) << endl;
 }
 // Использование оператора индексации
 cout << "Element at index 3: " << container[3] << endl;
 // Изменение через итератор
 for(auto& value : container) {
 value += 1;
 }
 cout << "After increment: ";
 for(int value : container) {
 cout << value << " ";
 }
 cout << endl;
 return 0;
}"

