#include <iostream>
#include <variant>
#include <string>
using namespace std;

int main() {
    variant<int, double, string> value;

    value = 42;
    cout << \Value: " << get<int>(value) << endl;

    value = 3.14;
    cout << "Value: " << get<double>(value) << endl;

    value = "Hello";
    cout << "Value: " << get<string>(value) << endl;

    // Проверка типа
    if (holds_alternative<int>(value)) {
        cout << "Contains int" << endl;
    } else if (holds_alternative<double>(value)) {
        cout << "Contains double" << endl;
    } else if (holds_alternative<string>(value)) {
        cout << "Contains string" << endl;
    }

    // Безопасный доступ
    if (auto intPtr = get_if<int>(&value)) {
        cout << "Int value: " << *intPtr << endl;
    } else {
        cout << "Not an int" << endl;
    }

    return 0;
}"

