#include <iostream>
#include <chrono>
#include <thread>
#include <cmath>
using namespace std;
using namespace std::chrono;

void demonstrateChrono() {
    // Точки времени
    auto start = high_resolution_clock::now();

    // Имитация работы
    this_thread::sleep_for(milliseconds(100));

    auto end = high_resolution_clock::now();

    // Разница времени
    auto duration = duration_cast<microseconds>(end - start);
    cout << \Время выполнения: " << duration.count() << " микросекунд" << endl;

    // Текущее время
    auto now = system_clock::now();
    auto now_time_t = system_clock::to_time_t(now);
    cout << "Текущее время: " << ctime(&now_time_t);

    // Работа с duration
    seconds sec(60);
    minutes min = duration_cast<minutes>(sec);
    cout << "60 секунд = " << min.count() << " минут" << endl;

    // Hours
    hours hr(2);
    auto total_minutes = duration_cast<minutes>(hr);
    cout << "2 часа = " << total_minutes.count() << " минут" << endl;
}

class Timer {
private:
    time_point<high_resolution_clock> start_time;

public:
    Timer() : start_time(high_resolution_clock::now()) {}

    void reset() {
        start_time = high_resolution_clock::now();
    }

    double elapsed() const {
        auto end = high_resolution_clock::now();
        auto duration = duration_cast<microseconds>(end - start_time);
        return duration.count() / 1000000.0;
    }
};

int main() {
    demonstrateChrono();

    cout << "\nИзмерение времени вычислений:" << endl;

    Timer timer;

    // Выполняем тяжелые вычисления
    double sum = 0;
    for (int i = 0; i < 1000000; i++) {
        sum += sin(i) * cos(i);
    }

    double elapsed = timer.elapsed();
    cout << "Время вычислений: " << elapsed << " секунд" << endl;
    cout << "Результат: " << sum << endl;

    return 0;
}"

#include <iostream>
#include <chrono>
#include <thread>
#include <cmath>

void demonstrateChrono() {
    // Точки времени
    auto start = std::chrono::high_resolution_clock::now();

    // Имитация работы
    std::this_thread::sleep_for(std::chrono::milliseconds(100));

    auto end = std::chrono::high_resolution_clock::now();

    // Разница времени
    auto duration = std::chrono::duration_cast<std::chrono::microseconds>(end - start);
    std::cout << \Время выполнения: " << duration.count() << " микросекунд" << std::endl;

    // Текущее время
    auto now = std::chrono::system_clock::now();
    auto now_time_t = std::chrono::system_clock::to_time_t(now);
    std::cout << "Текущее время: " << std::ctime(&now_time_t);

    // Работа с duration
    std::chrono::seconds sec(60);
    auto min = std::chrono::duration_cast<std::chrono::minutes>(sec);
    std::cout << "60 секунд = " << min.count() << " минут" << std::endl;

    // Hours
    std::chrono::hours hr(2);
    auto total_minutes = std::chrono::duration_cast<std::chrono::minutes>(hr);
    std::cout << "2 часа = " << total_minutes.count() << " минут" << std::endl;
}

class Timer {
private:
    std::chrono::time_point<std::chrono::high_resolution_clock> start_time;

public:
    Timer() : start_time(std::chrono::high_resolution_clock::now()) {}

    void reset() {
        start_time = std::chrono::high_resolution_clock::now();
    }

    double elapsed() const {
        auto end = std::chrono::high_resolution_clock::now();
        auto duration = std::chrono::duration_cast<std::chrono::microseconds>(end - start_time);
        return duration.count() / 1000000.0;
    }
};

int main() {
    demonstrateChrono();

    std::cout << "\nИзмерение времени вычислений:" << std::endl;

    Timer timer;

    // Выполняем тяжелые вычисления
    double sum = 0;
    for (int i = 0; i < 1000000; i++) {
        sum += std::sin(i) * std::cos(i);
    }

    double elapsed = timer.elapsed();
    std::cout << "Время вычислений: " << elapsed << " секунд" << std::endl;
    std::cout << "Результат: " << sum << std::endl;

    return 0;
}"

