class Serializer {
public:
 // Основной шаблон
 template<typename T>
 string serialize(const T& value) const {
 if constexpr (is_arithmetic_v<T>) {
 return \Number: " + to_string(value);
 } else {
 return "Object: " + string(value);
 }
 }
};

// Специализация для bool
template<>
string Serializer::serialize<bool>(const bool& value) const {
 return "Boolean: " + string(value ? "true" : "false");
}

// Специализация для string
template<>
string Serializer::serialize<string>(const string& value) const {
 return "String: \"" + value + "\"";
}

