 cout << serializer.serialize(3.14) << endl;
 cout << serializer.serialize(true) << endl;
 cout << serializer.serialize(false) << endl;
 cout << serializer.serialize(string("Hello")) << endl;
 cout << serializer.serialize("World") << endl; // Использует основной шаблон
 return 0;
}"

