 using type = TrueType;
};

template<typename TrueType, typename FalseType>
struct conditional<false, TrueType, FalseType> {
 using type = FalseType;
};

template<bool Condition, typename TrueType, typename FalseType>
using conditional_t = typename conditional<Condition, TrueType, FalseType>::type;

template<typename T>
class SmartPointer {
 conditional_t<is_array_v<T>, unique_ptr<T[]>, unique_ptr<T>> ptr;
public:
 template<typename U>
 SmartPointer(U* p) : ptr(p) {}

 auto get() const {
 return ptr.get();
 }

 auto operator->() const {
 return ptr.operator->();
 }

 auto operator*() const {
 return *ptr;
 }
};

