template<typename... Types>
class CommonTypeFinder {
public:
 using type = common_type_t<Types...>;

 static constexpr bool has_common_type = !is_void_v<type>;

 static type convertAll(const Types&... values) {
 return type{values...};
 }

 static vector<type> toCommonVector(const Types&... values) {
 return vector<type>{static_cast<type>(values)...};
 }
};

template<typename T1, typename T2>
class MixedArithmetic {
 using common_t = common_type_t<T1, T2>;
public:
 static common_t add(T1 a, T2 b) {
 return static_cast<common_t>(a) + static_cast<common_t>(b);
 }

 static common_t multiply(T1 a, T2 b) {
 return static_cast<common_t>(a) * static_cast<common_t>(b);
 }

 static bool areCompatible() {
 return !is_void_v<common_t>;
 }
};

