// SFINAE для типов с методом serialize()
template<typename T>
class has_serialize {
private:
    template<typename U>
    static auto test(int) -> decltype(
        std::declval<U>().serialize(), std::true_type{});

    template<typename U>
    static std::false_type test(...);

public:
    static constexpr bool value = decltype(test<T>(0))::value;
};

template<typename T>
typename std::enable_if<has_serialize<T>::value, std::string>::type
serialize(const T& obj) {
    return obj.serialize();
}

template<typename T>
typename std::enable_if<!has_serialize<T>::value, std::string>::type
serialize(const T& obj) {
    return std::to_string(obj);
}

class MyClass {
public:
    std::string serialize() const {
        return \MyClass serialized";
    }
};

int main() {
    MyClass obj;
    int number = 42;

    std::cout << serialize(obj) << std::endl;
    std::cout << serialize(number) << std::endl;

    return 0;
}"

