#include <iostream>
#include <concepts>
#include <vector>

// Концепт для числовых типов
template<typename T>
concept Numeric = std::integral<T> || std::floating_point<T>;

// Концепт для типов с методом size()
template<typename T>
concept HasSize = requires(T t) {
    t.size();
};

// Функция только для числовых типов
template<Numeric T>
T square(T x) {
    return x * x;
}

// Функция для типов с методом size()
template<HasSize T>
void printSize(const T& container) {
    std::cout << \Size: " << container.size() << std::endl;
}

