#include <iostream>
#include <string>
#include <expected>
using namespace std;

// Имитируем std::expected если компилятор не поддерживает C++23
#ifdef __cpp_lib_expected
using std::expected;
using std::unexpected;
#else
// Простая реализация для демонстрации
template<typename T, typename E>
class expected {
private:
    union {
        T value;
        E error;
    };
    bool has_value;

public:
    expected(const T& v) : value(v), has_value(true) {}
    expected(const E& e) : error(e), has_value(false) {}

    bool hasValue() const { return has_value; }
    const T& getValue() const { return value; }
    const E& getError() const { return error; }

    T value_or(const T& default_val) const {
        return has_value ? value : default_val;
    }
};

template<typename E>
class unexpected {
private:
    E error;

public:
    unexpected(const E& e) : error(e) {}
    const E& getError() const { return error; }
};
#endif

enum class FileError {
    NotFound,
    PermissionDenied,
    IOError
};

expected<string, FileError> readFile(const string& filename) {
    if (filename == \missing.txt") {
        return unexpected(FileError::NotFound);
    } else if (filename == "protected.txt") {
        return unexpected(FileError::PermissionDenied);
    } else {
        return string("Содержимое файла ") + filename;
    }
}

void processFile(const string& filename) {
    auto result = readFile(filename);

    if (result.hasValue()) {
        cout << "Успешно: " << result.getValue() << endl;
    } else {
        switch (result.getError()) {
            case FileError::NotFound:
                cout << "Ошибка: файл не найден" << endl;
                break;
            case FileError::PermissionDenied:
                cout << "Ошибка: доступ запрещен" << endl;
                break;
            case FileError::IOError:
                cout << "Ошибка: ошибка ввода-вывода" << endl;
                break;
        }
    }
}

int main() {
    cout << "Обработка разных файлов:" << endl;

    processFile("document.txt");
    processFile("missing.txt");
    processFile("protected.txt");

    return 0;
}"

#include <iostream>
#include <string>
#include <expected>

// Имитируем std::expected если компилятор не поддерживает C++23
#ifdef __cpp_lib_expected
using std::expected;
using std::unexpected;
#else
// Простая реализация для демонстрации
template<typename T, typename E>
class expected {
private:
    union {
        T value;
        E error;
    };
    bool has_value;

public:
    expected(const T& v) : value(v), has_value(true) {}
    expected(const E& e) : error(e), has_value(false) {}

    bool hasValue() const { return has_value; }
    const T& getValue() const { return value; }
    const E& getError() const { return error; }

    T value_or(const T& default_val) const {
        return has_value ? value : default_val;
    }
};

template<typename E>
class unexpected {
private:
    E error;

public:
    unexpected(const E& e) : error(e) {}
    const E& getError() const { return error; }
};
#endif

enum class FileError {
    NotFound,
    PermissionDenied,
    IOError
};

expected<std::string, FileError> readFile(const std::string& filename) {
    if (filename == \missing.txt") {
        return unexpected(FileError::NotFound);
    } else if (filename == "protected.txt") {
        return unexpected(FileError::PermissionDenied);
    } else {
        return std::string("Содержимое файла ") + filename;
    }
}

void processFile(const std::string& filename) {
    auto result = readFile(filename);

    if (result.hasValue()) {
        std::cout << "Успешно: " << result.getValue() << std::endl;
    } else {
        switch (result.getError()) {
            case FileError::NotFound:
                std::cout << "Ошибка: файл не найден" << std::endl;
                break;
            case FileError::PermissionDenied:
                std::cout << "Ошибка: доступ запрещен" << std::endl;
                break;
            case FileError::IOError:
                std::cout << "Ошибка: ошибка ввода-вывода" << std::endl;
                break;
        }
    }
}

int main() {
    std::cout << "Обработка разных файлов:" << std::endl;

    processFile("document.txt");
    processFile("missing.txt");
    processFile("protected.txt");

    return 0;
}"

