#include <iostream>
#include <utility>
#include <vector>
using namespace std;

class Resource {
private:
    vector<int> data;
public:
    Resource() : data(1000, 42) { 
        cout << \Resource создан" << endl; 
    }

    Resource(const Resource& other) : data(other.data) { 
        cout << "Resource скопирован" << endl; 
    }

    Resource(Resource&& other) noexcept : data(move(other.data)) { 
        cout << "Resource перемещен" << endl; 
    }

    ~Resource() { 
        cout << "Resource уничтожен" << endl; 
    }
};

void process(Resource&& r) {
    cout << "Обработка r-value ссылки" << endl;
}

void process(const Resource& r) {
    cout << "Обработка l-value ссылки" << endl;
}

int main() {
    cout << "=== L-value ссылки ===" << endl;
    Resource r1;
    process(r1);           // l-value

    cout << "\n=== R-value ссылки ===" << endl;
    process(Resource());   // r-value
    process(move(r1));     // r-value (явное преобразование)

    return 0;
}"

