 }
 void work() const {
 std::cout << "Working on project: " << name << std::endl;
 }
};

class Team {
 std::vector<std::unique_ptr<Project>> projects;
 std::string teamName;
public:
 Team(const std::string& name) : teamName(name) {}
 // Конструктор перемещения
 Team(Team&& other) noexcept 
 : projects(std::move(other.projects))

style:
 teamName(std::move(other.teamName)) {
 std::cout << "Team move constructor: " << teamName << std::endl;
 }
 // Перемещающее присваивание
 Team& operator=(Team&& other) noexcept {
