#include <iostream>
#include <utility>
#include <string>
using namespace std;

class Widget {
private:
    string name;

public:
    // Конструктор с l-value reference
    Widget(const string& n) : name(n) {
        cout << \Конструктор с l-value: " << name << endl;
    }

    // Конструктор с r-value reference
    Widget(string&& n) : name(move(n)) {
        cout << "Конструктор с r-value: " << name << endl;
    }

    string getName() const { return name; }
};

// Фабричная функция с perfect forwarding
template<typename T

style:
 typename... Args>
T create(Args&&... args) {
    return T(forward<Args>(args)...);
}

void processWidget(const Widget& w) {
    cout << "Обработка l-value: " << w.getName() << endl;
}

void processWidget(Widget&& w) {
    cout << "Обработка r-value: " << w.getName() << endl;
}

// Универсальная ссылка с perfect forwarding
template<typename T>
void relay(T&& arg) {
    processWidget(forward<T>(arg));
}

int main() {
    string str = "Временный объект";

    // Создание с l-value
    Widget w1 = create<Widget>(str);

    // Создание с r-value
    Widget w2 = create<Widget>(string("Временная строка"));

    cout << "\nPerfect forwarding:" << endl;

    // Передача l-value
    relay(w1);

    // Передача r-value
    relay(create<Widget>(string("Еще один временный")));

    return 0;
}"

