#include <iostream>
using namespace std;

class Buffer {
 int* data;
 size_t size;
public:
 Buffer(size_t s) : size(s), data(new int[s]) {}
 Buffer(Buffer&& other) noexcept : data(other.data), size(other.size) {
 other.data = nullptr;
 other.size = 0;
 }
 Buffer& operator=(Buffer&& other) noexcept {
 if(this != &other) {
 delete[] data;
 data = other.data;
 size = other.size;
 other.data = nullptr;
 other.size = 0;
 }
 return *this;
 }
 ~Buffer() { delete[] data; }
};

