#include <vector>
#include <string>
#include <functional>
#include <exception>
using namespace std;

class TestSystem {
 struct TestCase {
 string name;
 function<void()> test;
 function<void()> setup;
 function<void()> teardown;
 };

 vector<TestCase> tests;
 vector<string> results;

public:
 void addTest(const string& name, function<void()> test, 
 function<void()> setup = []{}, function<void()> teardown = []{}) {
 tests.push_back({name, test, setup, teardown});
 }

 void runTests() {
 for(auto& testCase : tests) {
 try {
 testCase.setup();
 testCase.test();
 testCase.teardown();
 results.push_back(\PASS: " + testCase.name);
 } catch(const exception& e) {
 results.push_back("FAIL: " + testCase.name + " - " + e.what());
 }
 }
 }

 vector<string> getResults() const {
 return results;
 }

 template<typename T>
 class Mock {
 T original;
 function<void()> mockBehavior;
 public:
 Mock(T obj) : original(obj) {}

 void setBehavior(function<void()> behavior) {
 mockBehavior = behavior;
 }

 void reset() {
 mockBehavior = nullptr;
 }

 void execute() {
 if(mockBehavior) {
 mockBehavior();
 } else {
 original();
 }
 }
 };

 template<typename T>
 static Mock<T> createMock(T obj) {
 return Mock<T>(obj);
 }
};"

#include <vector>
#include <string>
#include <functional>
#include <exception>

class TestSystem {
 struct TestCase {
 std::string name;
 std::function<void()> test;
 std::function<void()> setup;
 std::function<void()> teardown;
 };

 std::vector<TestCase> tests;
 std::vector<std::string> results;

public:
 void addTest(const std::string& name, std::function<void()> test, 
 std::function<void()> setup = []{}, std::function<void()> teardown = []{}) {
 tests.push_back({name, test, setup, teardown});
 }

 void runTests() {
 for(auto& testCase : tests) {
 try {
 testCase.setup();
 testCase.test();
 testCase.teardown();
 results.push_back(\PASS: " + testCase.name);
 } catch(const std::exception& e) {
 results.push_back("FAIL: " + testCase.name + " - " + e.what());
 }
 }
 }

 std::vector<std::string> getResults() const {
 return results;
 }

 template<typename T>
 class Mock {
 T original;
 std::function<void()> mockBehavior;
 public:
 Mock(T obj) : original(obj) {}

 void setBehavior(std::function<void()> behavior) {
 mockBehavior = behavior;
 }

 void reset() {
 mockBehavior = nullptr;
 }

 void execute() {
 if(mockBehavior) {
 mockBehavior();
 } else {
 original();
 }
 }
 };

 template<typename T>
 static Mock<T> createMock(T obj) {
 return Mock<T>(obj);
 }
};"

#include <iostream>
#include <vector>
#include <memory>
#include <string>
#include <map>
#include <functional>
#include <cmath>
using namespace std;

// Базовый интерфейс для плагинов
class IPlugin {
public:
    virtual ~IPlugin() = default;
    virtual string getName() const = 0;
    virtual string getVersion() const = 0;
    virtual void execute() = 0;
};

// Менеджер плагинов
class PluginManager {
private:
    map<string, unique_ptr<IPlugin>> plugins;

public:
    void registerPlugin(unique_ptr<IPlugin> plugin) {
        string name = plugin->getName();
        plugins[name] = move(plugin);
        cout << \Зарегистрирован плагин: " << name << endl;
    }

    void unregisterPlugin(const string& name) {
        auto it = plugins.find(name);
        if (it != plugins.end()) {
            cout << "Удален плагин: " << name << endl;
            plugins.erase(it);
        }
    }

    void executePlugin(const string& name) {
        auto it = plugins.find(name);
        if (it != plugins.end()) {
            cout << "Выполнение плагина '" << name << "':" << endl;
            it->second->execute();
        } else {
            cout << "Плагин '" << name << "' не найден" << endl;
        }
    }

    void listPlugins() const {
        cout << "\nЗарегистрированные плагины:" << endl;
        for (const auto& [name

style:
 plugin] : plugins) {
            cout << "- " << name << " v" << plugin->getVersion() << endl;
        }
    }

    size_t getPluginCount() const {
        return plugins.size();
    }
};

// Конкретные реализации плагинов
class HelloPlugin : public IPlugin {
public:
    string getName() const override {
        return "HelloPlugin";
    }

    string getVersion() const override {
        return "1.0";
    }

    void execute() override {
        cout << "Hello from HelloPlugin!" << endl;
    }
};

class MathPlugin : public IPlugin {
public:
    string getName() const override {
        return "MathPlugin";
    }

    string getVersion() const override {
        return "1.1";
    }

    void execute() override {
        cout << "MathPlugin: 2 + 2 = " << (2 + 2) << endl;
        cout << "MathPlugin: sqrt(16) = " << sqrt(16.0) << endl;
    }
};

class TimePlugin : public IPlugin {
public:
    string getName() const override {
        return "TimePlugin";
    }

    string getVersion() const override {
        return "2.0";
    }

    void execute() override {
        cout << "TimePlugin: Текущее время - 14:30:45" << endl;
    }
};

// Фабрика для создания плагинов
class PluginFactory {
public:
    static unique_ptr<IPlugin> createPlugin(const string& type) {
        if (type == "hello") {
            return make_unique<HelloPlugin>();
        } else if (type == "math") {
            return make_unique<MathPlugin>();
        } else if (type == "time") {
            return make_unique<TimePlugin>();
        }
        return nullptr;
    }

    static vector<string> getAvailableTypes() {
        return {"hello"

keywords:
 "time"};
    }
};

int main() {
    PluginManager manager;

    // Регистрируем плагины через фабрику
    cout << "Регистрация плагинов..." << endl;
    for (const auto& type : PluginFactory::getAvailableTypes()) {
        auto plugin = PluginFactory::createPlugin(type);
        if (plugin) {
            manager.registerPlugin(move(plugin));
        }
    }

    // Демонстрация работы
    cout << "\n=== Демонстрация системы плагинов ===" << endl;

    manager.listPlugins();

    cout << "\nТестирование плагинов:" << endl;
    manager.executePlugin("HelloPlugin");
    manager.executePlugin("MathPlugin");
    manager.executePlugin("TimePlugin");
    manager.executePlugin("NonExistentPlugin");

    // Динамическое управление
    cout << "\nДинамическое управление:" << endl;
    manager.unregisterPlugin("MathPlugin");
    manager.listPlugins();

    // Добавление нового плагина
    cout << "\nДобавление нового плагина:" << endl;
    auto newPlugin = make_unique<HelloPlugin>();
    manager.registerPlugin(move(newPlugin));

    cout << "\nИтоговое количество плагинов: " << manager.getPluginCount() << endl;

    return 0;
}"

