code:
#include <iostream>
#include <vector>
#include <algorithm>
#include <memory>
#include <string>
using namespace std;

class Observer {
public:
    virtual void update(const string& message) = 0;
    virtual ~Observer() = default;
};

class Subject {
private:
    vector<Observer*> observers;
    string state;
public:
    void attach(Observer* observer) {
        observers.push_back(observer);
    }

    void detach(Observer* observer) {
        observers.erase(remove(observers.begin(), observers.end(), observer), observers.end());
    }

    void notify() {
        for (Observer* observer : observers) {
            observer->update(state);
        }
    }

    void setState(const string& newState) {
        state = newState;
        notify();
    }
};

class ConcreteObserver : public Observer {
private:
    string name;
public:
    ConcreteObserver(const string& name) : name(name) {}

    void update(const string& message) override {
        cout << name << \ получил сообщение: " << message << endl;
    }
};

int main() {
    Subject subject;

    ConcreteObserver observer1("Наблюдатель 1");
    ConcreteObserver observer2("Наблюдатель 2");

    subject.attach(&observer1);
    subject.attach(&observer2);

    subject.setState("Первое состояние");
    subject.setState("Второе состояние");

    subject.detach(&observer1);
    subject.setState("Третье состояние");

    return 0;
}"

#include <iostream>
#include <vector>
#include <algorithm>
#include <memory>
#include <string>

class Observer {
public:
    virtual void update(const std::string& message) = 0;
    virtual ~Observer() = default;
};

class Subject {
private:
    std::vector<Observer*> observers;
    std::string state;
public:
    void attach(Observer* observer) {
        observers.push_back(observer);
    }

    void detach(Observer* observer) {
        observers.erase(std::remove(observers.begin(), observers.end(), observer), observers.end());
    }

    void notify() {
        for (Observer* observer : observers) {
            observer->update(state);
        }
    }

    void setState(const std::string& newState) {
        state = newState;
        notify();
    }
};

class ConcreteObserver : public Observer {
private:
    std::string name;
public:
    ConcreteObserver(const std::string& name) : name(name) {}

    void update(const std::string& message) override {
        std::cout << name << \ получил сообщение: " << message << std::endl;
    }
};

int main() {
    Subject subject;

    ConcreteObserver observer1("Наблюдатель 1");
    ConcreteObserver observer2("Наблюдатель 2");

    subject.attach(&observer1);
    subject.attach(&observer2);

    subject.setState("Первое состояние");
    subject.setState("Второе состояние");

    subject.detach(&observer1);
    subject.setState("Третье состояние");

    return 0;
}"

#include <iostream>
#include <atomic>
#include <mutex>
using namespace std;

class Singleton {
 static atomic<Singleton*> instance;
 static mutex mutex;
 Singleton() = default;
public:
 static Singleton* getInstance() {
 Singleton* tmp = instance.load(memory_order_acquire);
 if(!tmp) {
 lock_guard<mutex> lock(mutex);
 tmp = instance.load(memory_order_relaxed);
 if(!tmp) {
 tmp = new Singleton();
 instance.store(tmp, memory_order_release);
 }
 }
 return tmp;
 }
 void showMessage() {
 cout << \Singleton instance: " << this << endl;
 }
};

atomic<Singleton*> Singleton::instance(nullptr);
mutex Singleton::mutex;

int main() {
 Singleton* s1 = Singleton::getInstance();
 s1->showMessage();
 Singleton* s2 = Singleton::getInstance();
 s2->showMessage();
 return 0;
}"

#include <iostream>
#include <atomic>
#include <mutex>

class Singleton {
 static std::atomic<Singleton*> instance;
 static std::mutex mutex;
 Singleton() = default;
public:
 static Singleton* getInstance() {
 Singleton* tmp = instance.load(std::memory_order_acquire);
 if(!tmp) {
 std::lock_guard<std::mutex> lock(mutex);
 tmp = instance.load(std::memory_order_relaxed);
 if(!tmp) {
 tmp = new Singleton();
 instance.store(tmp, std::memory_order_release);
 }
 }
 return tmp;
 }
 void showMessage() {
 std::cout << \Singleton instance: " << this << std::endl;
 }
};

std::atomic<Singleton*> Singleton::instance(nullptr);
std::mutex Singleton::mutex;

