#include <iostream>
#include <memory>
#include <string>
using namespace std;

class Logger {
public:
    virtual void log(const string& message) = 0;
    virtual ~Logger() = default;
};

class ConsoleLogger : public Logger {
public:
    void log(const string& message) override {
        cout << \[CONSOLE] " << message << endl;
    }
};

class FileLogger : public Logger {
public:
    void log(const string& message) override {
        cout << "[FILE] " << message << endl;
    }
};

template<typename LoggerType>
class Service {
private:
    unique_ptr<LoggerType> logger;

public:
    Service(unique_ptr<LoggerType> log) : logger(move(log)) {}

    void doWork() {
        logger->log("Начало работы");
        // Какая-то работа
        logger->log("Конец работы");
    }
};

int main() {
    auto consoleService = Service<ConsoleLogger>(make_unique<ConsoleLogger>());
    consoleService.doWork();

    auto fileService = Service<FileLogger>(make_unique<FileLogger>());
    fileService.doWork();

    return 0;
}"

