#include <memory>
#include <string>

class Logger {
public:
    virtual void log(const std::string& message) = 0;
    virtual ~Logger() = default;
};

class ConsoleLogger : public Logger {
public:
    void log(const std::string& message) override {
        std::cout << \[CONSOLE] " << message << std::endl;
    }
};

class FileLogger : public Logger {
public:
    void log(const std::string& message) override {
        std::cout << "[FILE] " << message << std::endl;
    }
};

template<typename LoggerType>
class Service {
private:
    std::unique_ptr<LoggerType> logger;

public:
    Service(std::unique_ptr<LoggerType> log) : logger(std::move(log)) {}

    void doWork() {
        logger->log("Начало работы");
        // Какая-то работа
        logger->log("Конец работы");
    }
};

int main() {
    auto consoleService = Service<ConsoleLogger>(std::make_unique<ConsoleLogger>());
    consoleService.doWork();

    auto fileService = Service<FileLogger>(std::make_unique<FileLogger>());
    fileService.doWork();

    return 0;
}"

#include <iostream>
#include <unordered_map>
#include <list>
using namespace std;

class LRUCache {
private:
    int capacity;
    list<pair<int, int>> cache;
    unordered_map<int, list<pair<int, int>>::iterator> map;

public:
    LRUCache(int cap) : capacity(cap) {}

    int get(int key) {
        if (map.find(key) == map.end()) {
            return -1;
        }

        // Перемещаем в начало
        cache.splice(cache.begin(), cache, map[key]);
        return map[key]->second;
    }

    void put(int key, int value) {
        if (map.find(key) != map.end()) {
            // Обновляем значение и перемещаем в начало
            map[key]->second = value;
            cache.splice(cache.begin(), cache, map[key]);
            return;
        }

        if (cache.size() == capacity) {
            // Удаляем самый старый элемент
            int lastKey = cache.back().first;
            cache.pop_back();
            map.erase(lastKey);
        }

        // Добавляем новый элемент
        cache.emplace_front(key, value);
        map[key] = cache.begin();
    }
};

int main() {
    LRUCache cache(2);

    cache.put(1, 1);
    cache.put(2, 2);
    cout << \get(1): " << cache.get(1) << endl; // 1

    cache.put(3

topic:
 4); // Удаляет ключ 1
