    std::string input;
    std::cout << \Введите строку для хеширования: ";
    std::getline(std::cin

style:
 input);

    std::string hash = SHA256::hash(input);
    std::cout << "SHA-256 хеш: " << hash << std::endl;
    return 0;
}"

