#include <iostream>
#include <cstdlib>
#include <ctime>
using namespace std;

double estimatePi(int numSamples) {
    int insideCircle = 0;

    srand(time(0));
    for (int i = 0; i < numSamples; i++) {
        double x = (double)rand() / RAND_MAX;
        double y = (double)rand() / RAND_MAX;

        if (x * x + y * y <= 1) {
            insideCircle++;
        }
    }

    return 4.0 * insideCircle / numSamples;
}

int main() {
    int samples = 1000000;
    double piEstimate = estimatePi(samples);

    cout << \Оценка Pi методом Монте-Карло: " << piEstimate << endl;
    cout << "Точное значение Pi: " << M_PI << endl;
    cout << "Погрешность: " << abs(piEstimate - M_PI) << endl;

    return 0;
}"

