#include <iostream>
#include <cmath>
using namespace std;

double sinTaylor(double x, int terms = 10) {
    double result = x; // первый член ряда
    double term = x;

    for (int i = 1; i <= terms; i++) {
        term *= -x * x / ((2 * i) * (2 * i + 1));
        result += term;
    }

    return result;
}

