#include <iostream>
#include <vector>
using namespace std;

void sieveOfEratosthenes(int n) {
    vector<bool> isPrime(n+1, true);

    for(int p = 2; p*p <= n; p++) {
        if(isPrime[p]) {
            for(int i = p*p; i <= n; i += p) {
                isPrime[i] = false;
            }
        }
    }

    cout << \Простые числа до " << n << ": ";
    for(int p = 2; p <= n; p++) {
        if(isPrime[p]) cout << p << " ";
    }
    cout << endl;
}

int main() {
    sieveOfEratosthenes(30);
    return 0;
}"

#include <iostream>
#include <vector>

void sieveOfEratosthenes(int n) {
    std::vector<bool> isPrime(n+1, true);

    for(int p = 2; p*p <= n; p++) {
        if(isPrime[p]) {
            for(int i = p*p; i <= n; i += p) {
                isPrime[i] = false;
            }
        }
    }

    std::cout << \Простые числа до " << n << ": ";
    for(int p = 2; p <= n; p++) {
        if(isPrime[p]) std::cout << p << " ";
    }
    std::cout << std::endl;
}

int main() {
    sieveOfEratosthenes(30);
    return 0;
}"

#include <iostream>
#include <string>
using namespace std;

bool luhnCheck(const string& cardNumber) {
    int sum = 0;
    bool alternate = false;

    for(int i = cardNumber.length() - 1; i >= 0; i--) {
        int digit = cardNumber[i] - '0';

        if(alternate) {
            digit *= 2;
            if(digit > 9) digit -= 9;
        }

        sum += digit;
        alternate = !alternate;
    }

    return (sum % 10 == 0);
}

int main() {
    string card = \4111111111111111";
    cout << "Карта " << (luhnCheck(card) ? "валидна" : "невалидна") << endl;
    return 0;
}"

