#include <iostream>
#include <string>
#include <vector>
using namespace std;

const int PRIME = 101;

long long calculateHash(const string& str, int start, int end) {
    long long hash = 0;
    for (int i = start; i <= end; i++) {
        hash = (hash * 256 + str[i]) % PRIME;
    }
    return hash;
}

long long recalculateHash(long long oldHash, char oldChar, char newChar, int patternLen) {
    long long newHash = (oldHash - oldChar * pow(256, patternLen - 1)) * 256 + newChar;
    return newHash % PRIME;
}

vector<int> rabinKarpSearch(const string& text, const string& pattern) {
    vector<int> positions;
    int n = text.length();
    int m = pattern.length();

    if (m == 0 || n < m) return positions;

    long long patternHash = calculateHash(pattern, 0, m - 1);
    long long textHash = calculateHash(text, 0, m - 1);

    for (int i = 0; i <= n - m; i++) {
        if (patternHash == textHash) {
            // Проверяем посимвольно на случай коллизии
            bool match = true;
            for (int j = 0; j < m; j++) {
                if (text[i + j] != pattern[j]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                positions.push_back(i);
            }
        }

        // Пересчитываем хэш для следующего окна
        if (i < n - m) {
            textHash = recalculateHash(textHash, text[i], text[i + m], m);
            if (textHash < 0) {
                textHash += PRIME;
            }
        }
    }

    return positions;
}

int main() {
    string text = \ABABCABABACABC";
    string pattern = "ABAB";

    vector<int> positions = rabinKarpSearch(text

style:
 pattern);

    if (positions.empty()) {
        cout << "Паттерн не найден" << endl;
    } else {
        cout << "Паттерн найден на позициях: ";
        for (int pos : positions) {
            cout << pos << " ";
        }
        cout << endl;
    }

    return 0;
}"

