#include <iostream>
#include <vector>
#include <stack>
using namespace std;

void topologicalSortUtil(int v, const vector<vector<int>>& graph, 
                        vector<bool>& visited, stack<int>& stack) {
    visited[v] = true;

    for (int neighbor : graph[v]) {
        if (!visited[neighbor]) {
            topologicalSortUtil(neighbor, graph, visited, stack);
        }
    }

    stack.push(v);
}

vector<int> topologicalSort(const vector<vector<int>>& graph) {
    int n = graph.size();
    vector<bool> visited(n, false);
    stack<int> stack;

    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            topologicalSortUtil(i, graph, visited, stack);
        }
    }

    vector<int> result;
    while (!stack.empty()) {
        result.push_back(stack.top());
        stack.pop();
    }

    return result;
}

