#include <iostream>
#include <vector>
#include <stack>
#include <algorithm>
using namespace std;

void fillOrder(int v, const vector<vector<int>>& graph, vector<bool>& visited, stack<int>& stack) {
    visited[v] = true;

    for (int neighbor : graph[v]) {
        if (!visited[neighbor]) {
            fillOrder(neighbor, graph, visited, stack);
        }
    }

    stack.push(v);
}

void DFSUtil(int v, const vector<vector<int>>& graph, vector<bool>& visited, vector<int>& component) {
    visited[v] = true;
    component.push_back(v);

    for (int neighbor : graph[v]) {
        if (!visited[neighbor]) {
            DFSUtil(neighbor, graph, visited, component);
        }
    }
}

vector<vector<int>> findSCCs(const vector<vector<int>>& graph) {
    int n = graph.size();
    vector<bool> visited(n, false);
    stack<int> stack;

    // Первый проход DFS для заполнения стека
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            fillOrder(i, graph, visited, stack);
        }
    }

    // Транспонирование графа
    vector<vector<int>> transposed(n);
    for (int u = 0; u < n; u++) {
        for (int v : graph[u]) {
            transposed[v].push_back(u);
        }
    }

    // Второй проход DFS на транспонированном графе
    fill(visited.begin(), visited.end(), false);
    vector<vector<int>> sccs;

    while (!stack.empty()) {
        int v = stack.top();
        stack.pop();

        if (!visited[v]) {
            vector<int> component;
            DFSUtil(v, transposed, visited, component);
            sccs.push_back(component);
        }
    }

    return sccs;
}

int main() {
    int n = 5;
    vector<vector<int>> graph(n);

    graph[0] = {1};
    graph[1] = {2};
    graph[2] = {0, 3};
    graph[3] = {4};

    vector<vector<int>> sccs = findSCCs(graph);

    cout << \Сильно связные компоненты:" << endl;
    for (size_t i = 0; i < sccs.size(); i++) {
        cout << "Компонента " << i + 1 << ": ";
        for (int node : sccs[i]) {
            cout << node << " ";
        }
        cout << endl;
    }

    return 0;
}"

